struct DefaultOffscreenPlatform {
    DefaultOffscreenPlatform()
    {
        if (qEnvironmentVariableIsEmpty("QT_QPA_PLATFORM") &&
            qEnvironmentVariableIntValue("QTFLUENT_VISUAL_SMOKE_VISIBLE") == 0) {
            qputenv("QT_QPA_PLATFORM", QByteArrayLiteral("offscreen"));
        }
    }
};

const DefaultOffscreenPlatform kDefaultOffscreenPlatform;

struct Bucket {
    qint64 count = 0;
    qint64 r = 0;
    qint64 g = 0;
    qint64 b = 0;
};

struct ContrastStats {
    QColor background;
    qreal maxContrast = 1.0;
    qreal readableRatio = 0.0;
    int readablePixels = 0;
    int sampledPixels = 0;
};

struct CheckTarget {
    QString name;
    QPointer<QWidget> widget;
    QRect area;
    qreal minContrast = 3.0;
    qreal minReadableRatio = 0.006;
};

class ScopedGraphicsEffectDisabler final {
public:
    explicit ScopedGraphicsEffectDisabler(QWidget *root)
    {
        if (!root) {
            return;
        }

        QList<QWidget *> widgets{root};
        widgets.append(root->findChildren<QWidget *>(QString(), Qt::FindChildrenRecursively));
        for (QWidget *widget : std::as_const(widgets)) {
            if (!widget) {
                continue;
            }
            if (auto *effect = widget->graphicsEffect(); effect && effect->isEnabled()) {
                m_effects.append({effect, true});
                effect->setEnabled(false);
            }
        }
    }

    ~ScopedGraphicsEffectDisabler()
    {
        for (const EffectState &state : std::as_const(m_effects)) {
            if (state.effect) {
                state.effect->setEnabled(state.wasEnabled);
            }
        }
    }

private:
    struct EffectState {
        QPointer<QGraphicsEffect> effect;
        bool wasEnabled = false;
    };

    QList<EffectState> m_effects;
};

QStringList *g_teachingTipGeometryWarnings = nullptr;
QtMessageHandler g_previousMessageHandler = nullptr;

void captureTeachingTipGeometryWarnings(QtMsgType type,
                                        const QMessageLogContext &context,
                                        const QString &message)
{
    if (type == QtWarningMsg
        && g_teachingTipGeometryWarnings
        && message.contains(QStringLiteral("QWindowsWindow::setGeometry"))
        && message.contains(QStringLiteral("FluentTeachingTipClassWindow"))) {
        g_teachingTipGeometryWarnings->append(message);
    }

    if (g_previousMessageHandler) {
        g_previousMessageHandler(type, context, message);
    }
}

