qreal linearChannel(qreal value)
{
    return value <= 0.03928 ? value / 12.92 : std::pow((value + 0.055) / 1.055, 2.4);
}

qreal relativeLuminance(const QColor &color)
{
    return 0.2126 * linearChannel(color.redF())
        + 0.7152 * linearChannel(color.greenF())
        + 0.0722 * linearChannel(color.blueF());
}

qreal contrastRatio(const QColor &a, const QColor &b)
{
    const qreal la = relativeLuminance(a);
    const qreal lb = relativeLuminance(b);
    const qreal lighter = qMax(la, lb);
    const qreal darker = qMin(la, lb);
    return (lighter + 0.05) / (darker + 0.05);
}

QRect normalizedArea(const QImage &image, const QRect &area)
{
    const QRect imageRect(QPoint(0, 0), image.size());
    const QRect result = (area.isValid() ? area : imageRect.adjusted(4, 4, -4, -4)).intersected(imageRect);
    return result.isValid() ? result : imageRect;
}

QColor dominantColor(const QImage &image, const QRect &rawArea)
{
    const QRect area = normalizedArea(image, rawArea);
    QHash<int, Bucket> buckets;
    buckets.reserve(64);

    for (int y = area.top(); y <= area.bottom(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = area.left(); x <= area.right(); ++x) {
            const QColor c = QColor::fromRgba(line[x]);
            if (c.alpha() < 220) {
                continue;
            }
            const int key = ((c.red() >> 4) << 8) | ((c.green() >> 4) << 4) | (c.blue() >> 4);
            Bucket &bucket = buckets[key];
            ++bucket.count;
            bucket.r += c.red();
            bucket.g += c.green();
            bucket.b += c.blue();
        }
    }

    Bucket best;
    for (auto it = buckets.constBegin(); it != buckets.constEnd(); ++it) {
        if (it.value().count > best.count) {
            best = it.value();
        }
    }

    if (best.count <= 0) {
        return QColor(Qt::transparent);
    }
    return QColor(static_cast<int>(best.r / best.count),
                  static_cast<int>(best.g / best.count),
                  static_cast<int>(best.b / best.count));
}

QColor averageColorDifferentFrom(const QImage &image, const QRect &rawArea, const QColor &background, int minDelta = 10)
{
    const QRect area = normalizedArea(image, rawArea);
    qint64 count = 0;
    qint64 r = 0;
    qint64 g = 0;
    qint64 b = 0;

    for (int y = area.top(); y <= area.bottom(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = area.left(); x <= area.right(); ++x) {
            const QColor c = QColor::fromRgba(line[x]);
            const int delta = qAbs(c.red() - background.red())
                            + qAbs(c.green() - background.green())
                            + qAbs(c.blue() - background.blue());
            if (delta < minDelta) {
                continue;
            }
            ++count;
            r += c.red();
            g += c.green();
            b += c.blue();
        }
    }

    if (count <= 0) {
        return QColor();
    }
    return QColor(static_cast<int>(r / count), static_cast<int>(g / count), static_cast<int>(b / count));
}

QColor blendOver(const QColor &foreground, const QColor &background)
{
    const qreal a = foreground.alphaF();
    return QColor::fromRgbF(
        foreground.redF() * a + background.redF() * (1.0 - a),
        foreground.greenF() * a + background.greenF() * (1.0 - a),
        foreground.blueF() * a + background.blueF() * (1.0 - a));
}

ContrastStats analyzeContrast(const QImage &image, const QRect &rawArea, qreal minContrast)
{
    const QRect area = normalizedArea(image, rawArea);
    ContrastStats stats;
    stats.background = dominantColor(image, area);
    if (!stats.background.isValid()) {
        return stats;
    }

    for (int y = area.top(); y <= area.bottom(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = area.left(); x <= area.right(); ++x) {
            const QColor c = QColor::fromRgba(line[x]);
            if (c.alpha() < 220) {
                continue;
            }
            ++stats.sampledPixels;
            const qreal contrast = contrastRatio(c, stats.background);
            stats.maxContrast = qMax(stats.maxContrast, contrast);
            if (contrast >= minContrast) {
                ++stats.readablePixels;
            }
        }
    }

    if (stats.sampledPixels > 0) {
        stats.readableRatio = static_cast<qreal>(stats.readablePixels) / stats.sampledPixels;
    }
    return stats;
}

int changedPixelCount(const QImage &a, const QImage &b, int threshold = 18)
{
    const int w = qMin(a.width(), b.width());
    const int h = qMin(a.height(), b.height());
    int changed = 0;

    for (int y = 0; y < h; ++y) {
        const auto *lineA = reinterpret_cast<const QRgb *>(a.constScanLine(y));
        const auto *lineB = reinterpret_cast<const QRgb *>(b.constScanLine(y));
        for (int x = 0; x < w; ++x) {
            const QColor ca = QColor::fromRgba(lineA[x]);
            const QColor cb = QColor::fromRgba(lineB[x]);
            const int delta = qAbs(ca.red() - cb.red())
                            + qAbs(ca.green() - cb.green())
                            + qAbs(ca.blue() - cb.blue())
                            + qAbs(ca.alpha() - cb.alpha());
            if (delta >= threshold) {
                ++changed;
            }
        }
    }

    return changed;
}

int nearColorPixelCount(const QImage &image, const QColor &target, const QRect &rawArea, int threshold = 42)
{
    const QRect area = normalizedArea(image, rawArea);
    int count = 0;
    for (int y = area.top(); y <= area.bottom(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = area.left(); x <= area.right(); ++x) {
            const QColor c = QColor::fromRgba(line[x]);
            const int delta = qAbs(c.red() - target.red())
                            + qAbs(c.green() - target.green())
                            + qAbs(c.blue() - target.blue());
            if (delta <= threshold) {
                ++count;
            }
        }
    }
    return count;
}

int alphaPixelCount(const QImage &image, int minAlpha = 16)
{
    int count = 0;
    for (int y = 0; y < image.height(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = 0; x < image.width(); ++x) {
            if (QColor::fromRgba(line[x]).alpha() >= minAlpha) {
                ++count;
            }
        }
    }
    return count;
}

int maxAlpha(const QImage &image)
{
    int alpha = 0;
    for (int y = 0; y < image.height(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = 0; x < image.width(); ++x) {
            alpha = qMax(alpha, QColor::fromRgba(line[x]).alpha());
        }
    }
    return alpha;
}

QRect alphaBounds(const QImage &image, int minAlpha = 16)
{
    int left = image.width();
    int top = image.height();
    int right = -1;
    int bottom = -1;

    for (int y = 0; y < image.height(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = 0; x < image.width(); ++x) {
            if (QColor::fromRgba(line[x]).alpha() < minAlpha) {
                continue;
            }
            left = qMin(left, x);
            top = qMin(top, y);
            right = qMax(right, x);
            bottom = qMax(bottom, y);
        }
    }

    return right >= left && bottom >= top ? QRect(QPoint(left, top), QPoint(right, bottom)) : QRect();
}

QPointF alphaCentroid(const QImage &image, int minAlpha = 16)
{
    qreal weightedX = 0.0;
    qreal weightedY = 0.0;
    qreal weight = 0.0;

    for (int y = 0; y < image.height(); ++y) {
        const auto *line = reinterpret_cast<const QRgb *>(image.constScanLine(y));
        for (int x = 0; x < image.width(); ++x) {
            const int alpha = QColor::fromRgba(line[x]).alpha();
            if (alpha < minAlpha) {
                continue;
            }
            weightedX += qreal(x) * qreal(alpha);
            weightedY += qreal(y) * qreal(alpha);
            weight += qreal(alpha);
        }
    }

    return weight > 0.0 ? QPointF(weightedX / weight, weightedY / weight) : QPointF();
}

QImage renderIconImage(FluentIconType type,
                       const FluentIconOptions &options = FluentIconOptions(),
                       QIcon::Mode mode = QIcon::Normal,
                       QSize size = QSize(32, 32))
{
    QImage image(size, QImage::Format_ARGB32);
    image.fill(Qt::transparent);

    QPainter painter(&image);
    FluentIcon::paintIcon(&painter, type, QRectF(QPointF(4, 4), QSizeF(size.width() - 8, size.height() - 8)), options, mode);
    painter.end();
    return image;
}

