    void timePickerWheelPopupCancelAndAcceptControlCommit()
    {
        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        auto wheelActionRect = [](QWidget *popup, bool accept) {
            const QRect content = PopupSurface::shadowContentRect(popup->rect());
            const QRect actionBar(content.left(), content.bottom() - 51, content.width(), 52);
            if (accept) {
                return QRect(actionBar.left(), actionBar.top(), actionBar.width() / 2, actionBar.height());
            }
            return QRect(actionBar.left() + actionBar.width() / 2,
                         actionBar.top(),
                         actionBar.width() - actionBar.width() / 2,
                         actionBar.height());
        };

        auto findWheelPopup = []() -> Detail::FluentWheelPickerPopup * {
            QWidget *widget = findVisibleTopLevelByObjectName(QStringLiteral("FluentWheelPickerPopup"));
            return dynamic_cast<Detail::FluentWheelPickerPopup *>(widget);
        };

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();

        FluentTimePicker picker;
        picker.setUse24HourClock(true);
        picker.setMinuteIncrement(5);
        picker.setTime(QTime(9, 15));
        picker.resize(210, 36);
        picker.show();
        QTRY_VERIFY(picker.isVisible());
        QCOMPARE(picker.use24HourClock(), true);
        QCOMPARE(picker.minuteIncrement(), 5);
        QVERIFY2(!renderWidgetImage(&picker).isNull(),
                 "TimePicker should render its closed 24-hour field through QWidget::render");

        QSignalSpy timeSpy(&picker, &QTimeEdit::timeChanged);

        QTest::mouseClick(&picker, Qt::LeftButton, Qt::NoModifier, picker.rect().center());
        QTRY_VERIFY2(findWheelPopup(), "TimePicker should open the shared wheel popup from the input surface");
        Detail::FluentWheelPickerPopup *popup = findWheelPopup();
        QVERIFY(popup);
        QCOMPARE(popup->columnCount(), 2);
        QVERIFY2(!renderWidgetImage(popup).isNull(),
                 "TimePicker wheel popup should render through QWidget::render while open offscreen");

        popup->setColumnValue(0, 18);
        popup->setColumnValue(1, 40);
        QCoreApplication::processEvents();
        QCOMPARE(popup->columnValue(0).toInt(), 18);
        QCOMPARE(popup->columnValue(1).toInt(), 40);

        QTest::mouseClick(popup, Qt::LeftButton, Qt::NoModifier, wheelActionRect(popup, false).center());
        QTRY_VERIFY(!popup->isVisible());
        QCOMPARE(picker.time(), QTime(9, 15));
        QCOMPARE(timeSpy.count(), 0);

        QTest::mouseClick(&picker, Qt::LeftButton, Qt::NoModifier, picker.rect().center());
        QTRY_VERIFY2(findWheelPopup(), "TimePicker should reopen the wheel popup after cancel");
        popup = findWheelPopup();
        QVERIFY(popup);
        QCOMPARE(popup->columnCount(), 2);
        popup->setColumnValue(0, 21);
        popup->setColumnValue(1, 35);
        QCoreApplication::processEvents();

        QTest::mouseClick(popup, Qt::LeftButton, Qt::NoModifier, wheelActionRect(popup, true).center());
        QTRY_VERIFY(!popup->isVisible());
        QCOMPARE(picker.time(), QTime(21, 35));
        QTRY_COMPARE(timeSpy.count(), 1);
        QCOMPARE(timeSpy.takeFirst().at(0).toTime(), QTime(21, 35));
        QVERIFY2(!renderWidgetImage(&picker).isNull(),
                 "TimePicker should render the accepted wheel value through QWidget::render");
    }

