    void dateAndTimePickerDisabledPlaceholdersUseDisabledTextToken()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.text = QColor(QStringLiteral("#123A70"));
        custom.subText = QColor(QStringLiteral("#FF00FF"));
        custom.disabledText = QColor(QStringLiteral("#005500"));
        custom.surface = QColor(QStringLiteral("#FFFFFF"));
        custom.background = QColor(QStringLiteral("#F7F9FC"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        const ThemeColors colors = ThemeManager::instance().colors();
        const auto metrics = Style::metrics();

        auto assertDisabledPlaceholder = [&](QWidget *widget, const QString &name) {
            widget->setEnabled(false);
            widget->show();
            QTRY_VERIFY(widget->isVisible());
            QCoreApplication::processEvents();

            const QImage image = renderWidgetImage(widget);
            QVERIFY2(!image.isNull(), qPrintable(name + QStringLiteral(" should render through QWidget::render")));
            const QRect textArea = widget->rect().adjusted(8, 3, -metrics.iconAreaWidth - 6, -3);
            const int disabledPixels = nearColorPixelCount(image, colors.disabledText, textArea, 76);
            const int subTextPixels = nearColorPixelCount(image, colors.subText, textArea, 58);
            QVERIFY2(disabledPixels > 16,
                     qPrintable(QStringLiteral("%1 disabled placeholder should use disabledText pixels, found %2")
                                    .arg(name)
                                    .arg(disabledPixels)));
            QVERIFY2(subTextPixels <= qMax(2, disabledPixels / 5),
                     qPrintable(QStringLiteral("%1 disabled placeholder should not keep subText pixels, found %2 vs disabled %3")
                                    .arg(name)
                                    .arg(subTextPixels)
                                    .arg(disabledPixels)));
        };

        FluentDatePicker date;
        date.setLocale(QLocale(QLocale::English, QLocale::UnitedStates));
        date.setMonthPlaceholderText(QStringLiteral("Month"));
        date.setDayPlaceholderText(QStringLiteral("Day"));
        date.setYearPlaceholderText(QStringLiteral("Year"));
        date.clearDate();
        date.resize(300, 36);
        assertDisabledPlaceholder(&date, QStringLiteral("DatePicker"));

        FluentTimePicker time;
        time.setHourPlaceholderText(QStringLiteral("Hour"));
        time.setMinutePlaceholderText(QStringLiteral("Minute"));
        time.setAnteMeridiemText(QStringLiteral("AM"));
        time.clearTime();
        time.resize(260, 36);
        assertDisabledPlaceholder(&time, QStringLiteral("TimePicker"));
    }

    void colorPickerChromeUsesThemeTokens()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        auto assertTokenBorder = [](const QString &context,
                                    const QImage &image,
                                    const QRect &area,
                                    const QColor &expected,
                                    const QColor &legacy) {
            const int tokenPixels = nearColorPixelCount(image, expected, area, 86);
            const int legacyPixels = nearColorPixelCount(image, legacy, area, 42);
            QVERIFY2(tokenPixels > 2,
                     qPrintable(context + QStringLiteral(" should render neutral.strokeSubtle border pixels")));
            QVERIFY2(legacyPixels <= qMax(1, tokenPixels / 3),
                     qPrintable(context + QStringLiteral(" should not render raw legacy border pixels")));
        };

        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        auto sendEnter = [](QWidget *widget) {
#if QT_VERSION >= QT_VERSION_CHECK(6, 0, 0)
            const QPointF point(widget->rect().center());
            QEnterEvent event(point, point, point);
#else
            QEvent event(QEvent::Enter);
#endif
            QCoreApplication::sendEvent(widget, &event);
            QCoreApplication::processEvents();
        };

        auto sendPress = [](QWidget *widget) {
            const QPointF point(widget->rect().center());
            QMouseEvent event(QEvent::MouseButtonPress,
                              point,
                              Qt::LeftButton,
                              Qt::LeftButton,
                              Qt::NoModifier);
            QCoreApplication::sendEvent(widget, &event);
            QCoreApplication::processEvents();
        };

        auto sendRelease = [](QWidget *widget) {
            const QPointF point(widget->rect().center());
            QMouseEvent event(QEvent::MouseButtonRelease,
                              point,
                              Qt::LeftButton,
                              Qt::NoButton,
                              Qt::NoModifier);
            QCoreApplication::sendEvent(widget, &event);
            QCoreApplication::processEvents();
        };

        auto checkerboardTokenFailure = [](const QString &context,
                                           const QImage &image,
                                           const QRect &area,
                                           const FluentThemeTokens &tokenSet) {
            const QColor expectedA = Style::mix(tokenSet.neutral.card,
                                                tokenSet.neutral.strokeSubtle,
                                                tokenSet.dark ? 0.42 : 0.30);
            const QColor expectedB = Style::mix(tokenSet.neutral.layer,
                                                tokenSet.neutral.cardHover,
                                                tokenSet.dark ? 0.24 : 0.18);
            const int aPixels = nearColorPixelCount(image, expectedA, area, 18);
            const int bPixels = nearColorPixelCount(image, expectedB, area, 18);
            if (aPixels <= 10) {
                return QStringLiteral("%1 checkerboard should render neutral-token cell A pixels, got %2")
                    .arg(context, QString::number(aPixels));
            }
            if (bPixels <= 10) {
                return QStringLiteral("%1 checkerboard should render neutral-token cell B pixels, got %2")
                    .arg(context, QString::number(bPixels));
            }

            auto opaqueNearColorPixelCount = [](const QImage &source,
                                                const QColor &target,
                                                const QRect &rawArea,
                                                int threshold) {
                const QRect sampleArea = normalizedArea(source, rawArea);
                int count = 0;
                for (int y = sampleArea.top(); y <= sampleArea.bottom(); ++y) {
                    const auto *line = reinterpret_cast<const QRgb *>(source.constScanLine(y));
                    for (int x = sampleArea.left(); x <= sampleArea.right(); ++x) {
                        const QColor c = QColor::fromRgba(line[x]);
                        if (c.alpha() < 220) {
                            continue;
                        }
                        const int delta = qAbs(c.red() - target.red())
                                        + qAbs(c.green() - target.green())
                                        + qAbs(c.blue() - target.blue());
                        if (delta <= threshold) {
                            ++count;
                        }
                    }
                }
                return count;
            };
            const int fixedBlack = opaqueNearColorPixelCount(image, QColor(QStringLiteral("#000000")), area, 2);
            const int fixedWhite = opaqueNearColorPixelCount(image, QColor(QStringLiteral("#FFFFFF")), area, 2);
            if (fixedBlack + fixedWhite >= qMax(4, (aPixels + bPixels) / 8)) {
                return QStringLiteral("%1 checkerboard should not prefer fixed black/white cells, black=%2 white=%3 token=%4")
                    .arg(context,
                         QString::number(fixedBlack),
                         QString::number(fixedWhite),
                         QString::number(aPixels + bPixels));
            }
            return QString();
        };

        syncTheme(false, QColor(QStringLiteral("#43FF43")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.background = QColor(QStringLiteral("#EEF5FF"));
        custom.surface = QColor(QStringLiteral("#F7FBFF"));
        custom.border = QColor(QStringLiteral("#FF00FF"));
        custom.hover = QColor(QStringLiteral("#00FFFF"));
        custom.pressed = QColor(QStringLiteral("#FF9500"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        const ThemeColors colors = ThemeManager::instance().colors();
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        QVERIFY(tokens.neutral.strokeSubtle != colors.border);

        FluentColorPicker picker;
        QCOMPARE(picker.color(), tokens.accent.base);
        auto *previewEdit = picker.findChild<QLineEdit *>();
        auto *openButton = picker.findChild<QPushButton *>();
        QVERIFY(previewEdit);
        QVERIFY(openButton);
        QVERIFY2(!previewEdit->styleSheet().contains(QStringLiteral("palette(")),
                 "FluentColorPicker preview should use resolved input tokens");
        QVERIFY2(!openButton->styleSheet().contains(QStringLiteral("palette(")),
                 "FluentColorPicker button should use resolved button tokens");
        QVERIFY(previewEdit->styleSheet().contains(tokens.neutral.card.name(QColor::HexArgb)));
        QVERIFY(previewEdit->styleSheet().contains(tokens.neutral.strokeSubtle.name(QColor::HexArgb)));
        QVERIFY(openButton->styleSheet().contains(tokens.neutral.strokeSubtle.name(QColor::HexArgb)));

        ColorPicker::ColorSwatchButton transparentSwatch(QColor(0, 0, 0, 0));
        transparentSwatch.resize(24, 24);
        const QImage transparentSwatchImage = renderWidgetImage(&transparentSwatch, QSize(24, 24));
        const QString swatchCheckerFailure =
            checkerboardTokenFailure(QStringLiteral("ColorSwatchButton"),
                                     transparentSwatchImage,
                                     QRect(5, 5, 14, 14),
                                     tokens);
        QVERIFY2(swatchCheckerFailure.isEmpty(), qPrintable(swatchCheckerFailure));

        ColorPicker::ColorSwatchButton swatch(QColor(0x33, 0x66, 0x99, 180));
        swatch.resize(24, 24);
        const QImage swatchImage = renderWidgetImage(&swatch, QSize(24, 24));
        assertTokenBorder(QStringLiteral("ColorSwatchButton"),
                          swatchImage,
                          QRect(5, 0, 14, 4),
                          tokens.neutral.strokeSubtle,
                          colors.border);

        QWidget swatchHost;
        const QColor swatchHostBackground(QStringLiteral("#112233"));
        swatchHost.resize(32, 32);
        swatchHost.setAttribute(Qt::WA_StyledBackground, true);
        swatchHost.setStyleSheet(QStringLiteral("background: %1;").arg(swatchHostBackground.name(QColor::HexArgb)));
        ColorPicker::ColorSwatchButton clippedSwatch(QColor(0x33, 0x66, 0x99, 180), &swatchHost);
        clippedSwatch.move(4, 4);
        clippedSwatch.resize(24, 24);
        clippedSwatch.show();
        swatchHost.show();
        QTRY_VERIFY(swatchHost.isVisible());
        const QImage clippedSwatchImage = renderWidgetImage(&swatchHost);
        const QPoint swatchCorners[] = {
            clippedSwatch.pos(),
            clippedSwatch.pos() + QPoint(clippedSwatch.width() - 1, 0),
            clippedSwatch.pos() + QPoint(0, clippedSwatch.height() - 1),
            clippedSwatch.pos() + QPoint(clippedSwatch.width() - 1, clippedSwatch.height() - 1),
        };
        for (const QPoint &corner : swatchCorners) {
            const QColor sampled = QColor::fromRgba(clippedSwatchImage.pixel(corner));
            const int delta = qAbs(sampled.red() - swatchHostBackground.red())
                            + qAbs(sampled.green() - swatchHostBackground.green())
                            + qAbs(sampled.blue() - swatchHostBackground.blue());
            QVERIFY2(delta < 8,
                     qPrintable(QStringLiteral("Transparent swatch checkerboard should be clipped to rounded corners, got %1 at %2,%3")
                                    .arg(sampled.name())
                                    .arg(corner.x())
                                    .arg(corner.y())));
        }

        ColorPicker::PreviewSwatch preview;
        preview.resize(96, 34);
        preview.setColor(QColor(0x33, 0x66, 0x99, 150));
        const QImage previewImage = renderWidgetImage(&preview, QSize(96, 34));
        assertTokenBorder(QStringLiteral("PreviewSwatch"),
                          previewImage,
                          QRect(12, 0, 72, 4),
                          tokens.neutral.strokeSubtle,
                          colors.border);

        ColorPicker::EyeDropperButton eyedropper;
        eyedropper.resize(30, 30);
        const QImage eyeImage = renderWidgetImage(&eyedropper, QSize(30, 30));
        assertTokenBorder(QStringLiteral("EyeDropperButton"),
                          eyeImage,
                          QRect(7, 0, 16, 4),
                          tokens.neutral.strokeSubtle,
                          colors.border);
        const QRect eyeFillSample(5, 5, 8, 7);
        const QColor expectedEyeHover = Style::controlHoverFill(tokens);
        sendEnter(&eyedropper);
        const QImage eyeHoverImage = renderWidgetImage(&eyedropper, QSize(30, 30));
        const QColor eyeHoverFill = dominantColor(eyeHoverImage, eyeFillSample);
        QVERIFY2(colorDelta(eyeHoverFill, expectedEyeHover) < 28,
                 qPrintable(QStringLiteral("EyeDropperButton hover fill should use the control hover token, got %1 expected near %2")
                                .arg(eyeHoverFill.name(), expectedEyeHover.name())));
        if (tokens.dark) {
            const QColor cardSurfaceHover =
                Style::mix(tokens.neutral.card, tokens.neutral.cardHover, 0.70);
            QVERIFY2(colorDelta(eyeHoverFill, cardSurfaceHover) > 6,
                     qPrintable(QStringLiteral("Dark EyeDropperButton hover should separate from card hover, got %1 card hover %2")
                                    .arg(eyeHoverFill.name(), cardSurfaceHover.name())));
        } else {
            QVERIFY2(colorDelta(eyeHoverFill, colors.hover) > 96,
                     qPrintable(QStringLiteral("EyeDropperButton hover fill should not use raw legacy hover color, got %1")
                                    .arg(eyeHoverFill.name())));
        }

        const QColor expectedEyePressed =
            Style::mix(tokens.neutral.card, tokens.neutral.fillTertiary, tokens.dark ? 0.44 : 0.38);
        sendPress(&eyedropper);
        const QImage eyePressedImage = renderWidgetImage(&eyedropper, QSize(30, 30));
        const QColor eyePressedFill = dominantColor(eyePressedImage, eyeFillSample);
        QVERIFY2(colorDelta(eyePressedFill, expectedEyePressed) < 34,
                 qPrintable(QStringLiteral("EyeDropperButton pressed fill should use neutral card/fillTertiary tokens, got %1 expected near %2")
                                .arg(eyePressedFill.name(), expectedEyePressed.name())));
        QVERIFY2(colorDelta(eyePressedFill, colors.pressed) > 72,
                 qPrintable(QStringLiteral("EyeDropperButton pressed fill should not use raw legacy pressed color, got %1")
                                .arg(eyePressedFill.name())));
        sendRelease(&eyedropper);

        ColorPicker::AlphaStrip alpha;
        alpha.resize(160, 30);
        alpha.setBaseColor(QColor(0x33, 0x66, 0x99));
        alpha.setValue(128);
        const QImage alphaImage = renderWidgetImage(&alpha, QSize(160, 30));
        assertTokenBorder(QStringLiteral("AlphaStrip"),
                          alphaImage,
                          QRect(18, 7, 124, 4),
                          tokens.neutral.strokeSubtle,
                          colors.border);

        ColorPicker::GradientStopBar stopBar;
        stopBar.resize(180, 44);
        stopBar.setStops(QVector<ColorPicker::GradientStop>{
            {0.0, QColor(0, 0, 0, 0)},
            {1.0, QColor(0, 0, 0, 0)}
        });
        const QImage stopBarImage = renderWidgetImage(&stopBar, QSize(180, 44));
        const QString stopBarCheckerFailure =
            checkerboardTokenFailure(QStringLiteral("GradientStopBar"),
                                     stopBarImage,
                                     QRect(20, 8, 120, 14),
                                     tokens);
        QVERIFY2(stopBarCheckerFailure.isEmpty(), qPrintable(stopBarCheckerFailure));

        FluentColorDialog dialog(QColor(), nullptr);
        QCOMPARE(dialog.resetColor(), tokens.accent.base);
        QCOMPARE(dialog.currentColor().rgba(), tokens.accent.base.rgba());
        QCOMPARE(dialog.selectedColor().rgba(), tokens.accent.base.rgba());
        auto separators = dialog.findChildren<QWidget *>(QStringLiteral("FluentColorDialogSeparator"));
        QVERIFY2(separators.size() >= 3, "FluentColorDialog should expose themed separator widgets");
        for (QWidget *separator : separators) {
            QVERIFY(separator->styleSheet().contains(tokens.neutral.strokeSubtle.name(QColor::HexArgb)));
            QVERIFY2(!separator->styleSheet().contains(colors.border.name(QColor::HexArgb)),
                     "FluentColorDialog separators should not keep raw legacy border color");
        }

        syncTheme(true, QColor(QStringLiteral("#43FF43")));
        ThemeColors darkCustom = ThemeManager::instance().colors();
        darkCustom.background = QColor(QStringLiteral("#101010"));
        darkCustom.surface = QColor(QStringLiteral("#201820"));
        darkCustom.border = QColor(QStringLiteral("#FF00FF"));
        ThemeManager::instance().setColors(darkCustom);
        QCoreApplication::processEvents();

        const FluentThemeTokens darkTokens = ThemeManager::instance().tokens();
        separators = dialog.findChildren<QWidget *>(QStringLiteral("FluentColorDialogSeparator"));
        for (QWidget *separator : separators) {
            QVERIFY(separator->styleSheet().contains(darkTokens.neutral.strokeSubtle.name(QColor::HexArgb)));
        }

        const ThemeColors darkColors = ThemeManager::instance().colors();
        const QColor expectedDarkHandle = Style::mix(darkTokens.neutral.card, darkColors.text, 0.72);
        const QRect handleFillSample(76, 9, 8, 10);

        ColorPicker::HueStrip darkHue;
        darkHue.setOrientation(Qt::Horizontal);
        darkHue.resize(160, 30);
        darkHue.setValue(180);
        const QImage darkHueImage = renderWidgetImage(&darkHue, QSize(160, 30));
        const QColor darkHueHandle = dominantColor(darkHueImage, handleFillSample);
        QVERIFY2(colorDelta(darkHueHandle, QColor(QStringLiteral("#FFFFFF"))) > 90,
                 qPrintable(QStringLiteral("Dark HueStrip handle should not fall back to hard-coded white, got %1")
                                .arg(darkHueHandle.name())));
        QVERIFY2(colorDelta(darkHueHandle, expectedDarkHandle) < 86,
                 qPrintable(QStringLiteral("Dark HueStrip handle should use theme-derived handle fill, got %1 expected near %2")
                                .arg(darkHueHandle.name(), expectedDarkHandle.name())));

        ColorPicker::AlphaStrip darkAlpha;
        darkAlpha.resize(160, 30);
        darkAlpha.setBaseColor(QColor(0x33, 0x66, 0x99));
        darkAlpha.setValue(128);
        const QImage darkAlphaImage = renderWidgetImage(&darkAlpha, QSize(160, 30));
        const QColor darkAlphaHandle = dominantColor(darkAlphaImage, handleFillSample);
        QVERIFY2(colorDelta(darkAlphaHandle, QColor(QStringLiteral("#FFFFFF"))) > 90,
                 qPrintable(QStringLiteral("Dark AlphaStrip handle should not fall back to hard-coded white, got %1")
                                .arg(darkAlphaHandle.name())));
        QVERIFY2(colorDelta(darkAlphaHandle, expectedDarkHandle) < 86,
                 qPrintable(QStringLiteral("Dark AlphaStrip handle should use theme-derived handle fill, got %1 expected near %2")
                                .arg(darkAlphaHandle.name(), expectedDarkHandle.name())));
    }

    void colorDialogChromeUsesFrameTokens()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();
            bool accentBorder = ThemeManager::instance().accentBorderEnabled();
            WindowMetrics windowMetrics = Style::windowMetrics();

            ~ThemeRestore()
            {
                Style::setWindowMetrics(windowMetrics);
                ThemeManager::instance().setAccentBorderEnabled(accentBorder);
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        auto renderColorDialog = [](FluentColorDialog &dialog) {
            QCoreApplication::processEvents();
            QImage image = renderWidgetImage(&dialog, dialog.size());
            if (alphaPixelCount(image, 16) < 128) {
                QCoreApplication::processEvents();
                QTest::qWait(20);
                image = renderWidgetImage(&dialog, dialog.size());
            }
            return image;
        };

        WindowMetrics metrics = Style::windowMetrics();
        metrics.accentBorderTraceDurationMs = 1;
        metrics.accentBorderTraceEnableOvershoot = 0.0;
        Style::setWindowMetrics(metrics);

        syncTheme(true, QColor(QStringLiteral("#43FF43")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.background = QColor(QStringLiteral("#101010"));
        custom.surface = QColor(QStringLiteral("#201820"));
        custom.border = QColor(QStringLiteral("#FF00FF"));
        custom.text = QColor(QStringLiteral("#E8E1FF"));
        ThemeManager::instance().setColors(custom);
        ThemeManager::instance().setAccentBorderEnabled(false);
        QCoreApplication::processEvents();

        const ThemeColors colors = ThemeManager::instance().colors();
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        QVERIFY(tokens.neutral.strokeSubtle != colors.border);

        FluentColorDialog dialog(QColor(QStringLiteral("#336699")), nullptr);
        dialog.show();
        QTRY_VERIFY(dialog.isVisible());
        QTest::qWait(20);

        const QImage image = renderColorDialog(dialog);
        QVERIFY2(!image.isNull(), "FluentColorDialog should render through QWidget::render offscreen");

        FluentFrameSpec neutralFrame;
        neutralFrame.accentBorderEnabled = false;
        neutralFrame.borderInset = 1.0;
        const QColor expectedModalSurface = fluentFrameSurface(colors, neutralFrame);
        const QRect surfaceProbe(dialog.width() / 2 - 42, 5, 84, 3);
        const QColor surfaceFill = dominantColor(image, surfaceProbe);
        QVERIFY2(colorDelta(surfaceFill, expectedModalSurface) < 42,
                 qPrintable(QStringLiteral("FluentColorDialog surface should use modal frame tokens, got %1 expected near %2")
                                .arg(surfaceFill.name(), expectedModalSurface.name())));
        QVERIFY2(colorDelta(surfaceFill, colors.surface) > 8,
                 qPrintable(QStringLiteral("FluentColorDialog surface should not stay on raw legacy surface, got %1")
                                .arg(surfaceFill.name())));

        const QRect borderProbe(48, 0, dialog.width() - 96, 4);
        QVERIFY2(nearColorPixelCount(image, tokens.neutral.strokeSubtle, borderProbe, 76) > 8,
                 "FluentColorDialog neutral border should render neutral.strokeSubtle token pixels");
        QVERIFY2(nearColorPixelCount(image, colors.border, borderProbe, 48) < 4,
                 "FluentColorDialog neutral border should not render the raw legacy border color");
        QVERIFY2(nearColorPixelCount(image, tokens.accent.base, borderProbe, 72) < 4,
                 "FluentColorDialog neutral border should not keep an accent border when accent borders are disabled");

        int sampledSeparators = 0;
        const auto separators = dialog.findChildren<QWidget *>(QStringLiteral("FluentColorDialogSeparator"));
        for (QWidget *separator : separators) {
            if (!separator || !separator->isVisible() || separator->width() < 60) {
                continue;
            }
            const QRect separatorRect(separator->mapTo(&dialog, QPoint(0, 0)), separator->size());
            const int tokenPixels = nearColorPixelCount(image, tokens.neutral.strokeSubtle, separatorRect, 76);
            const int legacyPixels = nearColorPixelCount(image, colors.border, separatorRect, 48);
            QVERIFY2(tokenPixels > 8,
                     "FluentColorDialog separators should render neutral.strokeSubtle token pixels");
            QVERIFY2(legacyPixels < qMax(4, tokenPixels / 3),
                     "FluentColorDialog separators should not render raw legacy border pixels");
            ++sampledSeparators;
        }
        QVERIFY2(sampledSeparators >= 2,
                 "FluentColorDialog should expose visible separator chrome for pixel sampling");

        dialog.close();
        QCoreApplication::processEvents();

        ThemeManager::instance().setAccentBorderEnabled(true);
        QCoreApplication::processEvents();

        FluentColorDialog accentDialog(QColor(QStringLiteral("#336699")), nullptr);
        accentDialog.show();
        QTRY_VERIFY(accentDialog.isVisible());
        QTest::qWait(20);

        const QImage accentImage = renderColorDialog(accentDialog);
        QVERIFY2(!accentImage.isNull(), "Accent FluentColorDialog should render through QWidget::render offscreen");
        const QRect accentBorderProbe(48, 0, accentDialog.width() - 96, 4);
        QVERIFY2(nearColorPixelCount(accentImage, tokens.accent.base, accentBorderProbe, 72) > 8,
                 "FluentColorDialog accent border should render accent.base token pixels");
        QVERIFY2(nearColorPixelCount(accentImage, colors.border, accentBorderProbe, 48) < 4,
                 "FluentColorDialog accent border should not fall back to the raw legacy border color");
        accentDialog.close();
    }

    void colorDialogPersistsRecentColorsOnAccept()
    {
        const QString key = QStringLiteral("QtFluent/FluentColorDialog/recent");
        struct AppIdentityRestore {
            QString organizationName = QCoreApplication::organizationName();
            QString organizationDomain = QCoreApplication::organizationDomain();
            QString applicationName = QCoreApplication::applicationName();

            AppIdentityRestore()
            {
                QCoreApplication::setOrganizationName(QStringLiteral("QtFluentVisualSmoke"));
                QCoreApplication::setOrganizationDomain(QStringLiteral("qtfluent.local"));
                QCoreApplication::setApplicationName(QStringLiteral("ColorDialogRecentTest"));
            }

            ~AppIdentityRestore()
            {
                QCoreApplication::setOrganizationName(organizationName);
                QCoreApplication::setOrganizationDomain(organizationDomain);
                QCoreApplication::setApplicationName(applicationName);
            }
        } appIdentityRestore;

        struct SettingsRestore {
            QString key;
            bool hadValue = false;
            QVariant oldValue;

            explicit SettingsRestore(const QString &settingsKey)
                : key(settingsKey)
            {
                QSettings settings;
                hadValue = settings.contains(key);
                oldValue = settings.value(key);
                settings.remove(key);
                settings.sync();
            }

            ~SettingsRestore()
            {
                QSettings settings;
                if (hadValue) {
                    settings.setValue(key, oldValue);
                } else {
                    settings.remove(key);
                }
                settings.sync();
            }
        } restore(key);

        auto toHexArgb = [](const QColor &color) {
            return QStringLiteral("#%1%2%3%4")
                .arg(QString::number(color.alpha(), 16).rightJustified(2, QLatin1Char('0')).toUpper(),
                     QString::number(color.red(), 16).rightJustified(2, QLatin1Char('0')).toUpper(),
                     QString::number(color.green(), 16).rightJustified(2, QLatin1Char('0')).toUpper(),
                     QString::number(color.blue(), 16).rightJustified(2, QLatin1Char('0')).toUpper());
        };

        auto clickPrimaryButton = [](FluentColorDialog &dialog) {
            FluentButton *primary = nullptr;
            const auto buttons = dialog.findChildren<FluentButton *>();
            for (FluentButton *button : buttons) {
                if (button && button->isPrimary()) {
                    primary = button;
                    break;
                }
            }
            QVERIFY2(primary, "FluentColorDialog should expose a primary OK button");
            primary->click();
            QCoreApplication::processEvents();
        };

        QStringList seeded;
        for (int index = 0; index < 12; ++index) {
            seeded << toHexArgb(QColor(8 + index, 30 + index, 70 + index, 255 - index));
        }
        {
            QSettings settings;
            settings.setValue(key, seeded);
            settings.sync();
        }

        const QColor firstAccepted(0x12, 0x34, 0x56, 0x78);
        FluentColorDialog firstDialog(firstAccepted, nullptr);
        QCOMPARE(firstDialog.currentColor(), firstAccepted);
        clickPrimaryButton(firstDialog);

        QSettings settings;
        QStringList stored = settings.value(key).toStringList();
        QCOMPARE(stored.size(), 12);
        QCOMPARE(stored.first(), toHexArgb(firstAccepted));
        QVERIFY2(!stored.contains(seeded.last()),
                 "FluentColorDialog recent colors should keep at most 12 entries");

        const QColor duplicate(0xAA, 0x44, 0x66, 0x88);
        const QString duplicateHex = toHexArgb(duplicate);
        stored[5] = duplicateHex;
        settings.setValue(key, stored);
        settings.sync();

        FluentColorDialog duplicateDialog(duplicate, nullptr);
        clickPrimaryButton(duplicateDialog);
        const QStringList deduped = settings.value(key).toStringList();
        QCOMPARE(deduped.size(), 12);
        QCOMPARE(deduped.first(), duplicateHex);
        QCOMPARE(deduped.count(duplicateHex), 1);

        FluentColorDialog nextDialog(QColor(), nullptr);
        bool foundRecentSwatch = false;
        const auto swatches = nextDialog.findChildren<ColorPicker::ColorSwatchButton *>();
        for (ColorPicker::ColorSwatchButton *swatch : swatches) {
            if (swatch && swatch->color() == duplicate) {
                foundRecentSwatch = true;
                break;
            }
        }
        QVERIFY2(foundRecentSwatch,
                 "FluentColorDialog should show persisted recent colors when opened again");
        QVERIFY2(!renderWidgetImage(&nextDialog).isNull(),
                 "FluentColorDialog recent colors should render to an offscreen QWidget::render image");
    }

    void colorDialogUsesToolWindowAndAutoRejectsOnDeactivate()
    {
        FluentColorDialog dialog(QColor(QStringLiteral("#2D7DFF")), nullptr);

        const Qt::WindowFlags flags = dialog.windowFlags();
        QCOMPARE(flags & Qt::WindowType_Mask, Qt::Tool);
        QVERIFY2(flags.testFlag(Qt::FramelessWindowHint),
                 "FluentColorDialog should keep frameless popup-like chrome");
        QVERIFY2(flags.testFlag(Qt::NoDropShadowWindowHint),
                 "FluentColorDialog should let Fluent draw the shadow/border treatment");
        QVERIFY2((flags & Qt::WindowType_Mask) != Qt::Popup,
                 "FluentColorDialog should avoid Qt::Popup to keep transparent frameless windows stable");

        dialog.show();
        QTRY_VERIFY(dialog.isVisible());
        QVERIFY2(!renderWidgetImage(&dialog).isNull(),
                 "FluentColorDialog should render through QWidget::render while shown offscreen");

        QSignalSpy rejectedSpy(&dialog, &QDialog::rejected);
        QEvent deactivate(QEvent::WindowDeactivate);
        QVERIFY(QCoreApplication::sendEvent(&dialog, &deactivate));

        QTRY_COMPARE(rejectedSpy.count(), 1);
        QTRY_VERIFY(!dialog.isVisible());
    }

    void colorDialogHeaderDragMovesWindow()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        auto sendMouse = [](QWidget *target, QEvent::Type type, const QPoint &pos,
                            const QPoint &globalPos, Qt::MouseButton button, Qt::MouseButtons buttons) {
#if QT_VERSION >= QT_VERSION_CHECK(6, 0, 0)
            QMouseEvent event(type,
                              QPointF(pos),
                              QPointF(pos),
                              QPointF(globalPos),
                              button,
                              buttons,
                              Qt::NoModifier);
#else
            QMouseEvent event(type, pos, globalPos, button, buttons, Qt::NoModifier);
#endif
            QCoreApplication::sendEvent(target, &event);
            QCoreApplication::processEvents();
        };

        FluentColorDialog dialog(QColor(QStringLiteral("#2D7DFF")), nullptr);
        dialog.move(160, 140);
        dialog.show();
        QTRY_VERIFY(dialog.isVisible());
        QCoreApplication::processEvents();

        QWidget *header = dialog.findChild<QWidget *>(QStringLiteral("fluentColorHeader"));
        QVERIFY2(header, "FluentColorDialog should expose its documented draggable header widget");
        QVERIFY2(header->isVisible(), "FluentColorDialog header should be visible while the dialog is shown");

        const QPoint before = dialog.pos();
        const QPoint dragStart(22, header->height() / 2);
        const QPoint dragDelta(36, 24);
        const QPoint dragGlobal = header->mapToGlobal(dragStart);

        sendMouse(header, QEvent::MouseButtonPress, dragStart, dragGlobal, Qt::LeftButton, Qt::LeftButton);
        sendMouse(header, QEvent::MouseMove, dragStart + dragDelta, dragGlobal + dragDelta, Qt::NoButton, Qt::LeftButton);
        sendMouse(header, QEvent::MouseButtonRelease, dragStart + dragDelta, dragGlobal + dragDelta, Qt::LeftButton, Qt::NoButton);

        const QPoint after = dialog.pos();
        const int tolerance = 2;
        QVERIFY2(qAbs((after - before).x() - dragDelta.x()) <= tolerance
                     && qAbs((after - before).y() - dragDelta.y()) <= tolerance,
                 qPrintable(QStringLiteral("FluentColorDialog header drag should move by %1,%2; start=%3,%4 moved=%5,%6")
                                .arg(dragDelta.x())
                                .arg(dragDelta.y())
                                .arg(before.x())
                                .arg(before.y())
                                .arg(after.x())
                                .arg(after.y())));
        QVERIFY2(!renderWidgetImage(&dialog, dialog.size()).isNull(),
                 "FluentColorDialog should still render offscreen after a synthetic header drag");
    }

    void colorPickerRollsBackLivePreviewOnCancel()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        FluentColorPicker picker;
        picker.resize(260, 36);
        const QColor initial(QStringLiteral("#123456"));
        const QColor preview(QStringLiteral("#C86432"));
        picker.setColor(initial);

        QSignalSpy changedSpy(&picker, &FluentColorPicker::colorChanged);
        bool sawDialog = false;
        bool sawLivePreview = false;
        bool renderedDialog = false;

        auto findColorDialog = []() -> FluentColorDialog * {
            if (auto *modal = qobject_cast<FluentColorDialog *>(QApplication::activeModalWidget())) {
                return modal;
            }
            const auto topLevels = QApplication::topLevelWidgets();
            for (QWidget *widget : topLevels) {
                if (auto *dialog = qobject_cast<FluentColorDialog *>(widget)) {
                    return dialog;
                }
            }
            return nullptr;
        };

        QTimer::singleShot(0, [&]() {
            FluentColorDialog *dialog = findColorDialog();
            if (!dialog) {
                QCoreApplication::processEvents(QEventLoop::AllEvents, 20);
                dialog = findColorDialog();
            }
            if (!dialog) {
                return;
            }

            sawDialog = true;
            dialog->setCurrentColor(preview);
            QCoreApplication::processEvents();
            sawLivePreview = picker.color() == preview;
            renderedDialog = !renderWidgetImage(dialog).isNull();
            dialog->reject();
        });

        QTimer::singleShot(1000, []() {
            if (auto *dialog = qobject_cast<QDialog *>(QApplication::activeModalWidget())) {
                dialog->reject();
            }
        });

        QVERIFY(QMetaObject::invokeMethod(&picker, "openDialog", Qt::DirectConnection));
        QVERIFY2(sawDialog, "FluentColorPicker should open a FluentColorDialog from its button workflow");
        QVERIFY2(sawLivePreview, "FluentColorPicker should mirror dialog colorChanged while the dialog is open");
        QVERIFY2(renderedDialog, "FluentColorPicker dialog should render through QWidget::render while open offscreen");
        QCOMPARE(picker.color(), initial);

        QList<QColor> emittedColors;
        for (const auto &arguments : changedSpy) {
            emittedColors.append(arguments.at(0).value<QColor>());
        }
        QVERIFY2(emittedColors.contains(preview),
                 "FluentColorPicker should emit the live preview color before cancel");
        QVERIFY2(emittedColors.contains(initial),
                 "FluentColorPicker should emit the restored opening color after cancel");
        QVERIFY2(!renderWidgetImage(&picker).isNull(),
                 "FluentColorPicker should render to an offscreen QWidget::render image after rollback");
    }

    void motionTokensCanDisablePopupAnimation()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        const FluentMotionTokens oldMotionTokens = ThemeManager::instance().motionTokens();
        struct AnimationRestore {
            bool enabled = true;
            FluentMotionTokens tokens;
            ~AnimationRestore()
            {
                ThemeManager::instance().setMotionTokens(tokens);
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled, oldMotionTokens};

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        QWidget window;
        auto *layout = new QVBoxLayout(&window);
        auto *button = new FluentButton(QStringLiteral("Button"), &window);
        auto *toolButton = new FluentToolButton(QStringLiteral("Tool"), &window);
        auto *edit = new FluentLineEdit(&window);
        auto *shortcut = new FluentKeySequenceEdit(QKeySequence(QStringLiteral("Ctrl+K")), &window);
        auto *textEdit = new FluentTextEdit(&window);
        auto *codeEditor = new FluentCodeEditor(&window);
        auto *toggle = new FluentToggleSwitch(QStringLiteral("Toggle"), &window);
        auto *check = new FluentCheckBox(QStringLiteral("Check"), &window);
        auto *radio = new FluentRadioButton(QStringLiteral("Radio"), &window);
        auto *slider = new FluentSlider(Qt::Horizontal, &window);
        auto *progress = new FluentProgressBar(&window);
        auto *ring = new FluentProgressRing(&window);
        auto *dial = new FluentDial(&window);
        auto *splitter = new FluentSplitter(Qt::Horizontal, &window);
        auto *combo = new FluentComboBox(&window);
        auto *autoSuggest = new FluentAutoSuggestBox(&window);
        auto *calendarPicker = new FluentCalendarPicker(&window);
        auto *datePicker = new FluentDatePicker(&window);
        auto *timePicker = new FluentTimePicker(&window);
        auto *rangePicker = new FluentDateRangePicker(&window);
        combo->addItems({QStringLiteral("Alpha"), QStringLiteral("Beta"), QStringLiteral("Gamma")});
        combo->setCurrentIndex(1);
        codeEditor->setPlainText(QStringLiteral("int main() {\n    return 0;\n}\n"));
        rangePicker->setDateRange(QDate(2026, 5, 1), QDate(2026, 5, 29));
        autoSuggest->setSuggestions({
            QStringLiteral("Alpha command"),
            QStringLiteral("Beta command"),
            QStringLiteral("Gamma command"),
        });
        slider->setRange(0, 100);
        progress->setRange(0, 100);
        ring->setRange(0, 100);
        splitter->addWidget(new QLabel(QStringLiteral("Left pane"), splitter));
        splitter->addWidget(new QLabel(QStringLiteral("Right pane"), splitter));
        splitter->setMinimumHeight(42);
        layout->addWidget(button);
        layout->addWidget(toolButton);
        layout->addWidget(edit);
        layout->addWidget(shortcut);
        layout->addWidget(textEdit);
        layout->addWidget(codeEditor);
        layout->addWidget(toggle);
        layout->addWidget(check);
        layout->addWidget(radio);
        layout->addWidget(slider);
        layout->addWidget(progress);
        layout->addWidget(ring);
        layout->addWidget(dial);
        layout->addWidget(splitter);
        layout->addWidget(combo);
        layout->addWidget(autoSuggest);
        layout->addWidget(calendarPicker);
        layout->addWidget(datePicker);
        layout->addWidget(timePicker);
        layout->addWidget(rangePicker);
        window.show();
        QCoreApplication::processEvents();

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();

        QCOMPARE(FluentMotion::duration(FluentMotionRole::PopupOpen), 0);
        QCOMPARE(FluentMotion::duration(FluentMotionRole::Hover), 0);

        QTest::mouseMove(button, button->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(button->hoverLevel() >= 0.99, "Button hover animation did not reconfigure to complete immediately");

        QTest::mouseMove(toolButton, toolButton->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(toolButton->hoverLevel() >= 0.99, "ToolButton hover animation did not reconfigure to complete immediately");

        edit->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(edit->focusLevel() >= 0.99, "LineEdit focus animation did not reconfigure to complete immediately");

        QTest::mouseMove(shortcut, shortcut->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(shortcut->hoverLevel() >= 0.99, "KeySequenceEdit hover animation did not complete immediately");
        shortcut->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(shortcut->focusLevel() >= 0.99, "KeySequenceEdit focus animation did not complete immediately");

        QTest::mouseMove(textEdit->viewport(), textEdit->viewport()->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(textEdit->hoverLevel() >= 0.99, "TextEdit hover animation did not complete immediately");
        textEdit->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(textEdit->focusLevel() >= 0.99, "TextEdit focus animation did not complete immediately");

        QTest::mouseMove(codeEditor->viewport(), codeEditor->viewport()->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(codeEditor->hoverLevel() >= 0.99, "CodeEditor hover animation did not complete immediately");
        codeEditor->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(codeEditor->focusLevel() >= 0.99, "CodeEditor focus animation did not complete immediately");

        QTest::mouseMove(combo, combo->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(combo->hoverLevel() >= 0.99, "ComboBox hover animation did not reconfigure to complete immediately");

        auto assertPickerImmediate = [](auto *picker, const char *name) {
            QTest::mouseMove(picker, picker->rect().center());
            QCoreApplication::processEvents();
            QVERIFY2(picker->hoverLevel() >= 0.99,
                     qPrintable(QString::fromLatin1(name) + QStringLiteral(" hover animation did not complete immediately")));
            picker->setFocus(Qt::OtherFocusReason);
            QCoreApplication::processEvents();
            QVERIFY2(picker->focusLevel() >= 0.99,
                     qPrintable(QString::fromLatin1(name) + QStringLiteral(" focus animation did not complete immediately")));
        };

        assertPickerImmediate(calendarPicker, "CalendarPicker");
        assertPickerImmediate(datePicker, "DatePicker");
        assertPickerImmediate(timePicker, "TimePicker");
        assertPickerImmediate(rangePicker, "DateRangePicker");

        toggle->setChecked(true);
        QCOMPARE(toggle->progress(), 1.0);
        toggle->setChecked(false);
        QCOMPARE(toggle->progress(), 0.0);

        QTest::mouseMove(check, check->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(check->hoverLevel() >= 0.99, "CheckBox hover animation did not complete immediately");
        check->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(check->focusLevel() >= 0.99, "CheckBox focus animation did not complete immediately");

        QTest::mouseMove(radio, radio->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(radio->hoverLevel() >= 0.99, "RadioButton hover animation did not complete immediately");
        radio->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(radio->focusLevel() >= 0.99, "RadioButton focus animation did not complete immediately");

        slider->setValue(75);
        QCOMPARE(slider->handlePos(), 0.75);
        progress->setValue(66);
        QCOMPARE(progress->displayValue(), 66.0);
        ring->setValue(40);
        QCOMPARE(ring->displayValue(), 40.0);

        ring->setIndeterminate(true);
        const qreal stableAngle = ring->rotationAngle();
        QTest::qWait(50);
        QCOMPARE(ring->rotationAngle(), stableAngle);

        QTest::mouseMove(dial, dial->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(dial->hoverLevel() >= 0.99, "Dial hover animation did not complete immediately");
        dial->setFocus(Qt::OtherFocusReason);
        QCoreApplication::processEvents();
        QVERIFY2(dial->focusLevel() >= 0.99, "Dial focus animation did not complete immediately");

        QSplitterHandle *splitterHandle = splitter->handle(1);
        QVERIFY2(splitterHandle, "Splitter should expose a draggable handle");
        QTest::mouseMove(splitterHandle, splitterHandle->rect().center());
        QCoreApplication::processEvents();
        QVERIFY2(splitterHandle->property("fluentHoverLevel").toReal() >= 0.99,
                 "Splitter handle hover animation did not complete immediately");

        combo->showPopup();
        QCoreApplication::processEvents();

        QWidget *popup = findVisibleTopLevelByObjectName(QStringLiteral("FluentComboPopup"));
        QVERIFY2(popup && popup->isVisible(), "ComboBox popup was not visible with animations disabled");
        QCOMPARE(popup->windowOpacity(), 1.0);
        QVERIFY2(popup->mask().isEmpty(), "ComboBox popup should finish reveal mask immediately with animations disabled");
        QVERIFY2(findComboPopupView(), "ComboBox popup view was not available with animations disabled");

        combo->hidePopup();
        QCoreApplication::processEvents();

        autoSuggest->lineEdit()->setFocus(Qt::OtherFocusReason);
        autoSuggest->setText(QStringLiteral("Alpha"));
        QCoreApplication::processEvents();
        QWidget *autoSuggestPopup = findVisibleTopLevelByObjectName(QStringLiteral("FluentAutoSuggestPopup"));
        QVERIFY2(autoSuggestPopup && autoSuggestPopup->isVisible(),
                 "AutoSuggestBox popup was not visible with animations disabled");
        QCOMPARE(autoSuggestPopup->windowOpacity(), 1.0);
        QVERIFY2(autoSuggestPopup->mask().isEmpty(),
                 "AutoSuggestBox popup should finish reveal mask immediately with animations disabled");
        QVERIFY2(findAutoSuggestPopupView(), "AutoSuggestBox popup view was not available with animations disabled");
        autoSuggestPopup->close();
        QCoreApplication::processEvents();
    }

    void flyoutChromeUsesPopupSurfaceTokens()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();
            bool accentBorder = ThemeManager::instance().accentBorderEnabled();

            ~ThemeRestore()
            {
                ThemeManager::instance().setAccentBorderEnabled(accentBorder);
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        auto renderFlyout = [](FluentFlyout &flyout) {
            QCoreApplication::processEvents();
            QImage image = renderWidgetImage(&flyout, flyout.size());
            if (alphaPixelCount(image, 16) < 128) {
                QCoreApplication::processEvents();
                QTest::qWait(20);
                image = renderWidgetImage(&flyout, flyout.size());
            }
            return image;
        };

        syncTheme(true, QColor(QStringLiteral("#43FF43")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.background = QColor(QStringLiteral("#101010"));
        custom.surface = QColor(QStringLiteral("#201820"));
        custom.border = QColor(QStringLiteral("#FF00FF"));
        custom.text = QColor(QStringLiteral("#E8E1FF"));
        ThemeManager::instance().setColors(custom);
        ThemeManager::instance().setAccentBorderEnabled(false);
        QCoreApplication::processEvents();

        const ThemeColors colors = ThemeManager::instance().colors();
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        QVERIFY(tokens.neutral.strokeSubtle != colors.border);

        FluentFlyout flyout;
        auto *label = new FluentLabel(QStringLiteral("Flyout popup chrome"), &flyout);
        label->setFixedWidth(220);
        flyout.setContentWidget(label);
        flyout.resize(PopupSurface::withShadowMargins(QSize(260, 64)));
        flyout.layout()->activate();
        QCoreApplication::processEvents();

        const QImage image = renderFlyout(flyout);
        QVERIFY2(!image.isNull(), "FluentFlyout should render through QWidget::render offscreen");

        const QRect contentRect = PopupSurface::shadowContentRect(flyout.rect());
        QVERIFY2(contentRect.isValid(), "FluentFlyout should expose a valid PopupSurface content rect");

        FluentSurfaceSpec popupSurface;
        popupSurface.level = FluentSurfaceLevel::Popup;
        popupSurface.elevation = FluentElevationLevel::None;
        popupSurface.radius = PopupSurface::kRadius;
        popupSurface.borderWidth = PopupSurface::kBorderWidth;
        popupSurface.borderInset = 0.0;
        const QColor expectedSurface = fluentSurfaceFill(colors, popupSurface);
        const QRect surfaceProbe(contentRect.left() + 34,
                                 contentRect.top() + 6,
                                 qMax(1, contentRect.width() - 68),
                                 4);
        const QColor surfaceFill = dominantColor(image, surfaceProbe);
        QVERIFY2(colorDelta(surfaceFill, expectedSurface) < 42,
                 qPrintable(QStringLiteral("FluentFlyout surface should use popup surface tokens, got %1 expected near %2")
                                .arg(surfaceFill.name(), expectedSurface.name())));
        QVERIFY2(colorDelta(surfaceFill, colors.surface) > 8,
                 qPrintable(QStringLiteral("FluentFlyout surface should not stay on raw legacy surface, got %1")
                                .arg(surfaceFill.name())));

        const QRect borderProbe(contentRect.left() + 32,
                                contentRect.top(),
                                qMax(1, contentRect.width() - 64),
                                4);
        QVERIFY2(nearColorPixelCount(image, tokens.neutral.strokeSubtle, borderProbe, 76) > 8,
                 "FluentFlyout neutral border should render neutral.strokeSubtle token pixels");
        QVERIFY2(nearColorPixelCount(image, colors.border, borderProbe, 48) < 4,
                 "FluentFlyout neutral border should not render the raw legacy border color");
        QVERIFY2(nearColorPixelCount(image, tokens.accent.base, borderProbe, 72) < 4,
                 "FluentFlyout neutral border should not keep an accent border when accent borders are disabled");

        flyout.close();
        QCoreApplication::processEvents();

        ThemeManager::instance().setAccentBorderEnabled(true);
        QCoreApplication::processEvents();

        FluentFlyout accentFlyout;
        auto *accentLabel = new FluentLabel(QStringLiteral("Accent flyout chrome"), &accentFlyout);
        accentLabel->setFixedWidth(220);
        accentFlyout.setContentWidget(accentLabel);
        accentFlyout.resize(PopupSurface::withShadowMargins(QSize(260, 64)));
        accentFlyout.layout()->activate();
        QCoreApplication::processEvents();

        const QImage accentImage = renderFlyout(accentFlyout);
        QVERIFY2(!accentImage.isNull(), "Accent FluentFlyout should render through QWidget::render offscreen");
        const QRect accentContentRect = PopupSurface::shadowContentRect(accentFlyout.rect());
        const QRect accentBorderProbe(accentContentRect.left() + 32,
                                      accentContentRect.top(),
                                      qMax(1, accentContentRect.width() - 64),
                                      4);
        QVERIFY2(nearColorPixelCount(accentImage, tokens.accent.base, accentBorderProbe, 72) > 8,
                 "FluentFlyout accent border should render accent.base token pixels");
        QVERIFY2(nearColorPixelCount(accentImage, colors.border, accentBorderProbe, 48) < 4,
                 "FluentFlyout accent border should not fall back to the raw legacy border color");
        accentFlyout.close();
    }

    void flyoutReducedMotionSnapsRunningOpenAnimation()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        const FluentMotionTokens oldMotionTokens = ThemeManager::instance().motionTokens();
        struct RestoreMotion {
            bool enabled = true;
            FluentMotionTokens tokens;
            ~RestoreMotion()
            {
                ThemeManager::instance().setMotionTokens(tokens);
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled, oldMotionTokens};

        ThemeManager::instance().setAnimationsEnabled(true);
        FluentMotion::setDuration(FluentMotionRole::PopupOpen, 240);
        QCoreApplication::processEvents();

        QWidget window;
        window.resize(420, 260);
        auto *layout = new QVBoxLayout(&window);
        layout->setContentsMargins(36, 36, 36, 36);
        auto *anchor = new FluentButton(QStringLiteral("Anchor"), &window);
        layout->addWidget(anchor);
        layout->addStretch(1);
        window.show();
        QTRY_VERIFY(window.isVisible());

        FluentFlyout flyout(&window);
        auto *label = new FluentLabel(QStringLiteral("Popup open should snap when reduced motion is enabled."), &flyout);
        label->setWordWrap(true);
        label->setFixedWidth(220);
        flyout.setContentWidget(label);
        flyout.showFor(anchor, FluentFlyout::Placement::Bottom);
        QCoreApplication::processEvents();
        QVERIFY2(flyout.isVisible(), "Flyout should be visible while the popup-open animation is running");

        const auto runningBefore = flyout.findChildren<QAbstractAnimation *>(QString(), Qt::FindDirectChildrenOnly);
        QVERIFY2(std::any_of(runningBefore.cbegin(), runningBefore.cend(), [](QAbstractAnimation *animation) {
                     return animation && animation->state() == QAbstractAnimation::Running;
                 }),
                 "Flyout should have a running popup-open animation before reduced motion is enabled");

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QCOMPARE(FluentMotion::duration(FluentMotionRole::PopupOpen), 0);

        const auto runningAfter = flyout.findChildren<QAbstractAnimation *>(QString(), Qt::FindDirectChildrenOnly);
        QVERIFY2(std::none_of(runningAfter.cbegin(), runningAfter.cend(), [](QAbstractAnimation *animation) {
                     return animation && animation->state() == QAbstractAnimation::Running;
                 }),
                 "Flyout popup-open animation should stop when reduced motion is enabled mid-flight");
        QCOMPARE(flyout.windowOpacity(), 1.0);
        QVERIFY2(flyout.mask().isEmpty(), "Flyout reveal mask should be cleared after snap-completing popup open");

        const QImage rendered = renderWidgetImage(&flyout);
        QVERIFY2(!rendered.isNull(), "Flyout should render to an offscreen QWidget::render image after snap-completing open");
    }

    void flyoutShowForHonorsDocumentedPlacements()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();

        QScreen *screen = QApplication::primaryScreen();
        QVERIFY2(screen, "FluentFlyout placement checks require a primary screen from the Qt platform plugin");
        const QRect available = screen->availableGeometry();
        QVERIFY2(available.width() >= 360 && available.height() >= 280,
                 "FluentFlyout placement checks require enough offscreen screen space around the anchor");

        QWidget window;
        const QSize windowSize(qMin(520, available.width() - 80),
                               qMin(340, available.height() - 80));
        window.setGeometry(available.left() + (available.width() - windowSize.width()) / 2,
                           available.top() + (available.height() - windowSize.height()) / 2,
                           windowSize.width(),
                           windowSize.height());
        auto *anchor = new FluentButton(QStringLiteral("Anchor"), &window);
        anchor->setGeometry(window.width() / 2 - 42, window.height() / 2 - 16, 84, 32);
        window.show();
        QTRY_VERIFY(window.isVisible());
        QTRY_VERIFY(anchor->isVisible());

        const QRect anchorGlobal(anchor->mapToGlobal(QPoint(0, 0)), anchor->size());
        const int directionalGap = 5;
        auto verifyPlacement = [&](FluentFlyout::Placement placement, const QString &context) {
            FluentFlyout flyout(&window);
            auto *label = new FluentLabel(context, &flyout);
            label->setFixedSize(132, 34);
            flyout.setContentWidget(label);
            flyout.showFor(anchor, placement);
            QCoreApplication::processEvents();
            QTRY_VERIFY2(flyout.isVisible(), qPrintable(context + QStringLiteral(" flyout should be visible")));
            QCOMPARE(flyout.windowOpacity(), 1.0);
            QVERIFY2(flyout.mask().isEmpty(),
                     qPrintable(context + QStringLiteral(" flyout should finish popup reveal immediately with animations disabled")));

            const QRect content = PopupSurface::shadowContentRect(flyout.rect());
            QVERIFY2(content.isValid(), qPrintable(context + QStringLiteral(" flyout should expose a valid content rect")));
            const QRect contentGlobal(flyout.mapToGlobal(content.topLeft()), content.size());
            QVERIFY2(available.contains(flyout.geometry().topLeft())
                         && available.contains(flyout.geometry().bottomRight()),
                     qPrintable(context + QStringLiteral(" flyout should stay inside available screen geometry")));

            switch (placement) {
            case FluentFlyout::Placement::Bottom:
                QVERIFY2(contentGlobal.top() >= anchorGlobal.bottom() + directionalGap,
                         qPrintable(context + QStringLiteral(" flyout content should be below the anchor")));
                QVERIFY2(qAbs(contentGlobal.center().x() - anchorGlobal.center().x()) <= 6,
                         qPrintable(context + QStringLiteral(" flyout content should stay horizontally centered on the anchor")));
                break;
            case FluentFlyout::Placement::Top:
                QVERIFY2(contentGlobal.bottom() <= anchorGlobal.top() - directionalGap,
                         qPrintable(context + QStringLiteral(" flyout content should be above the anchor")));
                QVERIFY2(qAbs(contentGlobal.center().x() - anchorGlobal.center().x()) <= 6,
                         qPrintable(context + QStringLiteral(" flyout content should stay horizontally centered on the anchor")));
                break;
            case FluentFlyout::Placement::Right:
                QVERIFY2(contentGlobal.left() >= anchorGlobal.right() + directionalGap,
                         qPrintable(context + QStringLiteral(" flyout content should be right of the anchor")));
                QVERIFY2(qAbs(contentGlobal.center().y() - anchorGlobal.center().y()) <= 6,
                         qPrintable(context + QStringLiteral(" flyout content should stay vertically centered on the anchor")));
                break;
            case FluentFlyout::Placement::Left:
                QVERIFY2(contentGlobal.right() <= anchorGlobal.left() - directionalGap,
                         qPrintable(context + QStringLiteral(" flyout content should be left of the anchor")));
                QVERIFY2(qAbs(contentGlobal.center().y() - anchorGlobal.center().y()) <= 6,
                         qPrintable(context + QStringLiteral(" flyout content should stay vertically centered on the anchor")));
                break;
            }

            QVERIFY2(!renderWidgetImage(&flyout, flyout.size()).isNull(),
                     qPrintable(context + QStringLiteral(" flyout should render through QWidget::render offscreen")));
            flyout.close();
            QCoreApplication::processEvents();
        };

        verifyPlacement(FluentFlyout::Placement::Bottom, QStringLiteral("Bottom placement"));
        verifyPlacement(FluentFlyout::Placement::Top, QStringLiteral("Top placement"));
        verifyPlacement(FluentFlyout::Placement::Right, QStringLiteral("Right placement"));
        verifyPlacement(FluentFlyout::Placement::Left, QStringLiteral("Left placement"));
    }

    void popupHostsReducedMotionSnapRunningOpenAnimations()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        const FluentMotionTokens oldMotionTokens = ThemeManager::instance().motionTokens();
        struct RestoreMotion {
            bool enabled = true;
            FluentMotionTokens tokens;
            ~RestoreMotion()
            {
                ThemeManager::instance().setMotionTokens(tokens);
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled, oldMotionTokens};

        auto resetPopupOpenMotion = []() {
            ThemeManager::instance().setAnimationsEnabled(true);
            FluentMotion::setDuration(FluentMotionRole::PopupOpen, 240);
            QCoreApplication::processEvents();
            QCOMPARE(FluentMotion::duration(FluentMotionRole::PopupOpen), 240);
        };

        auto runningDirectAnimations = [](QObject *object) {
            QStringList running;
            const auto animations = object->findChildren<QAbstractAnimation *>(QString(), Qt::FindDirectChildrenOnly);
            for (QAbstractAnimation *animation : animations) {
                if (animation && animation->state() == QAbstractAnimation::Running) {
                    running << QStringLiteral("%1 duration=%2 current=%3")
                                   .arg(QString::fromLatin1(animation->metaObject()->className()))
                                   .arg(animation->duration())
                                   .arg(animation->currentTime());
                }
            }
            return running;
        };

        auto assertRunning = [&](QObject *object, const QString &name) {
            const QStringList running = runningDirectAnimations(object);
            QVERIFY2(!running.isEmpty(),
                     qPrintable(name + QStringLiteral(" should have a running popup-open animation")));
        };

        auto assertSnapped = [&](QWidget *popup, const QString &name) {
            QVERIFY2(popup, qPrintable(name + QStringLiteral(" popup should exist")));
            QCoreApplication::processEvents();
            const QStringList running = runningDirectAnimations(popup);
            QVERIFY2(running.isEmpty(),
                     qPrintable(name + QStringLiteral(" should stop popup-open animations after reduced motion: ")
                                + running.join(QStringLiteral(", "))));
            QCOMPARE(popup->windowOpacity(), 1.0);
            QVERIFY2(popup->mask().isEmpty(),
                     qPrintable(name + QStringLiteral(" should clear popup-open reveal mask after snap")));
            QVERIFY2(!renderWidgetImage(popup).isNull(),
                     qPrintable(name + QStringLiteral(" should render through QWidget::render after snap")));
        };

        QWidget host;
        host.resize(440, 260);
        auto *layout = new QVBoxLayout(&host);
        layout->setContentsMargins(36, 36, 36, 36);
        auto *combo = new FluentComboBox(&host);
        combo->addItems({QStringLiteral("Alpha"), QStringLiteral("Beta"), QStringLiteral("Gamma")});
        auto *anchor = new FluentButton(QStringLiteral("Anchor"), &host);
        layout->addWidget(combo);
        layout->addWidget(anchor);
        layout->addStretch(1);
        host.show();
        QTRY_VERIFY(host.isVisible());

        resetPopupOpenMotion();
        combo->showPopup();
        QCoreApplication::processEvents();
        QWidget *comboPopup = findVisibleTopLevelByObjectName(QStringLiteral("FluentComboPopup"));
        QVERIFY2(comboPopup, "ComboBox popup should be visible while popup-open animation is running");
        assertRunning(comboPopup, QStringLiteral("ComboBox popup"));
        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        assertSnapped(comboPopup, QStringLiteral("ComboBox popup"));
        combo->hidePopup();
        QCoreApplication::processEvents();

        resetPopupOpenMotion();
        FluentCalendarPopup calendarPopup(anchor);
        calendarPopup.popup();
        QCoreApplication::processEvents();
        QVERIFY2(calendarPopup.isVisible(), "Calendar popup should be visible while popup-open animation is running");
        assertRunning(&calendarPopup, QStringLiteral("Calendar popup"));
        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        assertSnapped(&calendarPopup, QStringLiteral("Calendar popup"));
        calendarPopup.dismiss();
        QCoreApplication::processEvents();

        resetPopupOpenMotion();
        auto *menu = new FluentMenu(&host);
        menu->addAction(QStringLiteral("Open"));
        menu->addAction(QStringLiteral("Save"));
        menu->popup(anchor->mapToGlobal(QPoint(0, anchor->height() + 6)));
        QTRY_VERIFY2(findVisibleTopLevelByObjectName(QStringLiteral("FluentMenuPopupHost")),
                     "FluentMenu popup host should be visible while popup-open animation is running");
        QWidget *menuPopup = findVisibleTopLevelByObjectName(QStringLiteral("FluentMenuPopupHost"));
        QVERIFY(menuPopup);
        assertRunning(menuPopup, QStringLiteral("FluentMenu popup host"));
        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        assertSnapped(menuPopup, QStringLiteral("FluentMenu popup host"));
        menuPopup->close();
        menu->deleteLater();
    }

    void menuReducedMotionSnapsRunningFallbackPopupAnimation()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        const FluentMotionTokens oldMotionTokens = ThemeManager::instance().motionTokens();
        struct RestoreMotion {
            bool enabled = true;
            FluentMotionTokens tokens;
            ~RestoreMotion()
            {
                ThemeManager::instance().setMotionTokens(tokens);
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled, oldMotionTokens};

        auto runningDirectAnimations = [](QObject *object) {
            QStringList running;
            const auto animations = object->findChildren<QVariantAnimation *>(QString(), Qt::FindDirectChildrenOnly);
            for (QVariantAnimation *animation : animations) {
                if (animation && animation->state() == QAbstractAnimation::Running) {
                    running << QStringLiteral("%1 duration=%2 current=%3")
                                   .arg(QString::fromLatin1(animation->metaObject()->className()))
                                   .arg(animation->duration())
                                   .arg(animation->currentTime());
                }
            }
            return running;
        };

        ThemeManager::instance().setAnimationsEnabled(true);
        FluentMotion::setDuration(FluentMotionRole::PopupOpen, 220);
        QCoreApplication::processEvents();

        FluentMenu menu;
        menu.addAction(QStringLiteral("Open"));
        menu.addAction(QStringLiteral("Save"));
        menu.addAction(QStringLiteral("Export"));
        menu.resize(menu.sizeHint());
        const QPoint finalPos(40, 40);
        menu.move(finalPos);
        menu.show();
        QTRY_VERIFY(menu.isVisible());
        QVERIFY2(!runningDirectAnimations(&menu).isEmpty(),
                 "FluentMenu fallback show path should start a popup-open animation before reduced motion is enabled");

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QCOMPARE(FluentMotion::duration(FluentMotionRole::PopupOpen), 0);

        const QStringList running = runningDirectAnimations(&menu);
        QVERIFY2(running.isEmpty(),
                 qPrintable(QStringLiteral("FluentMenu fallback popup animation should stop after reduced motion: ")
                            + running.join(QStringLiteral(", "))));
        QCOMPARE(menu.windowOpacity(), 1.0);
        QCOMPARE(menu.pos(), finalPos);
        QVERIFY2(!renderWidgetImage(&menu).isNull(),
                 "FluentMenu fallback popup should render to an offscreen QWidget::render image after snap");
        menu.close();
    }

    void buttonControlsReducedMotionResyncExistingAnimations()
    {
        struct MotionRestore {
            bool animationsEnabled = ThemeManager::instance().animationsEnabled();
            FluentMotionTokens motionTokens = ThemeManager::instance().motionTokens();

            ~MotionRestore()
            {
                ThemeManager::instance().setMotionTokens(motionTokens);
                ThemeManager::instance().setAnimationsEnabled(animationsEnabled);
                QCoreApplication::processEvents();
            }
        } restore;

        auto runningDirectAnimations = [](QObject *object) {
            QStringList running;
            const auto animations = object->findChildren<QAbstractAnimation *>(QString(), Qt::FindDirectChildrenOnly);
            for (QAbstractAnimation *animation : animations) {
                if (animation && animation->state() == QAbstractAnimation::Running) {
                    running << QStringLiteral("%1 duration=%2 current=%3")
                                   .arg(QString::fromLatin1(animation->metaObject()->className()))
                                   .arg(animation->duration())
                                   .arg(animation->currentTime());
                }
            }
            return running;
        };

        auto assertNoRunningDirectAnimation = [&](QObject *object, const QString &message) {
            const QStringList running = runningDirectAnimations(object);
            QVERIFY2(running.isEmpty(),
                     qPrintable(message + QStringLiteral(": ") + running.join(QStringLiteral(", "))));
        };

        auto sendEnter = [](QWidget *widget) {
#if QT_VERSION >= QT_VERSION_CHECK(6, 0, 0)
            QEnterEvent event(QPointF(8, 8), QPointF(8, 8), QPointF(8, 8));
#else
            QEvent event(QEvent::Enter);
#endif
            QCoreApplication::sendEvent(widget, &event);
        };

        auto sendPress = [](QWidget *widget) {
            const QPointF point(widget->rect().center());
            QMouseEvent event(QEvent::MouseButtonPress, point, Qt::LeftButton, Qt::LeftButton, Qt::NoModifier);
            QCoreApplication::sendEvent(widget, &event);
        };

        auto assertInteractiveSnap = [&](QWidget *widget, const QString &name) {
            QVERIFY2(widget, qPrintable(name + QStringLiteral(" widget should exist")));
            QTRY_VERIFY(runningDirectAnimations(widget).isEmpty());

            sendEnter(widget);
            QCOMPARE(widget->property("hoverLevel").toReal(), 1.0);
            assertNoRunningDirectAnimation(widget, name + QStringLiteral(" hover should snap with reduced motion"));

            sendPress(widget);
            QCOMPARE(widget->property("pressLevel").toReal(), 1.0);
            assertNoRunningDirectAnimation(widget, name + QStringLiteral(" press should snap with reduced motion"));
        };

        auto assertInteractiveMidFlightSnap = [&](QWidget *widget, const QString &name) {
            QVERIFY2(widget, qPrintable(name + QStringLiteral(" widget should exist")));

            ThemeManager::instance().setAnimationsEnabled(true);
            QCoreApplication::processEvents();
            QTRY_VERIFY(runningDirectAnimations(widget).isEmpty());

            sendEnter(widget);
            QCoreApplication::processEvents();
            QVERIFY2(!runningDirectAnimations(widget).isEmpty(),
                     qPrintable(name + QStringLiteral(" hover should be running before reduced motion is enabled")));
            ThemeManager::instance().setAnimationsEnabled(false);
            QCoreApplication::processEvents();
            QCOMPARE(widget->property("hoverLevel").toReal(), 1.0);
            assertNoRunningDirectAnimation(widget,
                                           name + QStringLiteral(" hover should snap when reduced motion is enabled mid-flight"));

            ThemeManager::instance().setAnimationsEnabled(true);
            QCoreApplication::processEvents();
            QTRY_VERIFY(runningDirectAnimations(widget).isEmpty());

            sendPress(widget);
            QCoreApplication::processEvents();
            QVERIFY2(!runningDirectAnimations(widget).isEmpty(),
                     qPrintable(name + QStringLiteral(" press should be running before reduced motion is enabled")));
            ThemeManager::instance().setAnimationsEnabled(false);
            QCoreApplication::processEvents();
            QCOMPARE(widget->property("pressLevel").toReal(), 1.0);
            assertNoRunningDirectAnimation(widget,
                                           name + QStringLiteral(" press should snap when reduced motion is enabled mid-flight"));
        };

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeManager::instance().setAnimationsEnabled(true);
        FluentMotion::setDuration(FluentMotionRole::Selection, 180);
        FluentMotion::setDuration(FluentMotionRole::Hover, 180);
        FluentMotion::setDuration(FluentMotionRole::Press, 180);
        QCoreApplication::processEvents();

        QWidget host;
        auto *layout = new QVBoxLayout(&host);
        auto *button = new FluentButton(QStringLiteral("Button"), &host);
        auto *toolButton = new FluentToolButton(QStringLiteral("Tool"), &host);
        auto *animated = new FluentAnimatedButton(QStringLiteral("Animated"), &host);
        auto *dropDown = new FluentDropDownButton(QStringLiteral("Drop"), &host);
        auto *split = new FluentSplitButton(QStringLiteral("Split"), &host);
        layout->addWidget(button);
        layout->addWidget(toolButton);
        layout->addWidget(animated);
        layout->addWidget(dropDown);
        layout->addWidget(split);
        host.resize(320, 240);
        host.show();
        QTRY_VERIFY(host.isVisible());

        assertInteractiveMidFlightSnap(button, QStringLiteral("FluentButton"));
        assertInteractiveMidFlightSnap(toolButton, QStringLiteral("FluentToolButton"));
        assertInteractiveMidFlightSnap(animated, QStringLiteral("FluentAnimatedButton"));
        assertInteractiveMidFlightSnap(dropDown, QStringLiteral("FluentDropDownButton"));
        assertInteractiveMidFlightSnap(split->mainButton(), QStringLiteral("FluentSplitButton main segment"));
        assertInteractiveMidFlightSnap(split->dropDownButton(), QStringLiteral("FluentSplitButton dropdown segment"));

        ThemeManager::instance().setAnimationsEnabled(false);

        assertInteractiveSnap(button, QStringLiteral("FluentButton"));
        assertInteractiveSnap(toolButton, QStringLiteral("FluentToolButton"));
        assertInteractiveSnap(animated, QStringLiteral("FluentAnimatedButton"));
        assertInteractiveSnap(dropDown, QStringLiteral("FluentDropDownButton"));
        assertInteractiveSnap(split->mainButton(), QStringLiteral("FluentSplitButton main segment"));
        assertInteractiveSnap(split->dropDownButton(), QStringLiteral("FluentSplitButton dropdown segment"));

        const QImage rendered = renderWidgetImage(&host);
        QVERIFY2(!rendered.isNull(), "Button controls should render to an offscreen QWidget::render image");
        QCOMPARE(rendered.size(), host.size());
    }

    void lottieHonorsReducedMotion()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        FluentLottieWidget loopingWidget;
        QVERIFY2(loopingWidget.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-looping")),
                 "Visual smoke Lottie fixture should parse for looping playback");
        loopingWidget.setLooping(true);
        loopingWidget.setSpeed(0.01);
        loopingWidget.setCurrentFrame(17);
        loopingWidget.play();
        QVERIFY2(loopingWidget.isPlaying(), "Plain Lottie playback should start while global animations are enabled");
        const int loopingFrameBeforeReducedMotion = loopingWidget.currentFrame();

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QTRY_VERIFY2(!loopingWidget.isPlaying(), "Plain Lottie playback should pause when reduced motion is enabled");
        QCOMPARE(loopingWidget.currentFrame(), loopingFrameBeforeReducedMotion);

        FluentLottieWidget disabledPlayWidget;
        QVERIFY2(disabledPlayWidget.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-disabled-play")),
                 "Visual smoke Lottie fixture should parse for reduced-motion play()");
        disabledPlayWidget.setCurrentFrame(7);
        disabledPlayWidget.play();
        QCOMPARE(disabledPlayWidget.currentFrame(), 7);
        QVERIFY2(!disabledPlayWidget.isPlaying(), "Lottie play() should not start a timer while reduced motion is enabled");

        FluentLottieWidget segmentWidget;
        QVERIFY2(segmentWidget.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-segment")),
                 "Visual smoke Lottie fixture should parse for segment playback");
        QSignalSpy finishedSpy(&segmentWidget, &FluentLottieWidget::finished);
        segmentWidget.playSegment(0, 10);
        QCOMPARE(segmentWidget.currentFrame(), 10);
        QVERIFY2(!segmentWidget.isPlaying(), "Lottie segment playback should not start a timer while reduced motion is enabled");
        QCOMPARE(finishedSpy.count(), 1);

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        FluentLottieWidget activeSegmentWidget;
        QVERIFY2(activeSegmentWidget.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-active-segment")),
                 "Visual smoke Lottie fixture should parse for mid-flight segment playback");
        activeSegmentWidget.setSpeed(0.01);
        QSignalSpy activeSegmentFinishedSpy(&activeSegmentWidget, &FluentLottieWidget::finished);
        activeSegmentWidget.playSegment(3, 27);
        QCOMPARE(activeSegmentWidget.currentFrame(), 3);
        QVERIFY2(activeSegmentWidget.isPlaying(), "Lottie segment playback should start while global animations are enabled");

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QTRY_VERIFY2(!activeSegmentWidget.isPlaying(),
                     "Running Lottie segment playback should stop when reduced motion is enabled");
        QCOMPARE(activeSegmentWidget.currentFrame(), 27);
        QTRY_COMPARE(activeSegmentFinishedSpy.count(), 1);
        QVERIFY2(!renderWidgetImage(&activeSegmentWidget, QSize(48, 48)).isNull(),
                 "Reduced-motion Lottie segment should render to an offscreen QWidget::render image");

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        FluentAnimatedIcon animatedIcon;
        QVERIFY2(animatedIcon.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-active")),
                 "Visual smoke Lottie fixture should parse");
        QCOMPARE(animatedIcon.markerFrame(QStringLiteral("NormalToPointerOver_End")), 24);
        animatedIcon.setState(QStringLiteral("PointerOver"), true);
        QVERIFY2(animatedIcon.isPlaying(), "AnimatedIcon transition should play while global animations are enabled");

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QTRY_VERIFY2(!animatedIcon.isPlaying(), "AnimatedIcon should stop when reduced motion is enabled");
        QCOMPARE(animatedIcon.currentFrame(), animatedIcon.markerFrame(QStringLiteral("NormalToPointerOver_End")));

        FluentAnimatedIcon reducedIcon;
        QVERIFY2(reducedIcon.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-reduced")),
                 "Visual smoke Lottie fixture should parse for reduced-motion transition");
        reducedIcon.setState(QStringLiteral("PointerOver"), true);
        QCOMPARE(reducedIcon.currentFrame(), reducedIcon.markerFrame(QStringLiteral("NormalToPointerOver_End")));
        QVERIFY2(!reducedIcon.isPlaying(), "AnimatedIcon should jump to the resolved end frame when reduced motion is already enabled");

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        FluentAnimatedButton animatedButton(QStringLiteral("Search"));
        QVERIFY2(animatedButton.loadAnimationData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-button-active")),
                 "Visual smoke Lottie fixture should parse for AnimatedButton");
        animatedButton.setAnimationState(QStringLiteral("PointerOver"), true);
        QVERIFY2(animatedButton.animatedIcon()->isPlaying(),
                 "AnimatedButton internal icon transition should play while global animations are enabled");

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QTRY_VERIFY2(!animatedButton.animatedIcon()->isPlaying(),
                     "AnimatedButton internal icon transition should stop when reduced motion is enabled");
        QCOMPARE(animatedButton.animatedIcon()->currentFrame(),
                 animatedButton.animatedIcon()->markerFrame(QStringLiteral("NormalToPointerOver_End")));
        QVERIFY2(!renderWidgetImage(&animatedButton).isNull(),
                 "Reduced-motion AnimatedButton should render to an offscreen QWidget::render image");

        FluentAnimatedButton reducedButton(QStringLiteral("Search"));
        QVERIFY2(reducedButton.loadAnimationData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-button-reduced")),
                 "Visual smoke Lottie fixture should parse for reduced-motion AnimatedButton");
        reducedButton.setAnimationState(QStringLiteral("PointerOver"), true);
        QCOMPARE(reducedButton.animatedIcon()->currentFrame(),
                 reducedButton.animatedIcon()->markerFrame(QStringLiteral("NormalToPointerOver_End")));
        QVERIFY2(!reducedButton.animatedIcon()->isPlaying(),
                 "AnimatedButton internal icon should jump to the resolved end frame when reduced motion is already enabled");

        FluentAnimatedButton stateButton(QStringLiteral("Search"));
        QVERIFY2(stateButton.loadAnimationData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-button-state")),
                 "Visual smoke Lottie fixture should parse for AnimatedButton state markers");
        stateButton.setCheckable(true);
        stateButton.setChecked(true);
        QCOMPARE(stateButton.animationState(), QStringLiteral("Selected"));
        QCOMPARE(stateButton.animatedIcon()->currentFrame(),
                 stateButton.animatedIcon()->markerFrame(QStringLiteral("NormalToSelected_End")));
        QVERIFY2(!stateButton.animatedIcon()->isPlaying(),
                 "Checked AnimatedButton should land on the Selected marker when reduced motion is enabled");

        stateButton.setEnabled(false);
        QCOMPARE(stateButton.animationState(), QStringLiteral("Disabled"));
        QCOMPARE(stateButton.animatedIcon()->currentFrame(),
                 stateButton.animatedIcon()->markerFrame(QStringLiteral("Disabled")));
        QVERIFY2(!stateButton.animatedIcon()->isPlaying(),
                 "Disabled AnimatedButton should land on the Disabled marker when reduced motion is enabled");

        stateButton.setEnabled(true);
        QCOMPARE(stateButton.animationState(), QStringLiteral("Selected"));
        QCOMPARE(stateButton.animatedIcon()->currentFrame(),
                 stateButton.animatedIcon()->markerFrame(QStringLiteral("Selected")));
    }

    void lottiePlaybackStopsWhileHidden()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        FluentLottieWidget widget;
        QVERIFY2(widget.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-hidden-playback")),
                 "Visual smoke Lottie fixture should parse for hidden playback suspension");
        widget.setLooping(true);
        widget.setSpeed(8.0);
        widget.resize(48, 48);
        widget.show();
        QTRY_VERIFY(widget.isVisible());

        widget.play();
        QVERIFY2(widget.isPlaying(), "Lottie playback intent should remain true while the widget is visible");
        const int initialFrame = widget.currentFrame();
        QTRY_VERIFY2(widget.currentFrame() != initialFrame,
                     "Visible Lottie playback should advance before hidden playback stop is tested");

        widget.hide();
        QCoreApplication::processEvents();
        const int hiddenFrame = widget.currentFrame();
        QTest::qWait(80);
        QCoreApplication::processEvents();
        QCOMPARE(widget.currentFrame(), hiddenFrame);
        QVERIFY2(widget.isPlaying(), "Hiding a Lottie widget should keep the playback request for automatic resume");

        widget.show();
        QTRY_VERIFY(widget.isVisible());
        QTRY_VERIFY2(widget.currentFrame() != hiddenFrame,
                     "Showing a hidden Lottie widget with an active play request should resume playback");
        widget.pause();
    }

    void lottiePlaybackStopsWhenClippedByParent()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        QWidget parent;
        parent.resize(64, 64);

        FluentLottieWidget widget(&parent);
        QVERIFY2(widget.loadData(visualSmokeLottieJson(), QStringLiteral("visual-smoke-lottie-clipped-playback")),
                 "Visual smoke Lottie fixture should parse for clipped playback suspension");
        widget.setLooping(true);
        widget.setSpeed(8.0);
        widget.resize(48, 48);
        widget.move(8, 8);

        parent.show();
        QTRY_VERIFY(parent.isVisible());
        widget.show();
        QTRY_VERIFY(widget.isVisible());

        widget.play();
        QVERIFY2(widget.isPlaying(), "Visible Lottie playback should start before clipping is tested");
        const int visibleFrame = widget.currentFrame();
        QTRY_VERIFY2(widget.currentFrame() != visibleFrame,
                     "Visible Lottie playback should advance before parent clipping is tested");

        widget.move(80, 8);
        QCoreApplication::processEvents();
        const int clippedFrame = widget.currentFrame();
        QTest::qWait(160);
        QCoreApplication::processEvents();
        QCOMPARE(widget.currentFrame(), clippedFrame);
        QVERIFY2(widget.isPlaying(), "Clipped Lottie should keep the playback request while its timer is suspended");

        widget.move(8, 8);
        QCoreApplication::processEvents();
        QTRY_VERIFY2(widget.currentFrame() != clippedFrame,
                     "Clipped Lottie playback should resume when the widget becomes visible again");
        widget.pause();
    }

