        tableModel.setData(tableModel.index(1, 0), QStringLiteral("Beta"));
        tableModel.setData(tableModel.index(2, 0), QStringLiteral("Gamma"));
        FluentTableView table;
        table.setModel(&tableModel);
        exerciseSelection(&table,
                          tableModel.index(0, 0),
                          tableModel.index(2, 0),
                          QStringLiteral("FluentTableView"));

        FluentTableWidget tableWidget(3, 2);
        tableWidget.setItem(0, 0, new QTableWidgetItem(QStringLiteral("Alpha")));
        tableWidget.setItem(1, 0, new QTableWidgetItem(QStringLiteral("Beta")));
        tableWidget.setItem(2, 0, new QTableWidgetItem(QStringLiteral("Gamma")));
        exerciseSelection(&tableWidget,
                          tableWidget.model()->index(0, 0),
                          tableWidget.model()->index(2, 0),
                          QStringLiteral("FluentTableWidget"));

        QStandardItemModel treeModel(3, 2);
        treeModel.setData(treeModel.index(0, 0), QStringLiteral("Alpha"));
        treeModel.setData(treeModel.index(1, 0), QStringLiteral("Beta"));
        treeModel.setData(treeModel.index(2, 0), QStringLiteral("Gamma"));
        FluentTreeView tree;
        tree.setModel(&treeModel);
        exerciseSelection(&tree,
                          treeModel.index(0, 0),
                          treeModel.index(2, 0),
                          QStringLiteral("FluentTreeView"));
