    void dataAndPopupViewsReducedMotionResyncExistingAnimations()
    {
        struct MotionRestore {
            bool animationsEnabled = ThemeManager::instance().animationsEnabled();
            FluentMotionTokens motionTokens = ThemeManager::instance().motionTokens();

            ~MotionRestore()
            {
                ThemeManager::instance().setMotionTokens(motionTokens);
                ThemeManager::instance().setAnimationsEnabled(animationsEnabled);
                QCoreApplication::processEvents();
            }
        } restore;

        auto runningDirectAnimations = [](QObject *object) {
            QStringList running;
            const auto animations = object->findChildren<QAbstractAnimation *>(QString(), Qt::FindDirectChildrenOnly);
            for (QAbstractAnimation *animation : animations) {
                if (animation && animation->state() == QAbstractAnimation::Running) {
                    running << QStringLiteral("%1 duration=%2 current=%3")
                                   .arg(QString::fromLatin1(animation->metaObject()->className()))
                                   .arg(animation->duration())
                                   .arg(animation->currentTime());
                }
            }
            return running;
        };

        auto assertNoRunningDirectAnimation = [&](QObject *object, const QString &message) {
            const QStringList running = runningDirectAnimations(object);
            QVERIFY2(running.isEmpty(),
                     qPrintable(message + QStringLiteral(": ") + running.join(QStringLiteral(", "))));
        };

        auto sendViewportMouseMove = [](QAbstractItemView *view, const QPoint &pos) {
            QMouseEvent event(QEvent::MouseMove, QPointF(pos), Qt::NoButton, Qt::NoButton, Qt::NoModifier);
            QCoreApplication::sendEvent(view->viewport(), &event);
        };

        auto sendEnter = [](QWidget *widget) {
#if QT_VERSION >= QT_VERSION_CHECK(6, 0, 0)
            QEnterEvent event(QPointF(8, 8), QPointF(8, 8), QPointF(8, 8));
#else
            QEvent event(QEvent::Enter);
#endif
            QCoreApplication::sendEvent(widget, &event);
        };

        auto setAnimatedMotion = []() {
            ThemeManager::instance().setAnimationsEnabled(true);
            FluentMotion::setDuration(FluentMotionRole::Hover, 180);
            FluentMotion::setDuration(FluentMotionRole::Selection, 180);
            FluentMotion::setDuration(FluentMotionRole::PopupOpen, 180);
            QCoreApplication::processEvents();
        };

        auto setReducedMotion = []() {
            ThemeManager::instance().setAnimationsEnabled(false);
            QCoreApplication::processEvents();
        };

        auto exerciseDataViewMidFlight = [&](auto *view,
                                             const QModelIndex &first,
                                             const QModelIndex &second,
                                             const QString &name) {
            QVERIFY2(view, qPrintable(name + QStringLiteral(" should exist")));
            view->resize(260, 140);
            view->show();
            QTRY_VERIFY(view->isVisible());
            QTRY_VERIFY(first.isValid());
            QTRY_VERIFY(second.isValid());
            QTRY_VERIFY(view->visualRect(first).isValid());
            QTRY_VERIFY(view->visualRect(second).isValid());
            QVERIFY(view->selectionModel());

            setReducedMotion();
            view->selectionModel()->setCurrentIndex(first, QItemSelectionModel::ClearAndSelect | QItemSelectionModel::Rows);
            QCoreApplication::processEvents();
            assertNoRunningDirectAnimation(view, name + QStringLiteral(" initial selection should settle before mid-flight check"));

            setAnimatedMotion();
            view->selectionModel()->setCurrentIndex(second, QItemSelectionModel::ClearAndSelect | QItemSelectionModel::Rows);
            QCoreApplication::processEvents();
            QVERIFY2(!runningDirectAnimations(view).isEmpty(),
                     qPrintable(name + QStringLiteral(" selection should be running before reduced motion is enabled")));
            setReducedMotion();
            assertNoRunningDirectAnimation(view,
                                           name + QStringLiteral(" selection should snap when reduced motion is enabled mid-flight"));
            QCOMPARE(view->currentIndex(), second);

            setAnimatedMotion();
            sendViewportMouseMove(view, view->visualRect(second).center());
            QCoreApplication::processEvents();
            QVERIFY2(!runningDirectAnimations(view).isEmpty(),
                     qPrintable(name + QStringLiteral(" hover should be running before reduced motion is enabled")));
            setReducedMotion();
            assertNoRunningDirectAnimation(view,
                                           name + QStringLiteral(" hover should snap when reduced motion is enabled mid-flight"));
        };

        auto exerciseDataView = [&](auto *view,
                                    const QModelIndex &first,
                                    const QModelIndex &second,
                                    const QString &name) {
            QVERIFY2(view, qPrintable(name + QStringLiteral(" should exist")));
            view->resize(260, 140);
            view->show();
            QTRY_VERIFY(view->isVisible());
            QTRY_VERIFY(first.isValid());
            QTRY_VERIFY(second.isValid());
            QTRY_VERIFY(view->visualRect(first).isValid());
            QTRY_VERIFY(view->visualRect(second).isValid());
            QTRY_VERIFY(runningDirectAnimations(view).isEmpty());
            QVERIFY(view->selectionModel());

            view->selectionModel()->setCurrentIndex(first, QItemSelectionModel::ClearAndSelect | QItemSelectionModel::Rows);
            view->selectionModel()->setCurrentIndex(second, QItemSelectionModel::ClearAndSelect | QItemSelectionModel::Rows);
            assertNoRunningDirectAnimation(view, name + QStringLiteral(" selection should snap when animations are disabled after construction"));

            sendViewportMouseMove(view, view->visualRect(second).center());
            QCoreApplication::processEvents();
            QCOMPARE(view->hoverLevel(), 1.0);
            assertNoRunningDirectAnimation(view, name + QStringLiteral(" hover should snap when animations are disabled after construction"));

            const QImage image = renderWidgetImage(view->viewport());
            QVERIFY2(!image.isNull(), qPrintable(name + QStringLiteral(" should render to an offscreen QWidget::render image")));
        };

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();

        QStringListModel listModel({QStringLiteral("Alpha"), QStringLiteral("Beta"), QStringLiteral("Gamma")});
        FluentListView list;
        list.setModel(&listModel);

        QStandardItemModel tableModel(3, 2);
        tableModel.setData(tableModel.index(0, 0), QStringLiteral("Alpha"));
        tableModel.setData(tableModel.index(1, 0), QStringLiteral("Beta"));
        tableModel.setData(tableModel.index(2, 0), QStringLiteral("Gamma"));
        FluentTableView table;
        table.setModel(&tableModel);

        FluentTableWidget tableWidget(3, 2);
        tableWidget.setItem(0, 0, new QTableWidgetItem(QStringLiteral("Alpha")));
        tableWidget.setItem(1, 0, new QTableWidgetItem(QStringLiteral("Beta")));
        tableWidget.setItem(2, 0, new QTableWidgetItem(QStringLiteral("Gamma")));

        QStandardItemModel treeModel(3, 2);
        treeModel.setData(treeModel.index(0, 0), QStringLiteral("Alpha"));
        treeModel.setData(treeModel.index(1, 0), QStringLiteral("Beta"));
        treeModel.setData(treeModel.index(2, 0), QStringLiteral("Gamma"));
        FluentTreeView tree;
        tree.setModel(&treeModel);

        QWidget host;
        auto *layout = new QVBoxLayout(&host);
        auto *combo = new FluentComboBox(&host);
        combo->addItems({QStringLiteral("Alpha"), QStringLiteral("Beta"), QStringLiteral("Gamma")});
        auto *suggest = new FluentAutoSuggestBox(&host);
        suggest->setSuggestions({QStringLiteral("Fluent layout"),
                                 QStringLiteral("Fluent motion"),
                                 QStringLiteral("Fluent tokens")});
        layout->addWidget(combo);
        layout->addWidget(suggest);
        host.resize(280, 96);
        host.show();
        QTRY_VERIFY(host.isVisible());

        exerciseDataViewMidFlight(&list, listModel.index(0, 0), listModel.index(2, 0), QStringLiteral("FluentListView"));
        exerciseDataViewMidFlight(&table, tableModel.index(0, 0), tableModel.index(2, 0), QStringLiteral("FluentTableView"));
        exerciseDataViewMidFlight(&tableWidget,
                                  tableWidget.model()->index(0, 0),
                                  tableWidget.model()->index(2, 0),
                                  QStringLiteral("FluentTableWidget"));
        exerciseDataViewMidFlight(&tree, treeModel.index(0, 0), treeModel.index(2, 0), QStringLiteral("FluentTreeView"));

        setAnimatedMotion();
        sendEnter(combo);
        QCoreApplication::processEvents();
        QVERIFY2(!runningDirectAnimations(combo).isEmpty(),
                 "FluentComboBox hover should be running before reduced motion is enabled");
        setReducedMotion();
        QCOMPARE(combo->hoverLevel(), 1.0);
        assertNoRunningDirectAnimation(combo,
                                       QStringLiteral("FluentComboBox hover should snap when reduced motion is enabled mid-flight"));

        setAnimatedMotion();
        combo->showPopup();
        QTRY_VERIFY(findComboPopupView());
        QListView *comboMidFlightView = findComboPopupView();
        QVERIFY(comboMidFlightView);
        const QModelIndex comboMidFirst = comboMidFlightView->model()->index(0, 0);
        const QModelIndex comboMidSecond = comboMidFlightView->model()->index(2, 0);
        QTRY_VERIFY(comboMidFlightView->visualRect(comboMidFirst).isValid());
        QTRY_VERIFY(comboMidFlightView->visualRect(comboMidSecond).isValid());
        QVERIFY(comboMidFlightView->selectionModel());

        setReducedMotion();
        comboMidFlightView->selectionModel()->setCurrentIndex(comboMidFirst, QItemSelectionModel::ClearAndSelect);
        QCoreApplication::processEvents();
        assertNoRunningDirectAnimation(comboMidFlightView,
                                       QStringLiteral("ComboBox popup initial selection should settle before mid-flight check"));

        setAnimatedMotion();
        comboMidFlightView->selectionModel()->setCurrentIndex(comboMidSecond, QItemSelectionModel::ClearAndSelect);
        QCoreApplication::processEvents();
        QVERIFY2(!runningDirectAnimations(comboMidFlightView).isEmpty(),
                 "ComboBox popup selection should be running before reduced motion is enabled");
        setReducedMotion();
        assertNoRunningDirectAnimation(comboMidFlightView,
                                       QStringLiteral("ComboBox popup selection should snap when reduced motion is enabled mid-flight"));

        setAnimatedMotion();
        sendViewportMouseMove(comboMidFlightView, comboMidFlightView->visualRect(comboMidSecond).center());
        QCoreApplication::processEvents();
        QVERIFY2(!runningDirectAnimations(comboMidFlightView).isEmpty(),
                 "ComboBox popup hover should be running before reduced motion is enabled");
        setReducedMotion();
        assertNoRunningDirectAnimation(comboMidFlightView,
                                       QStringLiteral("ComboBox popup hover should snap when reduced motion is enabled mid-flight"));
        combo->hidePopup();
        QCoreApplication::processEvents();

        setAnimatedMotion();
        QListView *suggestMidFlightView = openAutoSuggestPopup(suggest, QStringLiteral("Fluent"));
        QVERIFY2(suggestMidFlightView, "AutoSuggest popup view should open for the mid-flight reduced-motion check");
        const QModelIndex suggestMidIndex = suggestMidFlightView->model()->index(0, 0);
        QTRY_VERIFY(suggestMidFlightView->visualRect(suggestMidIndex).isValid());
        sendViewportMouseMove(suggestMidFlightView, suggestMidFlightView->visualRect(suggestMidIndex).center());
        QCoreApplication::processEvents();
        QVERIFY2(!runningDirectAnimations(suggestMidFlightView).isEmpty(),
                 "AutoSuggest popup hover should be running before reduced motion is enabled");
        setReducedMotion();
        assertNoRunningDirectAnimation(suggestMidFlightView,
                                       QStringLiteral("AutoSuggest popup hover should snap when reduced motion is enabled mid-flight"));
        if (QWidget *popup = findVisibleTopLevelByObjectName(QStringLiteral("FluentAutoSuggestPopup"))) {
            popup->close();
        }
        suggest->setText(QString());
        suggest->lineEdit()->clearFocus();
        QCoreApplication::processEvents();

        setReducedMotion();

        exerciseDataView(&list, listModel.index(0, 0), listModel.index(2, 0), QStringLiteral("FluentListView"));
        exerciseDataView(&table, tableModel.index(0, 0), tableModel.index(2, 0), QStringLiteral("FluentTableView"));
        exerciseDataView(&tableWidget,
                         tableWidget.model()->index(0, 0),
                         tableWidget.model()->index(2, 0),
                         QStringLiteral("FluentTableWidget"));
        exerciseDataView(&tree, treeModel.index(0, 0), treeModel.index(2, 0), QStringLiteral("FluentTreeView"));

        combo->showPopup();
        QTRY_VERIFY(findComboPopupView());
        QListView *comboView = findComboPopupView();
        QVERIFY(comboView);
        const QModelIndex comboFirst = comboView->model()->index(0, 0);
        const QModelIndex comboSecond = comboView->model()->index(2, 0);
        QTRY_VERIFY(comboView->visualRect(comboFirst).isValid());
        QTRY_VERIFY(comboView->visualRect(comboSecond).isValid());
        QTRY_VERIFY(runningDirectAnimations(comboView).isEmpty());
        QVERIFY(comboView->selectionModel());
        comboView->selectionModel()->setCurrentIndex(comboFirst, QItemSelectionModel::ClearAndSelect);
        comboView->selectionModel()->setCurrentIndex(comboSecond, QItemSelectionModel::ClearAndSelect);
        assertNoRunningDirectAnimation(comboView, QStringLiteral("ComboBox popup selection should snap when animations are disabled after construction"));
        sendViewportMouseMove(comboView, comboView->visualRect(comboSecond).center());
        QCoreApplication::processEvents();
        assertNoRunningDirectAnimation(comboView, QStringLiteral("ComboBox popup hover should snap when animations are disabled after construction"));
        QVERIFY2(!renderWidgetImage(comboView->viewport()).isNull(),
                 "ComboBox popup view should render to an offscreen QWidget::render image");
        combo->hidePopup();
        QCoreApplication::processEvents();

        QListView *suggestView = openAutoSuggestPopup(suggest, QStringLiteral("Fluent"));
        QVERIFY2(suggestView, "AutoSuggest popup view should open in offscreen mode");
        const QModelIndex suggestIndex = suggestView->model()->index(0, 0);
        QTRY_VERIFY(suggestView->visualRect(suggestIndex).isValid());
        QTRY_VERIFY(runningDirectAnimations(suggestView).isEmpty());
        sendViewportMouseMove(suggestView, suggestView->visualRect(suggestIndex).center());
        QCoreApplication::processEvents();
        assertNoRunningDirectAnimation(suggestView, QStringLiteral("AutoSuggest popup hover should snap when animations are disabled after construction"));
        QVERIFY2(!renderWidgetImage(suggestView->viewport()).isNull(),
                 "AutoSuggest popup view should render to an offscreen QWidget::render image");

        if (QWidget *popup = findVisibleTopLevelByObjectName(QStringLiteral("FluentAutoSuggestPopup"))) {
            popup->close();
        }
    }

    void dataViewFallbackStylesUseThemeTokens()
    {
        ThemeColors colors = Theme::light();
        colors.accent = QColor(QStringLiteral("#43FF43"));
        colors.focus = QColor(QStringLiteral("#FF00FF"));
        colors.surface = QColor(QStringLiteral("#F7FBFF"));
        colors.border = QColor(QStringLiteral("#8A99AA"));
        const FluentThemeTokens tokens = Theme::tokens(colors);
        const QColor disabledFill =
            Style::mix(tokens.neutral.card, tokens.neutral.fillSecondary, tokens.dark ? 0.30 : 0.46);
        const QColor disabledStroke =
            Style::mix(tokens.neutral.strokeSubtle, colors.disabledText, tokens.dark ? 0.18 : 0.12);

        auto assertTokenStyle = [&](const QString &name, const QString &style, const QStringList &expected) {
            QVERIFY2(!style.contains(QStringLiteral("palette(")),
                     qPrintable(name + QStringLiteral(" should use resolved theme tokens instead of palette() indirection")));
            QVERIFY2(!style.contains(colors.focus.name(QColor::HexArgb)),
                     qPrintable(name + QStringLiteral(" should use accent.base rather than the legacy focus color")));
            for (const QString &value : expected) {
                QVERIFY2(style.contains(value),
                         qPrintable(name + QStringLiteral(" did not contain expected token color ") + value));
            }
        };

        const QString listStyle = Theme::listViewStyle(colors);
        const QString tableStyle = Theme::tableViewStyle(colors);
        const QString treeStyle = Theme::treeViewStyle(colors);

        assertTokenStyle(QStringLiteral("Theme::listViewStyle"),
                         listStyle,
                         {tokens.neutral.card.name(QColor::HexArgb),
                          tokens.neutral.strokeSubtle.name(QColor::HexArgb),
                          tokens.accent.base.name(QColor::HexArgb),
                          disabledFill.name(QColor::HexArgb),
                          colors.disabledText.name(QColor::HexArgb),
                          disabledStroke.name(QColor::HexArgb)});
        assertTokenStyle(QStringLiteral("Theme::tableViewStyle"),
                         tableStyle,
                         {tokens.neutral.card.name(QColor::HexArgb),
                          tokens.neutral.layer.name(QColor::HexArgb),
                          tokens.neutral.strokeSubtle.name(QColor::HexArgb),
                          tokens.accent.base.name(QColor::HexArgb),
                          disabledFill.name(QColor::HexArgb),
                          colors.disabledText.name(QColor::HexArgb),
                          disabledStroke.name(QColor::HexArgb)});
        assertTokenStyle(QStringLiteral("Theme::treeViewStyle"),
                         treeStyle,
                         {tokens.neutral.card.name(QColor::HexArgb),
                          tokens.neutral.layer.name(QColor::HexArgb),
                          tokens.neutral.strokeSubtle.name(QColor::HexArgb),
                          tokens.accent.base.name(QColor::HexArgb),
                          disabledFill.name(QColor::HexArgb),
                          colors.disabledText.name(QColor::HexArgb),
                          disabledStroke.name(QColor::HexArgb)});
    }

    void codeEditorChromeUsesThemeTokens()
    {
        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };
        auto codeEditorSurfaceFill = [](const FluentThemeTokens &tokens, bool enabled, qreal hoverLevel) {
            if (!enabled) {
                return Style::mix(tokens.neutral.card, tokens.neutral.background, tokens.dark ? 0.48 : 0.35);
            }
            return Style::mix(tokens.neutral.card,
                              Style::controlHoverFill(tokens),
                              qBound<qreal>(0.0, hoverLevel, 1.0));
        };
        auto codeEditorGutterFill = [](const FluentThemeTokens &tokens) {
            return Style::mix(tokens.neutral.card, tokens.neutral.cardHover, tokens.dark ? 0.82 : 0.74);
        };

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        const ThemeColors colors = ThemeManager::instance().colors();

        FluentCodeEditor surfaceEditor;
        surfaceEditor.setLineNumbersEnabled(false);
        surfaceEditor.setCurrentLineHighlightEnabled(false);
        surfaceEditor.setBracketMatchHighlightEnabled(false);
        surfaceEditor.setPlainText(QStringLiteral("\n\n\n"));
        surfaceEditor.resize(260, 118);
        surfaceEditor.show();
        QTRY_VERIFY(surfaceEditor.isVisible());
        surfaceEditor.setHoverLevel(1.0);
        QCoreApplication::processEvents();

        QImage surfaceImage(surfaceEditor.size(), QImage::Format_ARGB32);
        surfaceImage.fill(colors.background.rgba());
        {
            QPainter painter(&surfaceImage);
            surfaceEditor.render(&painter);
        }

        const QRect viewportRect = surfaceEditor.viewport()->geometry();
        const QRect surfaceSample(viewportRect.left() + 36,
                                  viewportRect.top() + 28,
                                  qMax(8, viewportRect.width() - 72),
                                  18);
        const QColor surfaceFill = dominantColor(surfaceImage, surfaceSample);
        const QColor expectedSurface = codeEditorSurfaceFill(tokens, true, 1.0);
        QVERIFY2(colorDelta(surfaceFill, expectedSurface) < 42,
                 qPrintable(QStringLiteral("CodeEditor viewport surface should use the control hover token, got %1 expected near %2")
                                .arg(surfaceFill.name(), expectedSurface.name())));
        QVERIFY2(nearColorPixelCount(surfaceImage,
                                     tokens.neutral.strokeSubtle,
                                     QRect(10, 0, surfaceEditor.width() - 20, 3),
                                     56) > 8,
                 "CodeEditor border overlay should use the neutral strokeSubtle token");

        FluentCodeEditor gutterEditor;
        gutterEditor.setPlainText(QStringLiteral("int main() {\n    return 0;\n}\n"));
        gutterEditor.setCurrentLineHighlightEnabled(false);
        QTextCursor endCursor = gutterEditor.textCursor();
        endCursor.movePosition(QTextCursor::End);
        gutterEditor.setTextCursor(endCursor);
        gutterEditor.resize(280, 140);
        gutterEditor.show();
        QTRY_VERIFY(gutterEditor.isVisible());
        QCoreApplication::processEvents();

        QImage gutterImage(gutterEditor.size(), QImage::Format_ARGB32);
        gutterImage.fill(colors.background.rgba());
        {
            QPainter painter(&gutterImage);
            gutterEditor.render(&painter);
        }

        int digits = 1;
        int maxNum = qMax(1, gutterEditor.blockCount());
        while (maxNum >= 10) {
            maxNum /= 10;
            ++digits;
        }
        const int gutterWidth = 8 + 6 + gutterEditor.fontMetrics().horizontalAdvance(QLatin1Char('9')) * digits;
        const int secondLineY = gutterEditor.viewport()->geometry().top() + gutterEditor.fontMetrics().height() + 4;
        const QRect gutterSample(2,
                                 secondLineY,
                                 qMax(4, gutterWidth - 10),
                                 8);
        const QColor gutterFill = dominantColor(gutterImage, gutterSample);
        const QColor expectedGutter = codeEditorGutterFill(tokens);
        QVERIFY2(colorDelta(gutterFill, expectedGutter) < 46,
                 qPrintable(QStringLiteral("CodeEditor gutter should use neutral token tint, got %1 expected near %2")
                                .arg(gutterFill.name(), expectedGutter.name())));
        QVERIFY2(nearColorPixelCount(gutterImage,
                                     tokens.neutral.strokeSubtle,
                                     QRect(gutterWidth - 2, gutterEditor.viewport()->geometry().top(), 4, gutterEditor.viewport()->height()),
                                     56) > 8,
                 "CodeEditor gutter divider should use the neutral strokeSubtle token");
    }

    void codeEditorGutterWidthTracksBlockDigitsAndViewportMargin()
    {
        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };
        auto codeEditorGutterFill = [](const FluentThemeTokens &tokens) {
            return Style::mix(tokens.neutral.card, tokens.neutral.cardHover, tokens.dark ? 0.82 : 0.74);
        };
        auto makeLines = [](int count) {
            QStringList lines;
            lines.reserve(count);
            for (int i = 1; i <= count; ++i) {
                lines.append(QStringLiteral("int value%1 = %1;").arg(i));
            }
            return lines.join(QLatin1Char('\n'));
        };
        auto expectedGutterWidth = [](const FluentCodeEditor &editor) {
            int digits = 1;
            int maxNum = qMax(1, editor.blockCount());
            while (maxNum >= 10) {
                maxNum /= 10;
                ++digits;
            }
            return 8 + 6 + editor.fontMetrics().horizontalAdvance(QLatin1Char('9')) * digits;
        };
        auto assertNearInt = [](const QString &context, int actual, int expected) {
            QVERIFY2(qAbs(actual - expected) <= 1,
                     qPrintable(QStringLiteral("%1 expected %2 got %3").arg(context).arg(expected).arg(actual)));
        };

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        const ThemeColors colors = ThemeManager::instance().colors();
        const auto metrics = Style::metrics();

        FluentCodeEditor editor;
        editor.setAutoFormatEnabled(false);
        editor.setCurrentLineHighlightEnabled(false);
        editor.setBracketMatchHighlightEnabled(false);
        editor.setPlainText(makeLines(9));
        editor.resize(360, 172);
        editor.show();
        QTRY_VERIFY(editor.isVisible());
        QCoreApplication::processEvents();

        const int oneDigitGutter = expectedGutterWidth(editor);
        const QRect oneDigitViewport = editor.viewport()->geometry();
        assertNearInt(QStringLiteral("one-digit viewport left"),
                      oneDigitViewport.left(),
                      oneDigitGutter + metrics.paddingX);

        editor.setPlainText(makeLines(120));
        QTRY_COMPARE(editor.blockCount(), 120);
        QCoreApplication::processEvents();

        const int threeDigitGutter = expectedGutterWidth(editor);
        const QRect threeDigitViewport = editor.viewport()->geometry();
        QVERIFY2(threeDigitGutter > oneDigitGutter,
                 "CodeEditor gutter width should grow when blockCount() moves from one to three digits");
        assertNearInt(QStringLiteral("three-digit viewport left"),
                      threeDigitViewport.left(),
                      threeDigitGutter + metrics.paddingX);
        assertNearInt(QStringLiteral("viewport left delta"),
                      threeDigitViewport.left() - oneDigitViewport.left(),
                      threeDigitGutter - oneDigitGutter);

        QImage image(editor.size(), QImage::Format_ARGB32);
        image.fill(colors.background.rgba());
        {
            QPainter painter(&image);
            editor.render(&painter);
        }

        const QColor expectedGutter = codeEditorGutterFill(tokens);
        const QRect expandedGutterBand(oneDigitGutter + 2,
                                       threeDigitViewport.top() + editor.fontMetrics().height(),
                                       qMax(4, threeDigitGutter - oneDigitGutter - 4),
                                       12);
        const QColor expandedGutterFill = dominantColor(image, expandedGutterBand);
        QVERIFY2(colorDelta(expandedGutterFill, expectedGutter) < 46,
                 qPrintable(QStringLiteral("CodeEditor expanded gutter band should paint the neutral gutter tint, got %1 expected near %2")
                                .arg(expandedGutterFill.name(), expectedGutter.name())));
        QVERIFY2(nearColorPixelCount(image,
                                     tokens.neutral.strokeSubtle,
                                     QRect(threeDigitGutter - 2, threeDigitViewport.top(), 4, threeDigitViewport.height()),
                                     56) > 8,
                 "CodeEditor gutter divider should move to the new multi-digit gutter edge");

        editor.setLineNumbersEnabled(false);
        QCoreApplication::processEvents();
        assertNearInt(QStringLiteral("line-number-disabled viewport left"),
                      editor.viewport()->geometry().left(),
                      metrics.paddingX);
    }

    void codeEditorExtraSelectionsUseThemeTokens()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        auto colorDistance = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue())
                 + qAbs(a.alpha() - b.alpha());
        };

        auto colorsAtSelection = [](const QList<QTextEdit::ExtraSelection> &selections, int position) {
            QList<QColor> colors;
            for (const QTextEdit::ExtraSelection &selection : selections) {
                if (!selection.cursor.hasSelection()) {
                    continue;
                }
                if (selection.cursor.selectionStart() == position
                    && selection.cursor.selectionEnd() == position + 1) {
                    colors.append(selection.format.background().color());
                }
            }
            return colors;
        };

        auto assertNearColor = [&](const QString &context, const QColor &actual, const QColor &expected) {
            QVERIFY2(actual.isValid(), qPrintable(context + QStringLiteral(" should have a valid token color")));
            QVERIFY2(colorDistance(actual, expected) < 5,
                     qPrintable(QStringLiteral("%1 should use %2, got %3")
                                    .arg(context,
                                         expected.name(QColor::HexArgb),
                                         actual.name(QColor::HexArgb))));
        };

        syncTheme(false, QColor(QStringLiteral("#43FF43")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.surface = QColor(QStringLiteral("#F7FBFF"));
        custom.hover = QColor(QStringLiteral("#00FFFF"));
        custom.error = QColor(QStringLiteral("#FF2D55"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        const FluentThemeTokens tokens = ThemeManager::instance().tokens();

        FluentCodeEditor currentLineEditor;
        currentLineEditor.setLineNumbersEnabled(false);
        currentLineEditor.setBracketMatchHighlightEnabled(false);
        currentLineEditor.setPlainText(QStringLiteral("first\nsecond\nthird"));
        currentLineEditor.setTextCursor(QTextCursor(currentLineEditor.document()->findBlockByNumber(1)));
        QCoreApplication::processEvents();

        QColor currentLineColor;
        for (const QTextEdit::ExtraSelection &selection : currentLineEditor.extraSelections()) {
            if (selection.format.property(QTextFormat::FullWidthSelection).toBool()) {
                currentLineColor = selection.format.background().color();
                break;
            }
        }
        QColor expectedLine = tokens.neutral.cardHover;
        expectedLine.setAlphaF(tokens.dark ? 0.22 : 0.18);
        assertNearColor(QStringLiteral("CodeEditor current-line highlight"), currentLineColor, expectedLine);

        FluentCodeEditor matchedBracketEditor;
        matchedBracketEditor.setLineNumbersEnabled(false);
        matchedBracketEditor.setCurrentLineHighlightEnabled(false);
        matchedBracketEditor.setPlainText(QStringLiteral("if (ok) {\n}\n"));
        const int openParen = matchedBracketEditor.toPlainText().indexOf(QLatin1Char('('));
        const int closeParen = matchedBracketEditor.toPlainText().indexOf(QLatin1Char(')'));
        QTextCursor matchedCursor(matchedBracketEditor.document());
        matchedCursor.setPosition(openParen + 1);
        matchedBracketEditor.setTextCursor(matchedCursor);
        QCoreApplication::processEvents();

        QColor expectedBracket = tokens.accent.base;
        expectedBracket.setAlpha(90);
        const QList<QColor> openParenColors = colorsAtSelection(matchedBracketEditor.extraSelections(), openParen);
        const QList<QColor> closeParenColors = colorsAtSelection(matchedBracketEditor.extraSelections(), closeParen);
        QCOMPARE(openParenColors.size(), 1);
        QCOMPARE(closeParenColors.size(), 1);
        assertNearColor(QStringLiteral("CodeEditor matched opening bracket"), openParenColors.constFirst(), expectedBracket);
        assertNearColor(QStringLiteral("CodeEditor matched closing bracket"), closeParenColors.constFirst(), expectedBracket);

        FluentCodeEditor unmatchedBracketEditor;
        unmatchedBracketEditor.setLineNumbersEnabled(false);
        unmatchedBracketEditor.setCurrentLineHighlightEnabled(false);
        unmatchedBracketEditor.setPlainText(QStringLiteral("if (ok {\n}\n"));
        const int unmatchedParen = unmatchedBracketEditor.toPlainText().indexOf(QLatin1Char('('));
        QTextCursor unmatchedCursor(unmatchedBracketEditor.document());
        unmatchedCursor.setPosition(unmatchedParen + 1);
        unmatchedBracketEditor.setTextCursor(unmatchedCursor);
        QCoreApplication::processEvents();

        QColor expectedError = tokens.semantic.error;
        expectedError.setAlpha(90);
        const QList<QColor> unmatchedColors =
            colorsAtSelection(unmatchedBracketEditor.extraSelections(), unmatchedParen);
        QCOMPARE(unmatchedColors.size(), 1);
        assertNearColor(QStringLiteral("CodeEditor unmatched bracket"), unmatchedColors.constFirst(), expectedError);
        QVERIFY2(colorDistance(unmatchedColors.constFirst(), expectedBracket) > 80,
                 "CodeEditor unmatched bracket should use semantic.error, not an accent bracket token");
    }

    void codeEditorManualFormatMissingClangShowsFluentHintOnce()
    {
        struct TooltipRestore {
            ~TooltipRestore()
            {
                FluentToolTip::hideText();
                QCoreApplication::processEvents();
            }
        } tooltipRestore;

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        FluentToolTip::hideText();
        QCoreApplication::processEvents();

        FluentCodeEditor editor;
        editor.setClangFormatPath(QStringLiteral("__qtfluent_missing_clang_format__"));
        editor.setClangFormatMissingHintEnabled(true);
        editor.setPlainText(QStringLiteral("int main() {\nreturn 0;\n}\n"));
        editor.resize(360, 160);
        editor.show();
        QTRY_VERIFY(editor.isVisible());
        QVERIFY(!editor.clangFormatAvailable());

        QAction *formatAction = nullptr;
        for (QAction *action : editor.actions()) {
            if (action && action->shortcut() == QKeySequence(QStringLiteral("Ctrl+Shift+F"))) {
                formatAction = action;
                break;
            }
        }
        QVERIFY2(formatAction, "FluentCodeEditor should expose the documented manual format shortcut action");

        QSignalSpy finishedSpy(&editor, &FluentCodeEditor::formatFinished);
        formatAction->trigger();
        QTRY_COMPARE(finishedSpy.count(), 1);
        QTRY_VERIFY(findVisibleTopLevelByObjectName(QStringLiteral("FluentToolTip")));

        QWidget *tooltip = findVisibleTopLevelByObjectName(QStringLiteral("FluentToolTip"));
        QVERIFY(tooltip);
        auto *label = tooltip->findChild<QLabel *>();
        QVERIFY(label);
        QVERIFY2(label->text().contains(QStringLiteral("clang-format not found")),
                 "Manual formatting without clang-format should explain the basic formatter fallback");
        QVERIFY2(!renderWidgetImage(tooltip).isNull(),
                 "CodeEditor missing clang-format hint should render through FluentToolTip offscreen");

        FluentToolTip::hideText();
        QCoreApplication::processEvents();
        formatAction->trigger();
        QTRY_COMPARE(finishedSpy.count(), 2);
        QVERIFY2(!findVisibleTopLevelByObjectName(QStringLiteral("FluentToolTip")),
                 "CodeEditor missing clang-format hint should only be shown on the first manual format fallback");

        FluentCodeEditor disabledHintEditor;
        disabledHintEditor.setClangFormatPath(QStringLiteral("__qtfluent_missing_clang_format__"));
        disabledHintEditor.setClangFormatMissingHintEnabled(false);
        disabledHintEditor.setPlainText(QStringLiteral("if (ok) {\nreturn;\n}\n"));
        disabledHintEditor.resize(320, 140);
        disabledHintEditor.show();
        QTRY_VERIFY(disabledHintEditor.isVisible());

        QAction *disabledHintAction = nullptr;
        for (QAction *action : disabledHintEditor.actions()) {
            if (action && action->shortcut() == QKeySequence(QStringLiteral("Ctrl+Shift+F"))) {
                disabledHintAction = action;
                break;
            }
        }
        QVERIFY(disabledHintAction);
        disabledHintAction->trigger();
        QCoreApplication::processEvents();
        QVERIFY2(!findVisibleTopLevelByObjectName(QStringLiteral("FluentToolTip")),
                 "Disabling the missing clang-format hint should suppress the FluentToolTip");
    }

    void codeEditorAutoFormatDefersDuringImePreeditAndSkipsUnsafeStates()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const QString unformatted = QStringLiteral("int main(){\nreturn 0;\n}\n");
        const QString formatted = QStringLiteral("int main(){\n    return 0;\n}\n");

        auto configureEditor = [&](FluentCodeEditor &editor, const QString &text) {
            editor.setClangFormatPath(QStringLiteral("__qtfluent_missing_clang_format__"));
            editor.setClangFormatMissingHintEnabled(false);
            editor.setAutoFormatEnabled(true);
            editor.setAutoFormatTriggerPolicy(FluentCodeEditor::AutoFormatTriggerPolicy::OnEnterOrFocusOut);
            editor.setAutoFormatDebounceMs(0);
            editor.setPlainText(text);
            editor.resize(360, 160);
            editor.show();
            QElapsedTimer timer;
            timer.start();
            while (!editor.isVisible() && timer.elapsed() < 500) {
                QCoreApplication::processEvents(QEventLoop::AllEvents, 10);
                QTest::qWait(10);
            }
            return editor.isVisible() && !editor.clangFormatAvailable();
        };

        auto sendFocusOut = [](FluentCodeEditor &editor) {
            QFocusEvent event(QEvent::FocusOut, Qt::OtherFocusReason);
            QCoreApplication::sendEvent(&editor, &event);
            QCoreApplication::processEvents();
        };

        FluentCodeEditor readOnlyEditor;
        QVERIFY2(configureEditor(readOnlyEditor, unformatted),
                 "Read-only CodeEditor should show offscreen and use the basic formatter fallback");
        readOnlyEditor.setReadOnly(true);
        QSignalSpy readOnlyFinished(&readOnlyEditor, &FluentCodeEditor::formatFinished);
        sendFocusOut(readOnlyEditor);
        QTest::qWait(30);
        QCOMPARE(readOnlyFinished.count(), 0);
        QCOMPARE(readOnlyEditor.toPlainText(), unformatted);

        FluentCodeEditor oversizedEditor;
        QVERIFY2(configureEditor(oversizedEditor, unformatted),
                 "Oversized CodeEditor should show offscreen and use the basic formatter fallback");
        oversizedEditor.setMaxAutoFormatCharacters(8);
        QSignalSpy oversizedFinished(&oversizedEditor, &FluentCodeEditor::formatFinished);
        sendFocusOut(oversizedEditor);
        QTest::qWait(30);
        QCOMPARE(oversizedFinished.count(), 0);
        QCOMPARE(oversizedEditor.toPlainText(), unformatted);

        FluentCodeEditor imeEditor;
        QVERIFY2(configureEditor(imeEditor, unformatted),
                 "IME CodeEditor should show offscreen and use the basic formatter fallback");
        QSignalSpy imeFinished(&imeEditor, &FluentCodeEditor::formatFinished);

        const QList<QInputMethodEvent::Attribute> noAttributes;
        QInputMethodEvent composing{QStringLiteral("zhong"), noAttributes};
        QCoreApplication::sendEvent(&imeEditor, &composing);
        QCoreApplication::processEvents();
        sendFocusOut(imeEditor);
        QTest::qWait(30);
        QCOMPARE(imeFinished.count(), 0);
        QCOMPARE(imeEditor.toPlainText(), unformatted);

        QInputMethodEvent committed{QString(), noAttributes};
        QCoreApplication::sendEvent(&imeEditor, &committed);
        QTRY_COMPARE(imeFinished.count(), 1);
        QCOMPARE(imeFinished.takeFirst().at(0).toBool(), true);
        QCOMPARE(imeEditor.toPlainText(), formatted);
        QVERIFY2(!renderWidgetImage(&imeEditor).isNull(),
                 "CodeEditor should render after deferred IME auto-formatting through QWidget::render");
    }

    void codeEditorAsyncClangFormatDoesNotApplyStaleOutput()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        QTemporaryDir formatterDir;
        QVERIFY2(formatterDir.isValid(), "Test should be able to create a temporary clang-format shim");

#ifdef Q_OS_WIN
        const QString formatterPath = formatterDir.filePath(QStringLiteral("qtfluent-fake-clang-format.cmd"));
        const QByteArray formatterScript =
            "@echo off\r\n"
            "powershell -NoProfile -ExecutionPolicy Bypass -Command "
            "\"$text = [Console]::In.ReadToEnd(); "
            "Start-Sleep -Milliseconds 250; "
            "$text = $text -replace 'return 0;', 'return 42;'; "
            "[Console]::Out.Write($text)\"\r\n";
#else
        const QString formatterPath = formatterDir.filePath(QStringLiteral("qtfluent-fake-clang-format.sh"));
        const QByteArray formatterScript =
            "#!/bin/sh\n"
            "tmp=$(mktemp)\n"
            "cat > \"$tmp\"\n"
            "sleep 0.25\n"
            "sed 's/return 0;/return 42;/g' \"$tmp\"\n"
            "rm -f \"$tmp\"\n";
#endif

        QFile formatter(formatterPath);
        QVERIFY2(formatter.open(QIODevice::WriteOnly | QIODevice::Truncate),
                 "Test should be able to write a temporary clang-format shim");
        QVERIFY(formatter.write(formatterScript) == formatterScript.size());
        formatter.close();
        QVERIFY2(QFile::setPermissions(formatterPath,
                                       QFile::permissions(formatterPath)
                                           | QFileDevice::ReadOwner
                                           | QFileDevice::WriteOwner
                                           | QFileDevice::ExeOwner
                                           | QFileDevice::ReadUser
                                           | QFileDevice::ExeUser
                                           | QFileDevice::ReadGroup
                                           | QFileDevice::ExeGroup
                                           | QFileDevice::ReadOther
                                           | QFileDevice::ExeOther),
                 "Test should be able to mark the clang-format shim executable");

        const QString original = QStringLiteral("int main() {\nreturn 0;\n}\n");
        const QString userEdited = QStringLiteral("int main() {\nreturn 0; // user edit\n}\n");
        const QString expected = QStringLiteral("int main() {\nreturn 42; // user edit\n}\n");

        FluentCodeEditor editor;
        editor.setClangFormatPath(formatterPath);
        editor.setClangFormatMissingHintEnabled(false);
        editor.setAutoFormatEnabled(true);
        editor.setAutoFormatTriggerPolicy(FluentCodeEditor::AutoFormatTriggerPolicy::OnEnterOrFocusOut);
        editor.setAutoFormatDebounceMs(0);
        editor.setPlainText(original);
        editor.resize(360, 160);
        editor.show();
        QTRY_VERIFY(editor.isVisible());
        QVERIFY2(editor.clangFormatAvailable(),
                 qPrintable(QStringLiteral("Temporary clang-format shim should be executable: %1")
                                .arg(editor.clangFormatPath())));

        QSignalSpy startedSpy(&editor, &FluentCodeEditor::formatStarted);
        QSignalSpy finishedSpy(&editor, &FluentCodeEditor::formatFinished);

        editor.formatDocumentNow();
        QCOMPARE(startedSpy.count(), 1);

        editor.setPlainText(userEdited);
        QCOMPARE(editor.toPlainText(), userEdited);

        QTRY_VERIFY_WITH_TIMEOUT(finishedSpy.count() >= 2, 4000);
        QVERIFY2(startedSpy.count() >= 2,
                 "Stale clang-format output should schedule a pending reformat");
        QCOMPARE(finishedSpy.at(0).at(0).toBool(), false);
        QCOMPARE(finishedSpy.last().at(0).toBool(), true);
        QCOMPARE(editor.toPlainText(), expected);
        QVERIFY2(!editor.toPlainText().contains(QStringLiteral("return 42;\n}\n")),
                 "Stale clang-format output from the pre-edit document should not overwrite the user edit");
        QVERIFY2(!renderWidgetImage(&editor).isNull(),
                 "CodeEditor should render after stale async clang-format recovery through QWidget::render");
    }

    void cppHighlighterFollowsThemeChangesWhenUsedStandalone()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        auto formatColorAt = [](QTextDocument &document, int blockNumber, int column) {
            const QTextBlock block = document.findBlockByNumber(blockNumber);
            if (!block.isValid() || !block.layout()) {
                return QColor();
            }
            const QVector<QTextLayout::FormatRange> formats = block.layout()->formats();
            for (const QTextLayout::FormatRange &range : formats) {
                if (column >= range.start && column < range.start + range.length) {
                    return range.format.foreground().color();
                }
            }
            return QColor();
        };

        syncTheme(false, QColor(QStringLiteral("#43FF43")));
        QTextDocument document;
        document.setPlainText(QStringLiteral("#include <QtCore>\nint main() {\n    return 0;\n}\n"));

        auto *highlighter = new FluentCppHighlighter(&document);
        highlighter->rehighlight();
        QCoreApplication::processEvents();

        const QColor lightAccent = ThemeManager::instance().tokens().accent.base;
        QCOMPARE(formatColorAt(document, 0, 1), lightAccent);
        QCOMPARE(formatColorAt(document, 1, 1), lightAccent);
        QCOMPARE(formatColorAt(document, 2, 5), lightAccent);

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        QCoreApplication::processEvents();

        const QColor darkAccent = ThemeManager::instance().tokens().accent.base;
        QVERIFY(lightAccent != darkAccent);
        QCOMPARE(formatColorAt(document, 0, 1), darkAccent);
        QCOMPARE(formatColorAt(document, 1, 1), darkAccent);
        QCOMPARE(formatColorAt(document, 2, 5), darkAccent);
        QVERIFY2(highlighter->document() == &document,
                 "Standalone FluentCppHighlighter should update in place instead of relying on FluentCodeEditor recreation");
    }

    void codeEditorGutterSelectionExcludesBlockStartEnd()
    {
        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };
        auto codeEditorGutterFill = [](const FluentThemeTokens &tokens) {
            return Style::mix(tokens.neutral.card, tokens.neutral.cardHover, tokens.dark ? 0.82 : 0.74);
        };
        auto lineCenterY = [](FluentCodeEditor &editor, int blockNumber) {
            const QTextBlock block = editor.document()->findBlockByNumber(blockNumber);
            QTextCursor cursor(block);
            const QRect cursorRect = editor.cursorRect(cursor);
            return editor.viewport()->geometry().top() + cursorRect.center().y();
        };

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        const ThemeColors colors = ThemeManager::instance().colors();

        FluentCodeEditor editor;
        editor.setCurrentLineHighlightEnabled(false);
        editor.setBracketMatchHighlightEnabled(false);
        editor.setPlainText(QStringLiteral("first\nsecond\nthird"));
        QTextCursor selection(editor.document());
        selection.setPosition(0);
        selection.setPosition(editor.document()->findBlockByNumber(2).position(), QTextCursor::KeepAnchor);
        editor.setTextCursor(selection);
        editor.resize(280, 144);
        editor.show();
        QTRY_VERIFY(editor.isVisible());
        QCoreApplication::processEvents();

        QImage image(editor.size(), QImage::Format_ARGB32);
        image.fill(colors.background.rgba());
        {
            QPainter painter(&image);
            editor.render(&painter);
        }

        int digits = 1;
        int maxNum = qMax(1, editor.blockCount());
        while (maxNum >= 10) {
            maxNum /= 10;
            ++digits;
        }
        const int gutterWidth = 8 + 6 + editor.fontMetrics().horizontalAdvance(QLatin1Char('9')) * digits;
        const int sampleWidth = qMax(4, qMin(8, gutterWidth - 8));
        const QRect selectedLineSample(2, lineCenterY(editor, 1) - 4, sampleWidth, 8);
        const QRect excludedLineSample(2, lineCenterY(editor, 2) - 4, sampleWidth, 8);

        const QColor gutterFill = codeEditorGutterFill(tokens);
        QColor selectionFill = tokens.accent.base;
        selectionFill.setAlphaF(tokens.dark ? 0.28 : 0.18);
        const QColor selectedExpected = blendOver(selectionFill, gutterFill);

        const QColor selectedLineFill = dominantColor(image, selectedLineSample);
        QVERIFY2(colorDelta(selectedLineFill, selectedExpected) < 54,
                 qPrintable(QStringLiteral("CodeEditor gutter should highlight selected lines, got %1 expected near %2")
                                .arg(selectedLineFill.name(), selectedExpected.name())));

        const QColor excludedLineFill = dominantColor(image, excludedLineSample);
        QVERIFY2(colorDelta(excludedLineFill, gutterFill) < 46,
                 qPrintable(QStringLiteral("CodeEditor gutter should not include a selection that ends at the next block start, got %1 expected near %2")
                                .arg(excludedLineFill.name(), gutterFill.name())));
        QVERIFY2(colorDelta(excludedLineFill, selectedExpected) > 30,
                 "CodeEditor gutter third line should stay visibly different from selected gutter rows");
        QVERIFY2(!image.isNull(),
                 "CodeEditor gutter selection boundary should render to an offscreen QWidget::render image");
    }

    void tabWidgetChromeUsesThemeTokens()
    {
        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        const ThemeColors colors = ThemeManager::instance().colors();

        FluentTabWidget underlineTabs;
        underlineTabs.addTab(new QLabel(QStringLiteral("Overview page"), &underlineTabs), QStringLiteral("Overview"));
        underlineTabs.addTab(new QLabel(QStringLiteral("Details page"), &underlineTabs), QStringLiteral("Details"));
        underlineTabs.resize(280, 122);
        underlineTabs.show();
        QTRY_VERIFY(underlineTabs.isVisible());
        QTabBar *underlineBar = underlineTabs.tabBar();
        QVERIFY(underlineBar);
        QTRY_VERIFY(underlineBar->tabRect(0).isValid());

        QImage underlineImage(underlineBar->size(), QImage::Format_ARGB32);
        underlineImage.fill(colors.background.rgba());
        {
            QPainter painter(&underlineImage);
            underlineBar->render(&painter);
        }

        const QRect currentTab = underlineBar->tabRect(underlineBar->currentIndex());
        const QRect underlineArea(currentTab.left() + 12,
                                  underlineBar->height() - 8,
                                  qMax(0, currentTab.width() - 24),
                                  6);
        QVERIFY2(nearColorPixelCount(underlineImage, tokens.accent.base, underlineArea, 52) > 6,
                 "Underline TabWidget indicator should use the accent.base token");

        FluentTabWidget verticalTabs;
        verticalTabs.setTabPosition(QTabWidget::West);
        verticalTabs.addTab(new QLabel(QStringLiteral("Settings page"), &verticalTabs), QStringLiteral("General"));
        verticalTabs.addTab(new QLabel(QStringLiteral("About page"), &verticalTabs), QStringLiteral("About"));
        verticalTabs.resize(230, 150);
        verticalTabs.show();
        QTRY_VERIFY(verticalTabs.isVisible());
        QTabBar *verticalBar = verticalTabs.tabBar();
        QVERIFY(verticalBar);
        QTRY_VERIFY(verticalBar->tabRect(0).isValid());

        QImage verticalImage(verticalBar->size(), QImage::Format_ARGB32);
        verticalImage.fill(colors.background.rgba());
        {
            QPainter painter(&verticalImage);
            verticalBar->render(&painter);
        }

        const QRect verticalTab = verticalBar->tabRect(verticalBar->currentIndex());
        const QRect verticalBg = verticalTab.adjusted(10, 2, -10, -2);
        const QColor expectedSelectedBg =
            Style::mix(tokens.neutral.card, tokens.accent.base, tokens.dark ? 0.18 : 0.09);
        const QRect selectedBgSample(verticalBg.right() - 20,
                                     verticalBg.center().y() - 5,
                                     10,
                                     10);
        const QColor selectedBg = dominantColor(verticalImage, selectedBgSample);
        QVERIFY2(colorDelta(selectedBg, expectedSelectedBg) < 52,
                 qPrintable(QStringLiteral("Vertical TabWidget selected background should use neutral/accent tokens, got %1 expected near %2")
                                .arg(selectedBg.name(), expectedSelectedBg.name())));

        const QRect indicatorArea(verticalBg.left() + 4,
                                  verticalBg.top() + 8,
                                  8,
                                  qMax(0, verticalBg.height() - 16));
        QVERIFY2(nearColorPixelCount(verticalImage, tokens.accent.base, indicatorArea, 52) > 4,
                 "Vertical TabWidget indicator should use the accent.base token");
    }

    void tabWidgetReducedMotionResyncsExistingAnimations()
    {
        struct MotionRestore {
            bool animationsEnabled = ThemeManager::instance().animationsEnabled();
            FluentMotionTokens motionTokens = ThemeManager::instance().motionTokens();

            ~MotionRestore()
            {
                ThemeManager::instance().setMotionTokens(motionTokens);
                ThemeManager::instance().setAnimationsEnabled(animationsEnabled);
                QCoreApplication::processEvents();
            }
        } restore;

        auto hasRunningDirectAnimation = [](QObject *object) {
            const auto animations = object->findChildren<QVariantAnimation *>(QString(), Qt::FindDirectChildrenOnly);
            for (QVariantAnimation *animation : animations) {
                if (animation && animation->state() == QAbstractAnimation::Running) {
                    return true;
                }
            }
            return false;
        };

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeManager::instance().setAnimationsEnabled(true);
        FluentMotion::setDuration(FluentMotionRole::Selection, 180);
        FluentMotion::setDuration(FluentMotionRole::Hover, 180);
        QCoreApplication::processEvents();

        FluentTabWidget tabs;
        tabs.addTab(new QLabel(QStringLiteral("Overview page"), &tabs), QStringLiteral("Overview"));
        tabs.addTab(new QLabel(QStringLiteral("Details page"), &tabs), QStringLiteral("Details"));
        tabs.resize(280, 122);
        tabs.show();
        QTRY_VERIFY(tabs.isVisible());

        QTabBar *bar = tabs.tabBar();
        QVERIFY(bar);
        QTRY_VERIFY(bar->tabRect(0).isValid());
        QTRY_VERIFY(bar->tabRect(1).isValid());
        QTRY_VERIFY(!hasRunningDirectAnimation(bar));

        tabs.setCurrentIndex(1);
        QCoreApplication::processEvents();
        QVERIFY2(hasRunningDirectAnimation(bar),
                 "TabWidget selection indicator should be running before reduced motion is enabled");
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();
        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QVERIFY2(!hasRunningDirectAnimation(bar),
                 "TabWidget selection indicator should snap when reduced motion is enabled mid-flight");

        const QImage selectedImage = renderWidgetImage(bar);
        const QRect secondTab = bar->tabRect(1);
        const QRect secondUnderline(secondTab.left() + 12,
                                    bar->height() - 8,
                                    qMax(0, secondTab.width() - 24),
                                    6);
        QVERIFY2(nearColorPixelCount(selectedImage, tokens.accent.base, secondUnderline, 52) > 6,
                 "TabWidget reduced-motion indicator should land on the selected tab immediately");

        ThemeManager::instance().setAnimationsEnabled(true);
        QCoreApplication::processEvents();
        QMouseEvent hoverEvent(QEvent::MouseMove,
                               QPointF(bar->tabRect(0).center()),
                               QPointF(bar->tabRect(0).center()),
                               QPointF(bar->tabRect(0).center()),
                               Qt::NoButton,
                               Qt::NoButton,
                               Qt::NoModifier);
        QCoreApplication::sendEvent(bar, &hoverEvent);
        QCoreApplication::processEvents();
        QVERIFY2(hasRunningDirectAnimation(bar),
                 "TabWidget hover should be running before reduced motion is enabled");
        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();
        QVERIFY2(!hasRunningDirectAnimation(bar),
                 "TabWidget hover should snap when reduced motion is enabled mid-flight");

        QEvent leaveEvent(QEvent::Leave);
        QCoreApplication::sendEvent(bar, &leaveEvent);
        QVERIFY2(!hasRunningDirectAnimation(bar),
                 "TabWidget hover leave should snap when animations are disabled after construction");
    }

    void toolBarWrapsPlainActionsWithFluentButtons()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.background = QColor(QStringLiteral("#EEF5FF"));
        custom.surface = QColor(QStringLiteral("#F7FBFF"));
        custom.hover = QColor(QStringLiteral("#00FFFF"));
        custom.border = QColor(QStringLiteral("#FF00FF"));
        custom.text = QColor(QStringLiteral("#123A70"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        FluentToolBar toolbar(QStringLiteral("Document commands"));
        toolbar.setIconSize(QSize(18, 18));

        auto *saveAction = new QAction(FluentIcon::icon(FluentIconType::Save), QStringLiteral("Save"), &toolbar);
        saveAction->setCheckable(true);
        saveAction->setChecked(true);
        auto *exportAction = new QAction(FluentIcon::icon(FluentIconType::Download), QStringLiteral("Export"), &toolbar);
        exportAction->setEnabled(false);

        toolbar.addAction(saveAction);
        QAction *separatorAction = toolbar.addSeparator();
        toolbar.addAction(exportAction);
        toolbar.resize(320, 42);
        toolbar.show();
        QTRY_VERIFY(toolbar.isVisible());

        auto buttonForAction = [&toolbar](QAction *action) -> FluentToolButton * {
            const auto buttons = toolbar.findChildren<FluentToolButton *>();
            for (auto *button : buttons) {
                if (button && button->defaultAction() == action) {
                    return button;
                }
            }
            return nullptr;
        };

        auto *saveButton = buttonForAction(saveAction);
        auto *exportButton = buttonForAction(exportAction);
        QVERIFY2(saveButton, "FluentToolBar should wrap a plain QAction in a FluentToolButton");
        QVERIFY2(exportButton, "FluentToolBar should wrap trailing actions as FluentToolButtons too");
        QVERIFY2(!toolbar.widgetForAction(saveAction), "The original QAction should not remain as a native toolbar button");
        QCOMPARE(saveButton->text(), QStringLiteral("Save"));
        QVERIFY(saveButton->isCheckable());
        QVERIFY(saveButton->isChecked());
        QVERIFY(!exportButton->isEnabled());

        const auto &lightColors = ThemeManager::instance().colors();
        const auto lightTokens = ThemeManager::instance().tokens();
        const QColor lightHover = Style::mix(lightTokens.neutral.card,
                                             lightTokens.neutral.cardHover,
                                             lightTokens.dark ? 0.70 : 0.55);
        const QString lightStyle = toolbar.styleSheet();
        QVERIFY(lightStyle.contains(lightTokens.neutral.card.name(QColor::HexArgb)));
        QVERIFY(lightStyle.contains(lightTokens.neutral.strokeSubtle.name(QColor::HexArgb)));
        QVERIFY(lightStyle.contains(lightHover.name(QColor::HexArgb)));
        QVERIFY(lightStyle.contains(lightColors.text.name(QColor::HexArgb)));
        QVERIFY2(!lightStyle.contains(lightColors.border.name(QColor::HexArgb)),
                 "FluentToolBar style should not use the raw legacy border color");
        QVERIFY2(!lightStyle.contains(lightColors.hover.name(QColor::HexArgb)),
                 "FluentToolBar style should not use the raw legacy hover color");

        const QImage lightImage = renderWidgetImage(&toolbar, QSize(320, 42));
        QVERIFY2(nearColorPixelCount(lightImage, lightTokens.neutral.card, QRect(0, 0, 12, toolbar.height() - 3), 32) > 48,
                 "FluentToolBar background should render neutral.card token pixels");
        QVERIFY2(nearColorPixelCount(lightImage, lightTokens.neutral.strokeSubtle, QRect(0, toolbar.height() - 3, 320, 3), 72) > 24,
                 "FluentToolBar bottom border should render neutral.strokeSubtle token pixels");
        if (QWidget *separator = toolbar.widgetForAction(separatorAction)) {
            const QRect separatorProbe = separator->geometry().adjusted(-2, 0, 2, 0).intersected(toolbar.rect());
            QVERIFY2(separatorProbe.isValid(), "FluentToolBar separator should expose a valid render probe");
            QVERIFY2(nearColorPixelCount(lightImage, lightTokens.neutral.strokeSubtle, separatorProbe, 72) > 2,
                     "FluentToolBar separator should render neutral.strokeSubtle token pixels");
            QVERIFY2(nearColorPixelCount(lightImage, lightColors.border, separatorProbe, 36) < 4,
                     "FluentToolBar separator should not render raw legacy border pixels");
        } else {
            QFAIL("FluentToolBar separator should be represented by a toolbar widget for render verification");
        }

        saveAction->setText(QStringLiteral("Save all"));
        saveAction->setChecked(false);
        exportAction->setEnabled(true);
        QCoreApplication::processEvents();

        QCOMPARE(saveButton->text(), QStringLiteral("Save all"));
        QVERIFY(!saveButton->isChecked());
        QVERIFY(exportButton->isEnabled());

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        ThemeColors darkCustom = ThemeManager::instance().colors();
        darkCustom.background = QColor(QStringLiteral("#101010"));
        darkCustom.surface = QColor(QStringLiteral("#201820"));
        darkCustom.hover = QColor(QStringLiteral("#00FFFF"));
        darkCustom.border = QColor(QStringLiteral("#FF00FF"));
        darkCustom.text = QColor(QStringLiteral("#F2F7FF"));
        ThemeManager::instance().setColors(darkCustom);
        QCoreApplication::processEvents();

        const auto &darkColors = ThemeManager::instance().colors();
        const auto darkTokens = ThemeManager::instance().tokens();
        const QColor darkHover = Style::controlHoverFill(darkTokens);
        const QString darkStyle = toolbar.styleSheet();
        QVERIFY(lightStyle != darkStyle);
        QVERIFY(darkStyle.contains(darkTokens.neutral.card.name(QColor::HexArgb)));
        QVERIFY(darkStyle.contains(darkTokens.neutral.strokeSubtle.name(QColor::HexArgb)));
        QVERIFY(darkStyle.contains(darkHover.name(QColor::HexArgb)));
        QVERIFY(darkStyle.contains(darkColors.text.name(QColor::HexArgb)));
        QVERIFY2(!darkStyle.contains(darkColors.border.name(QColor::HexArgb)),
                 "Dark FluentToolBar style should not use the raw legacy border color");
        const QColor legacyDarkHover = Style::mix(darkColors.surface, darkColors.hover, 0.32);
        if (legacyDarkHover != darkHover) {
            QVERIFY2(!darkStyle.contains(legacyDarkHover.name(QColor::HexArgb)),
                     "Dark FluentToolBar style should not use the old surface/hover mix");
        }
    }

    void toolBarPreservesWrappedActionMaintenanceSemantics()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        FluentToolBar toolbar(QStringLiteral("Document commands"));
        toolbar.setIconSize(QSize(18, 18));

        auto *openAction = new QAction(FluentIcon::icon(FluentIconType::Document),
                                       QStringLiteral("Open"),
                                       &toolbar);
        auto *saveAction = new QAction(FluentIcon::icon(FluentIconType::Save),
                                       QStringLiteral("Save"),
                                       &toolbar);

        toolbar.addAction(openAction);
        auto *customWidget = new QLabel(QStringLiteral("Filter"), &toolbar);
        QAction *customAction = toolbar.addWidget(customWidget);
        toolbar.insertAction(openAction, saveAction);

        toolbar.resize(320, 42);
        toolbar.show();
        QTRY_VERIFY(toolbar.isVisible());

        auto buttonForAction = [&toolbar](QAction *action) -> FluentToolButton * {
            const auto buttons = toolbar.findChildren<FluentToolButton *>();
            for (auto *button : buttons) {
                if (button && button->defaultAction() == action) {
                    return button;
                }
            }
            return nullptr;
        };

        auto toolbarWrapsAction = [&toolbar](QAction *action) {
            for (QAction *toolbarAction : toolbar.actions()) {
                auto *widgetAction = qobject_cast<QWidgetAction *>(toolbarAction);
                if (!widgetAction) {
                    continue;
                }
                auto *button = qobject_cast<FluentToolButton *>(toolbar.widgetForAction(widgetAction));
                if (button && button->defaultAction() == action) {
                    return true;
                }
            }
            return false;
        };

        auto *saveButton = buttonForAction(saveAction);
        auto *openButton = buttonForAction(openAction);
        QVERIFY2(saveButton, "insertAction(before, action) should wrap the inserted source QAction");
        QVERIFY2(openButton, "Existing wrapped actions should remain present after inserting before them");
        QVERIFY2(toolbarWrapsAction(saveAction), "The inserted QAction should be represented by an internal wrapper");
        QVERIFY2(toolbarWrapsAction(openAction), "The original QAction should still be represented by an internal wrapper");
        QCOMPARE(toolbar.widgetForAction(customAction), customWidget);
        QVERIFY2(!toolbarWrapsAction(customAction),
                 "QWidgetAction/addWidget entries should not be replaced by FluentToolButton wrappers");
        QVERIFY2(saveButton->geometry().left() < openButton->geometry().left(),
                 "insertAction(before, action) should translate a wrapped before QAction to its wrapper position");
        QVERIFY2(openButton->geometry().right() <= customWidget->geometry().left(),
                 "Wrapped QAction insertion should keep custom toolbar widgets in order");

        const QImage beforeRemove = renderWidgetImage(&toolbar, QSize(320, 42));
        QVERIFY2(!beforeRemove.isNull(),
                 "FluentToolBar maintenance semantics should remain renderable through QWidget::render offscreen");

        toolbar.removeAction(saveAction);
        QCoreApplication::processEvents();
        QCoreApplication::sendPostedEvents(nullptr, QEvent::DeferredDelete);
        QCoreApplication::processEvents();

        QVERIFY2(!toolbarWrapsAction(saveAction),
                 "removeAction(source QAction) should remove the internal FluentToolButton wrapper");
        QVERIFY2(toolbarWrapsAction(openAction),
                 "Removing one wrapped source QAction should not disturb adjacent wrapped commands");
        QCOMPARE(toolbar.widgetForAction(customAction), customWidget);

        const QImage afterRemove = renderWidgetImage(&toolbar, QSize(320, 42));
        QVERIFY2(!afterRemove.isNull(),
                 "FluentToolBar should still render after removing a wrapped source QAction");
    }

    void statusBarUsesThemeTokensAndDisablesNativeGrip()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.background = QColor(QStringLiteral("#EEF5FF"));
        custom.surface = QColor(QStringLiteral("#F7FBFF"));
        custom.border = QColor(QStringLiteral("#FF00FF"));
        custom.text = QColor(QStringLiteral("#123A70"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        FluentStatusBar status;
        auto *label = new QLabel(QStringLiteral("Synced"), &status);
        status.addPermanentWidget(label);
        status.showMessage(QStringLiteral("Ready"));
        status.resize(260, 32);
        status.show();
        QTRY_VERIFY(status.isVisible());

        QVERIFY(!status.isSizeGripEnabled());
        QVERIFY(status.testAttribute(Qt::WA_StyledBackground));
        QCOMPARE(status.currentMessage(), QStringLiteral("Ready"));
        QCOMPARE(label->text(), QStringLiteral("Synced"));

        const auto &lightColors = ThemeManager::instance().colors();
        const auto lightTokens = ThemeManager::instance().tokens();
        const QString lightStyle = status.styleSheet();
        QVERIFY(lightStyle.contains(lightTokens.neutral.card.name(QColor::HexArgb)));
        QVERIFY(lightStyle.contains(lightTokens.neutral.strokeSubtle.name(QColor::HexArgb)));
        QVERIFY(lightStyle.contains(lightColors.text.name(QColor::HexArgb)));
        QVERIFY2(!lightStyle.contains(lightColors.border.name(QColor::HexArgb)),
                 "FluentStatusBar style should not use the raw legacy border color");

        const QImage lightImage = renderWidgetImage(&status, QSize(260, 32));
        QVERIFY2(nearColorPixelCount(lightImage, lightTokens.neutral.strokeSubtle, QRect(0, 0, 260, 3), 72) > 24,
                 "FluentStatusBar top border should render neutral.strokeSubtle token pixels");
        QVERIFY2(nearColorPixelCount(lightImage, lightColors.border, QRect(0, 0, 260, 3), 36) < 8,
                 "FluentStatusBar top border should not render raw legacy border pixels");

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        ThemeColors darkCustom = ThemeManager::instance().colors();
        darkCustom.background = QColor(QStringLiteral("#101010"));
        darkCustom.surface = QColor(QStringLiteral("#201820"));
        darkCustom.border = QColor(QStringLiteral("#FF00FF"));
        darkCustom.text = QColor(QStringLiteral("#F2F7FF"));
        ThemeManager::instance().setColors(darkCustom);
        QCoreApplication::processEvents();

        const auto &darkColors = ThemeManager::instance().colors();
        const auto darkTokens = ThemeManager::instance().tokens();
        const QString darkStyle = status.styleSheet();

        QVERIFY(lightStyle != darkStyle);
        QVERIFY(darkStyle.contains(darkTokens.neutral.card.name(QColor::HexArgb)));
        QVERIFY(darkStyle.contains(darkTokens.neutral.strokeSubtle.name(QColor::HexArgb)));
        QVERIFY(darkStyle.contains(darkColors.text.name(QColor::HexArgb)));
        QVERIFY2(!darkStyle.contains(darkColors.border.name(QColor::HexArgb)),
                 "Dark FluentStatusBar style should not use the raw legacy border color");
    }

    void dropDownAndSplitButtonsUseFluentMenuPopups()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        QWidget window;
        auto *layout = new QHBoxLayout(&window);
        layout->setContentsMargins(18, 18, 18, 18);
        layout->setSpacing(12);

        auto *drop = new FluentDropDownButton(QStringLiteral("More actions"), &window);
        drop->addAction(QStringLiteral("Copy link"));
        drop->addAction(QStringLiteral("Move to"));

        auto *split = new FluentSplitButton(QStringLiteral("Save"), &window);
        auto *saveAction = new QAction(QStringLiteral("Save"), split);
        split->setDefaultAction(saveAction);
        auto *splitMenu = new FluentMenu(split);
        splitMenu->addAction(QStringLiteral("Save as"));
        splitMenu->addAction(QStringLiteral("Export"));
        split->setMenu(splitMenu);

        layout->addWidget(drop);
        layout->addWidget(split);
        layout->addStretch(1);

        window.show();
        QTRY_VERIFY(window.isVisible());
        QTRY_VERIFY(drop->isVisible());
        QTRY_VERIFY(split->isVisible());

        auto popupContentGlobalRect = [](QWidget *popup) {
            const QRect content = PopupSurface::shadowContentRect(popup->rect());
            return QRect(popup->mapToGlobal(content.topLeft()), content.size());
        };
        auto widgetGlobalRect = [](QWidget *widget) {
            return QRect(widget->mapToGlobal(QPoint(0, 0)), widget->size());
        };
        auto closeFluentPopup = []() {
            if (QWidget *popup = findVisibleTopLevelByObjectName(QStringLiteral("FluentMenuPopupHost"))) {
                popup->close();
            }
            QCoreApplication::processEvents();
            QTRY_COMPARE(visibleTopLevelCountByObjectName(QStringLiteral("FluentMenuPopupHost")), 0);
        };

        QTest::mouseClick(drop, Qt::LeftButton, Qt::NoModifier, drop->rect().center());
        QCoreApplication::processEvents();
        QTRY_COMPARE(visibleTopLevelCountByObjectName(QStringLiteral("FluentMenuPopupHost")), 1);
        QCOMPARE(visibleNativeMenuPopupCount(), 0);
        QWidget *dropPopup = findVisibleTopLevelByObjectName(QStringLiteral("FluentMenuPopupHost"));
        QVERIFY2(dropPopup, "DropDownButton should open a Fluent menu popup");
        QVERIFY2(popupContentGlobalRect(dropPopup).top() >= widgetGlobalRect(drop).bottom(),
                 "DropDownButton popup content should appear below the button instead of overlapping its label");
        closeFluentPopup();

        QSignalSpy saveSpy(saveAction, &QAction::triggered);
        QTest::mouseClick(split->mainButton(), Qt::LeftButton, Qt::NoModifier, split->mainButton()->rect().center());
        QCoreApplication::processEvents();
        QCOMPARE(saveSpy.count(), 1);
        QCOMPARE(visibleTopLevelCountByObjectName(QStringLiteral("FluentMenuPopupHost")), 0);

        QTest::mouseClick(split->dropDownButton(),
                          Qt::LeftButton,
                          Qt::NoModifier,
                          split->dropDownButton()->rect().center());
        QCoreApplication::processEvents();
        QTRY_COMPARE(visibleTopLevelCountByObjectName(QStringLiteral("FluentMenuPopupHost")), 1);
        QCOMPARE(visibleNativeMenuPopupCount(), 0);
        QWidget *splitPopup = findVisibleTopLevelByObjectName(QStringLiteral("FluentMenuPopupHost"));
        QVERIFY2(splitPopup, "SplitButton dropdown segment should open a Fluent menu popup");
        QVERIFY2(popupContentGlobalRect(splitPopup).top() >= widgetGlobalRect(split).bottom(),
                 "SplitButton menu content should appear below the joined button surface");
        QCOMPARE(saveSpy.count(), 1);
        closeFluentPopup();
    }

    void navigationSelectionStaysInsideScrollableViewport()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();

        FluentNavigationView nav;
        nav.setExpandedWidth(248);
        nav.setFixedSize(248, 220);
        nav.setPaneTitle(QStringLiteral("Navigation"));

        std::vector<FluentNavigationItem> items;
        for (int i = 0; i < 18; ++i) {
            FluentNavigationItem item;
            item.key = QStringLiteral("item_%1").arg(i);
            item.text = QStringLiteral("Item %1").arg(i + 1);
            item.hasFluentIcon = true;
            item.fluentIcon = FluentIconType::Document;
            items.push_back(item);
        }
        nav.setItems(items);

        FluentNavigationItem settings;
        settings.key = QStringLiteral("settings");
        settings.text = QStringLiteral("Settings");
        settings.hasFluentIcon = true;
        settings.fluentIcon = FluentIconType::Settings;
        nav.setFooterItems({settings});

        nav.show();
        QTRY_VERIFY(nav.isVisible());
        nav.setSelectedKey(QStringLiteral("item_14"));
        QCoreApplication::processEvents();

        const QColor accent = ThemeManager::instance().colors().accent;
        const QImage selectedVisible = renderWidgetImage(&nav);
        QVERIFY2(nearColorPixelCount(selectedVisible, accent, QRect(0, 42, 16, 126)) > 8,
                 "Selecting a deep NavigationView item should scroll its accent indicator into the main viewport");

        const QPointF wheelPos(nav.width() / 2.0, 76.0);
        QWheelEvent wheel(wheelPos,
                          QPointF(nav.mapToGlobal(wheelPos.toPoint())),
                          QPoint(0, 40),
                          QPoint(),
                          Qt::NoButton,
                          Qt::NoModifier,
                          Qt::NoScrollPhase,
                          false);
        QCoreApplication::sendEvent(&nav, &wheel);
        QCoreApplication::processEvents();

        const QImage scrolledAway = renderWidgetImage(&nav);
        QVERIFY2(nearColorPixelCount(scrolledAway, accent, QRect(0, nav.height() - 48, 16, 46)) <= 4,
                 "A scrolled-away NavigationView selection indicator should not paint over pinned footer rows");
    }

