    void navigationAutoCollapseUsesParentWidthHysteresisAndSkipsTopMode()
    {
        syncTheme(false, QColor(QStringLiteral("#0066B4")));

        const bool oldAnimationsEnabled = ThemeManager::instance().animationsEnabled();
        struct RestoreAnimations {
            bool enabled = true;
            ~RestoreAnimations()
            {
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } restore{oldAnimationsEnabled};

        ThemeManager::instance().setAnimationsEnabled(false);
        QCoreApplication::processEvents();

        QWidget host;
        host.setObjectName(QStringLiteral("NavigationAutoCollapseHost"));
        host.resize(860, 240);
        auto *layout = new QHBoxLayout(&host);
        layout->setContentsMargins(0, 0, 0, 0);
        layout->setSpacing(0);

        auto *nav = new FluentNavigationView(&host);
        nav->setExpandedWidth(240);
        nav->setCompactWidth(56);

        FluentNavigationItem home;
        home.key = QStringLiteral("home");
        home.text = QStringLiteral("Home");
        home.hasFluentIcon = true;
        home.fluentIcon = FluentIconType::Home;

        FluentNavigationItem documents;
        documents.key = QStringLiteral("documents");
        documents.text = QStringLiteral("Documents");
        documents.hasFluentIcon = true;
        documents.fluentIcon = FluentIconType::Document;

        nav->setItems({home, documents});
        nav->setSelectedKey(home.key);
        layout->addWidget(nav);

        host.show();
        QTRY_VERIFY(host.isVisible());
        QTRY_VERIFY(nav->isVisible());

        QSignalSpy modeSpy(nav, &FluentNavigationView::paneDisplayModeChanged);
        QSignalSpy expandedSpy(nav, &FluentNavigationView::expandedChanged);

        nav->setAutoCollapseWidth(800);
        QCoreApplication::processEvents();
        QCOMPARE(nav->autoCollapseWidth(), 800);
        QCOMPARE(nav->paneDisplayMode(), FluentNavigationView::Left);
        QCOMPARE(nav->minimumWidth(), nav->expandedWidth());
        QCOMPARE(nav->maximumWidth(), nav->expandedWidth());
        QVERIFY2(!renderWidgetImage(nav, QSize(nav->expandedWidth(), 160)).isNull(),
                 "Expanded NavigationView should render before auto-collapse");

        host.resize(760, 240);
        QCoreApplication::processEvents();
        QTRY_COMPARE(nav->paneDisplayMode(), FluentNavigationView::LeftCompact);
        QCOMPARE(nav->minimumWidth(), nav->compactWidth());
        QCOMPARE(nav->maximumWidth(), nav->compactWidth());
        QCOMPARE(modeSpy.count(), 1);
        QCOMPARE(modeSpy.last().at(0).toInt(), int(FluentNavigationView::LeftCompact));
        QCOMPARE(expandedSpy.count(), 1);
        QCOMPARE(expandedSpy.last().at(0).toBool(), false);
        QVERIFY2(!renderWidgetImage(nav, QSize(nav->compactWidth(), 160)).isNull(),
                 "Compact NavigationView should render after parent-width auto-collapse");

        host.resize(850, 240);
        QCoreApplication::processEvents();
        QCOMPARE(nav->paneDisplayMode(), FluentNavigationView::LeftCompact);
        QCOMPARE(modeSpy.count(), 1);

        host.resize(900, 240);
        QCoreApplication::processEvents();
        QTRY_COMPARE(nav->paneDisplayMode(), FluentNavigationView::Left);
        QCOMPARE(nav->minimumWidth(), nav->expandedWidth());
        QCOMPARE(nav->maximumWidth(), nav->expandedWidth());
        QCOMPARE(modeSpy.count(), 2);
        QCOMPARE(modeSpy.last().at(0).toInt(), int(FluentNavigationView::Left));
        QCOMPARE(expandedSpy.count(), 2);
        QCOMPARE(expandedSpy.last().at(0).toBool(), true);

        nav->setPaneDisplayMode(FluentNavigationView::Top);
        QCoreApplication::processEvents();
        QCOMPARE(nav->paneDisplayMode(), FluentNavigationView::Top);
        modeSpy.clear();
        expandedSpy.clear();

        host.resize(640, 240);
        QCoreApplication::processEvents();
        QCOMPARE(nav->paneDisplayMode(), FluentNavigationView::Top);
        QCOMPARE(modeSpy.count(), 0);
        QCOMPARE(expandedSpy.count(), 0);
        QVERIFY2(nav->maximumWidth() > nav->expandedWidth(),
                 "Top NavigationView should keep expanding width policy instead of compact auto-collapse constraints");
        QVERIFY2(!renderWidgetImage(nav, QSize(320, 48)).isNull(),
                 "Top NavigationView should remain renderable while auto-collapse threshold is set");
    }

