    void controlSurfaceHoverSeparatesFromDarkCardHover()
    {
        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        const ThemeColors colors = Theme::dark();
        const FluentThemeTokens tokens = Theme::tokens(colors);

        QImage image(104, 56, QImage::Format_ARGB32);
        image.fill(Qt::transparent);
        {
            QPainter painter(&image);
            Style::paintControlSurface(painter,
                                       QRectF(10, 10, 84, 36),
                                       colors,
                                       1.0,
                                       0.0,
                                       true,
                                       false);
        }

        const QColor hoverFill = dominantColor(image, QRect(28, 22, 48, 12));
        const QColor expectedControlHover = Style::controlHoverFill(tokens);
        const QColor cardSurfaceHover = Style::mix(tokens.neutral.card, tokens.neutral.cardHover, 0.70);
        QVERIFY2(colorDelta(hoverFill, expectedControlHover) < 18,
                 qPrintable(QStringLiteral("Dark control surface hover should use controlHoverFill, got %1 expected near %2")
                                .arg(hoverFill.name(), expectedControlHover.name())));
        QVERIFY2(colorDelta(hoverFill, cardSurfaceHover) > 6,
                 qPrintable(QStringLiteral("Dark control surface hover should not collapse into card hover, got %1 card hover %2")
                                .arg(hoverFill.name(), cardSurfaceHover.name())));
    }

    void buttonSurfacesUseThemeTokens()
    {
        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        auto renderButton = [](bool dark,
                               const QColor &accent,
                               bool primary,
                               bool enabled,
                               qreal hoverLevel,
                               qreal pressLevel) {
            syncTheme(dark, accent);
            const ThemeColors colors = ThemeManager::instance().colors();

            QWidget host;
            host.resize(140, 52);
            host.setAttribute(Qt::WA_StyledBackground, true);
            host.setStyleSheet(QStringLiteral("background: %1;").arg(colors.background.name(QColor::HexArgb)));

            auto *button = new FluentButton(QStringLiteral("Token"), &host);
            button->setPrimary(primary);
            button->setEnabled(enabled);
            button->move(12, 8);
            button->resize(116, 36);
            button->show();

            host.show();
            QCoreApplication::processEvents();
            button->setHoverLevel(hoverLevel);
            button->setPressLevel(pressLevel);
            QCoreApplication::processEvents();

            QImage image(host.size(), QImage::Format_ARGB32);
            image.fill(colors.background.rgba());
            QPainter painter(&image);
            host.render(&painter);
            return image;
        };

        const QRect fillSample(20, 18, 18, 12);

        const QImage lightHoverImage =
            renderButton(false, QColor(QStringLiteral("#0066B4")), false, true, 1.0, 0.0);
        const FluentThemeTokens lightTokens = ThemeManager::instance().tokens();
        const ThemeColors lightColors = ThemeManager::instance().colors();
        const QColor lightHoverFill = dominantColor(lightHoverImage, fillSample);
        const QColor expectedLightHover = Style::controlHoverFill(lightTokens);
        const QColor legacyLightHover = Style::mix(lightColors.surface, lightColors.hover, 0.88);
        QVERIFY2(colorDelta(lightHoverFill, expectedLightHover) < 42,
                 qPrintable(QStringLiteral("Neutral FluentButton hover should use neutral card tokens, got %1 expected near %2")
                                .arg(lightHoverFill.name(), expectedLightHover.name())));
        QVERIFY2(colorDelta(lightHoverFill, legacyLightHover) > 12,
                 qPrintable(QStringLiteral("Neutral FluentButton hover should not fall back to legacy surface/hover mix, got %1")
                                .arg(lightHoverFill.name())));

        const QImage darkHoverImage =
            renderButton(true, QColor(QStringLiteral("#0066B4")), false, true, 1.0, 0.0);
        const FluentThemeTokens darkHoverTokens = ThemeManager::instance().tokens();
        const QColor darkHoverFill = dominantColor(darkHoverImage, fillSample);
        const QColor expectedDarkHover = Style::controlHoverFill(darkHoverTokens);
        const QColor darkCardHover =
            Style::mix(darkHoverTokens.neutral.card, darkHoverTokens.neutral.cardHover, 0.70);
        QVERIFY2(colorDelta(darkHoverFill, expectedDarkHover) < 42,
                 qPrintable(QStringLiteral("Dark neutral FluentButton hover should use the control hover token, got %1 expected near %2")
                                .arg(darkHoverFill.name(), expectedDarkHover.name())));
        QVERIFY2(colorDelta(darkHoverFill, darkCardHover) > 6,
                 qPrintable(QStringLiteral("Dark neutral FluentButton hover should separate from card hover, got %1 card hover %2")
                                .arg(darkHoverFill.name(), darkCardHover.name())));

        const QImage darkDisabledImage =
            renderButton(true, QColor(QStringLiteral("#0066B4")), false, false, 0.0, 0.0);
        const FluentThemeTokens darkTokens = ThemeManager::instance().tokens();
        const ThemeColors darkColors = ThemeManager::instance().colors();
        const QColor darkDisabledFill = dominantColor(darkDisabledImage, fillSample);
        const QColor expectedDarkDisabled =
            Style::mix(darkTokens.neutral.card, darkTokens.neutral.background, 0.48);
        const QColor legacyDarkDisabled = Style::mix(darkColors.surface, darkColors.hover, 0.45);
        QVERIFY2(colorDelta(darkDisabledFill, expectedDarkDisabled) < 48,
                 qPrintable(QStringLiteral("Disabled FluentButton should use neutral disabled tokens, got %1 expected near %2")
                                .arg(darkDisabledFill.name(), expectedDarkDisabled.name())));
        QVERIFY2(colorDelta(darkDisabledFill, legacyDarkDisabled) > 18,
                 qPrintable(QStringLiteral("Disabled FluentButton should not fall back to legacy hover mix, got %1")
                                .arg(darkDisabledFill.name())));

        const QImage darkPrimaryPressedImage =
            renderButton(true, QColor(QStringLiteral("#0066B4")), true, true, 0.0, 1.0);
        const FluentThemeTokens darkPrimaryTokens = ThemeManager::instance().tokens();
        const QColor darkPrimaryPressedFill = dominantColor(darkPrimaryPressedImage, fillSample);
        QVERIFY2(colorDelta(darkPrimaryPressedFill, darkPrimaryTokens.accent.light3) < 54,
                 qPrintable(QStringLiteral("Dark primary FluentButton pressed fill should use accent light3, got %1 expected near %2")
                                .arg(darkPrimaryPressedFill.name(), darkPrimaryTokens.accent.light3.name())));
    }

    void buttonIconAndTextGroupStaysCentered()
    {
        struct ThemeRestore {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();

            ~ThemeRestore()
            {
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } restore;

        syncTheme(false, QColor(QStringLiteral("#0066B4")));
        ThemeColors custom = ThemeManager::instance().colors();
        custom.text = QColor(QStringLiteral("#FF00FF"));
        custom.surface = QColor(QStringLiteral("#F7FBFF"));
        custom.hover = QColor(QStringLiteral("#00FFFF"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        const QColor iconColor(QStringLiteral("#E00000"));
        QPixmap iconPixmap(16, 16);
        iconPixmap.fill(Qt::transparent);
        {
            QPainter painter(&iconPixmap);
            painter.setRenderHint(QPainter::Antialiasing, true);
            painter.setPen(Qt::NoPen);
            painter.setBrush(iconColor);
            painter.drawRoundedRect(QRectF(1, 1, 14, 14), 3, 3);
        }

        FluentButton button(QStringLiteral("Center"));
        button.setIcon(QIcon(iconPixmap));
        button.setIconSize(QSize(16, 16));
        button.resize(180, 40);
        button.show();
        QTRY_VERIFY(button.isVisible());
        QCoreApplication::processEvents();

        const QImage image = renderWidgetImage(&button);
        QVERIFY2(!image.isNull(),
                 "Icon+text FluentButton should render through QWidget::render");

        auto boundsWhere = [](const QImage &source, const QRect &rawArea, auto predicate) {
            const QRect area = normalizedArea(source, rawArea);
            QRect bounds;
            for (int y = area.top(); y <= area.bottom(); ++y) {
                const auto *line = reinterpret_cast<const QRgb *>(source.constScanLine(y));
                for (int x = area.left(); x <= area.right(); ++x) {
                    const QColor color = QColor::fromRgba(line[x]);
                    if (!predicate(color)) {
                        continue;
                    }
                    const QRect pixel(QPoint(x, y), QSize(1, 1));
                    bounds = bounds.isNull() ? pixel : bounds.united(pixel);
                }
            }
            return bounds;
        };

        const QRect content = image.rect().adjusted(10, 6, -10, -6);
        const QRect iconBounds = boundsWhere(image, content, [](const QColor &color) {
            return color.alpha() > 180 && color.red() > 150 && color.green() < 90 && color.blue() < 90;
        });
        const QRect textBounds = boundsWhere(image, content, [](const QColor &color) {
            return color.alpha() > 180 && color.red() > 130 && color.blue() > 130 && color.green() < 120;
        });

        QVERIFY2(iconBounds.isValid(), "FluentButton icon pixels should render with the source icon color");
        QVERIFY2(textBounds.isValid(), "FluentButton text pixels should render with the theme text color");
        QVERIFY2(iconBounds.right() < textBounds.left(),
                 "FluentButton icon should be laid out to the left of the text");

        const int gap = textBounds.left() - iconBounds.right() - 1;
        QVERIFY2(gap >= 4 && gap <= 14,
                 qPrintable(QStringLiteral("FluentButton icon/text gap should stay near the documented 8px gap, got %1")
                                .arg(gap)));

        const int groupLeft = iconBounds.left();
        const int groupRight = textBounds.right();
        const qreal groupCenter = (groupLeft + groupRight) / 2.0;
        const qreal buttonCenter = image.rect().center().x();
        QVERIFY2(qAbs(groupCenter - buttonCenter) <= 4.0,
                 qPrintable(QStringLiteral("FluentButton icon+text group should be centered: group=%1 button=%2")
                                .arg(groupCenter)
                                .arg(buttonCenter)));
    }

    void buttonIconPositionApiUpdatesLayoutHints()
    {
        QPixmap iconPixmap(16, 16);
        iconPixmap.fill(Qt::red);

        FluentButton button(QIcon(iconPixmap), QStringLiteral("Search"));
        button.setIconSize(QSize(16, 16));

        QCOMPARE(static_cast<int>(button.iconPosition()),
                 static_cast<int>(FluentButton::IconPosition::Left));
        QCOMPARE(button.iconSpacing(), 8);

        const QSize horizontalHint = button.sizeHint();
        button.setIconPosition(FluentButton::IconPosition::Top);
        QCOMPARE(static_cast<int>(button.iconPosition()),
                 static_cast<int>(FluentButton::IconPosition::Top));
        QVERIFY2(button.sizeHint().height() > horizontalHint.height(),
                 "Top icon placement should reserve vertical icon+text space");

        button.setIconPosition(FluentButton::IconPosition::Right);
        QCOMPARE(static_cast<int>(button.iconPosition()),
                 static_cast<int>(FluentButton::IconPosition::Right));

        button.setIconSpacing(13);
        QCOMPARE(button.iconSpacing(), 13);
        button.setIconSpacing(-4);
        QCOMPARE(button.iconSpacing(), 0);
    }

    void toolButtonCaptionChromeUsesThemeTokens()
    {
        struct ThemeGuard {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();
            bool animationsEnabled = ThemeManager::instance().animationsEnabled();

            ~ThemeGuard()
            {
                ThemeManager::instance().setAnimationsEnabled(animationsEnabled);
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } guard;

        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        syncTheme(true, QColor(QStringLiteral("#43FF43")));
        ThemeManager::instance().setAnimationsEnabled(false);

        ThemeColors custom = ThemeManager::instance().colors();
        custom.hover = QColor(QStringLiteral("#FF00FF"));
        custom.pressed = QColor(QStringLiteral("#FF8800"));
        custom.focus = QColor(QStringLiteral("#FF00FF"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        const ThemeColors colors = ThemeManager::instance().colors();
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();

        QWidget host;
        host.resize(216, 54);
        host.setAttribute(Qt::WA_StyledBackground, true);
        host.setStyleSheet(QStringLiteral("background: %1;").arg(colors.background.name(QColor::HexArgb)));

        auto *caption = new FluentToolButton(&host);
        caption->setProperty("fluentWindowGlyph", 0);
        caption->move(8, 10);
        caption->resize(48, 32);
        caption->setHoverLevel(1.0);
        caption->show();

        auto *closeCaption = new FluentToolButton(&host);
        closeCaption->setProperty("fluentWindowGlyph", 3);
        closeCaption->move(72, 10);
        closeCaption->resize(48, 32);
        closeCaption->setHoverLevel(1.0);
        closeCaption->setPressLevel(1.0);
        closeCaption->show();

        auto *tool = new FluentToolButton(QStringLiteral("T"), &host);
        tool->move(144, 10);
        tool->resize(56, 32);
        tool->setFocusPolicy(Qt::StrongFocus);
        tool->show();

        host.show();
        QTRY_VERIFY(host.isVisible());
        tool->setFocus(Qt::OtherFocusReason);
        QTRY_VERIFY(tool->hasFocus());
        QCoreApplication::processEvents();

        QImage image(host.size(), QImage::Format_ARGB32);
        image.fill(colors.background.rgba());
        {
            QPainter painter(&image);
            host.render(&painter);
        }

        QColor expectedCaptionHover = tokens.neutral.cardHover;
        expectedCaptionHover.setAlphaF(tokens.dark ? 0.62 : 0.56);
        const QColor blendedCaptionHover = blendOver(expectedCaptionHover, colors.background);
        const QColor captionHover = dominantColor(image, QRect(14, 20, 14, 8));
        QVERIFY2(colorDelta(captionHover, blendedCaptionHover) < 54,
                 qPrintable(QStringLiteral("Caption FluentToolButton hover should use neutral.cardHover, got %1 expected near %2")
                                .arg(captionHover.name(), blendedCaptionHover.name())));

        QColor legacyHover = colors.hover;
        legacyHover.setAlphaF(0.58);
        const QColor legacyHoverBlend = blendOver(legacyHover, colors.background);
        QVERIFY2(colorDelta(captionHover, legacyHoverBlend) > 90,
                 qPrintable(QStringLiteral("Caption FluentToolButton hover should not use legacy hover color, got %1")
                                .arg(captionHover.name())));

        QColor expectedClosePressed = Style::mix(tokens.semantic.error,
                                                 tokens.dark ? tokens.neutral.background : colors.text,
                                                 tokens.dark ? 0.16 : 0.20);
        expectedClosePressed.setAlphaF(0.97);
        const QColor blendedClosePressed = blendOver(expectedClosePressed, colors.background);
        QColor legacyClosePressed = Style::mix(tokens.semantic.error, QColor(0, 0, 0), tokens.dark ? 0.16 : 0.20);
        legacyClosePressed.setAlphaF(0.97);
        const QColor blendedLegacyClosePressed = blendOver(legacyClosePressed, colors.background);
        const QColor closePressed = dominantColor(
            image,
            QRect(closeCaption->geometry().left() + 6, closeCaption->geometry().top() + 5, 10, 6));
        QVERIFY2(colorDelta(closePressed, blendedClosePressed) < 54,
                 qPrintable(QStringLiteral("Close caption pressed fill should use semantic error with theme-derived shade, got %1 expected near %2")
                                .arg(closePressed.name(), blendedClosePressed.name())));
        QVERIFY2(colorDelta(closePressed, blendedLegacyClosePressed) > 12,
                 qPrintable(QStringLiteral("Close caption pressed fill should not mix semantic error with fixed black, got %1")
                                .arg(closePressed.name())));

        const QRect focusArea(tool->geometry().left() + 5, tool->geometry().top(), tool->geometry().width() - 10, 6);
        QVERIFY2(nearColorPixelCount(image, tokens.accent.base, focusArea, 72) > 8,
                 "Focused FluentToolButton should paint an accent.base token focus ring");
        QVERIFY2(nearColorPixelCount(image, colors.focus, focusArea, 42) <= 2,
                 "Focused FluentToolButton should not paint the legacy focus color");
    }

    void buttonFamilyFocusUsesAccentBaseTokens()
    {
        struct ThemeGuard {
            ThemeManager::ThemeMode mode = ThemeManager::instance().themeMode();
            ThemeColors colors = ThemeManager::instance().colors();
            bool animationsEnabled = ThemeManager::instance().animationsEnabled();

            ~ThemeGuard()
            {
                ThemeManager::instance().setAnimationsEnabled(animationsEnabled);
                ThemeManager::instance().setColors(colors);
                ThemeManager::instance().setThemeMode(mode);
                QCoreApplication::processEvents();
            }
        } guard;

        syncTheme(false, QColor(QStringLiteral("#43FF43")));
        ThemeManager::instance().setAnimationsEnabled(false);
        ThemeColors custom = ThemeManager::instance().colors();
        custom.focus = QColor(QStringLiteral("#FF00FF"));
        ThemeManager::instance().setColors(custom);
        QCoreApplication::processEvents();

        const ThemeColors colors = ThemeManager::instance().colors();
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();

        QWidget host;
        host.resize(420, 116);
        host.setAttribute(Qt::WA_StyledBackground, true);
        host.setStyleSheet(QStringLiteral("background: %1;").arg(colors.background.name(QColor::HexArgb)));

        auto *button = new FluentButton(QStringLiteral("Button"), &host);
        button->move(12, 12);
        button->resize(92, 34);
        button->setFocusPolicy(Qt::StrongFocus);
        button->show();

        auto *animated = new FluentAnimatedButton(QStringLiteral("Animated"), &host);
        animated->move(116, 12);
        animated->resize(120, 34);
        animated->setFocusPolicy(Qt::StrongFocus);
        animated->show();

        auto *dropDown = new FluentDropDownButton(QStringLiteral("Menu"), &host);
        dropDown->move(248, 12);
        dropDown->resize(120, 34);
        dropDown->setFocusPolicy(Qt::StrongFocus);
        dropDown->show();

        auto *split = new FluentSplitButton(QStringLiteral("Split"), &host);
        split->move(12, 62);
        split->resize(132, 34);
        split->mainButton()->setFocusPolicy(Qt::StrongFocus);
        split->show();

        host.show();
        QTRY_VERIFY(host.isVisible());

        auto renderHost = [&]() {
            QImage image(host.size(), QImage::Format_ARGB32);
            image.fill(colors.background.rgba());
            QPainter painter(&image);
            host.render(&painter);
            return image;
        };

        auto assertFocus = [&](const QString &name, QWidget *target) {
            target->setFocus(Qt::OtherFocusReason);
            QTRY_VERIFY(target->hasFocus());
            QCoreApplication::processEvents();

            const QImage image = renderHost();
            const QPoint origin = target->mapTo(&host, QPoint(0, 0));
            const QRect focusArea(origin.x() + 8, origin.y(), qMax(1, target->width() - 16), 6);
            const int accentPixels = nearColorPixelCount(image, tokens.accent.base, focusArea, 72);
            const int legacyPixels = nearColorPixelCount(image, colors.focus, focusArea, 42);
            QVERIFY2(accentPixels > 8,
                     qPrintable(QStringLiteral("%1 should paint an accent.base token focus ring, pixels=%2")
                                    .arg(name)
                                    .arg(accentPixels)));
            QVERIFY2(legacyPixels <= 2,
                     qPrintable(QStringLiteral("%1 should not paint the legacy focus color, pixels=%2")
                                    .arg(name)
                                    .arg(legacyPixels)));
        };

        assertFocus(QStringLiteral("FluentButton"), button);
        assertFocus(QStringLiteral("FluentAnimatedButton"), animated);
        assertFocus(QStringLiteral("FluentDropDownButton"), dropDown);
        assertFocus(QStringLiteral("FluentSplitButton"), split->mainButton());
    }

    void comboAndAutoSuggestPopupsUseFluentItemTokens()
    {
        struct AnimationGuard {
            ~AnimationGuard()
            {
                ThemeManager::instance().setAnimationsEnabled(true);
                ThemeManager::instance().resetMotionTokens();
            }
        } guard;

        auto colorDelta = [](const QColor &a, const QColor &b) {
            return qAbs(a.red() - b.red())
                 + qAbs(a.green() - b.green())
                 + qAbs(a.blue() - b.blue());
        };

        ThemeManager::instance().setAnimationsEnabled(false);
        syncTheme(false, QColor(QStringLiteral("#43FF43")));
        const FluentThemeTokens lightTokens = ThemeManager::instance().tokens();

        QWidget window;
        auto *layout = new QVBoxLayout(&window);
        auto *combo = new FluentComboBox(&window);
        combo->addItems({QStringLiteral("Zero"), QStringLiteral("One"), QStringLiteral("Two")});
        combo->setCurrentIndex(1);
        combo->setPopupScrollThreshold(4);
        layout->addWidget(combo);

        auto *suggest = new FluentAutoSuggestBox(&window);
        suggest->setSuggestions({QStringLiteral("Fluent layout"),
                                 QStringLiteral("Fluent motion"),
                                 QStringLiteral("Fluent tokens")});
        layout->addWidget(suggest);

        window.resize(260, 120);
        window.show();
        QTRY_VERIFY(window.isVisible());

        combo->showPopup();
        QTRY_VERIFY(findComboPopupView());
        QListView *comboView = findComboPopupView();
        QVERIFY(comboView);
        const QModelIndex comboIndex = comboView->model()->index(1, 0);
        QVERIFY(comboIndex.isValid());
        QTRY_VERIFY(comboView->visualRect(comboIndex).isValid());
        QVERIFY2(comboView->sizeHintForIndex(comboIndex).height() >= 36,
                 "ComboBox popup rows should use the 36px Fluent item height");
        if (comboView->selectionModel()) {
            comboView->selectionModel()->setCurrentIndex(comboIndex, QItemSelectionModel::ClearAndSelect);
        }
        QCoreApplication::processEvents();
        const QRect comboRow = comboView->visualRect(comboIndex);
        const QImage comboImage = renderWidgetImage(comboView->viewport());
        const QRect comboIndicator(comboRow.left() + 4, comboRow.center().y() - 8, 4, 16);
        QVERIFY2(nearColorPixelCount(comboImage, lightTokens.accent.base, comboIndicator, 64) > 4,
                 "ComboBox selected row should render a 3px accent token indicator");
        combo->hidePopup();

        if (auto *model = qobject_cast<QStandardItemModel *>(combo->model())) {
            if (auto *item = model->item(2)) {
                item->setEnabled(false);
            }
        }
        combo->setCurrentIndex(2);
        combo->showPopup();
        QTRY_VERIFY(findComboPopupView());
        comboView = findComboPopupView();
        QVERIFY(comboView);
        const QModelIndex disabledComboIndex = comboView->model()->index(2, 0);
        QVERIFY(disabledComboIndex.isValid());
        QTRY_VERIFY(comboView->visualRect(disabledComboIndex).isValid());
        if (comboView->selectionModel()) {
            comboView->selectionModel()->setCurrentIndex(disabledComboIndex, QItemSelectionModel::ClearAndSelect);
        }
        QCoreApplication::processEvents();
        const QRect disabledComboRow = comboView->visualRect(disabledComboIndex);
        const QImage disabledComboPopupImage = renderWidgetImage(comboView->viewport());
        const QRect disabledComboIndicator(disabledComboRow.left() + 4,
                                           disabledComboRow.center().y() - 8,
                                           4,
                                           16);
        QVERIFY2(nearColorPixelCount(disabledComboPopupImage,
                                     lightTokens.accent.base,
                                     disabledComboIndicator,
                                     64) < 3,
                 "Disabled current ComboBox popup row should not render the accent selection indicator");
        QVERIFY2(nearColorPixelCount(disabledComboPopupImage,
                                     ThemeManager::instance().colors().disabledText,
                                     disabledComboRow.adjusted(26, 0, -8, 0),
                                     96) > 8,
                 "Disabled current ComboBox popup row should render text with disabledText pixels");
        combo->hidePopup();

        QListView *suggestView = openAutoSuggestPopup(suggest, QStringLiteral("Fluent"));
        QVERIFY2(suggestView, "AutoSuggest popup view should open in offscreen mode");
        const QModelIndex suggestIndex = suggestView->model()->index(0, 0);
        QVERIFY(suggestIndex.isValid());
        QTRY_VERIFY(suggestView->visualRect(suggestIndex).isValid());
        QVERIFY2(suggestView->sizeHintForIndex(suggestIndex).height() >= 36,
                 "AutoSuggest popup rows should use the 36px Fluent item height");
        if (suggestView->selectionModel()) {
            suggestView->selectionModel()->setCurrentIndex(suggestIndex, QItemSelectionModel::ClearAndSelect);
        }
        QCoreApplication::processEvents();
        const QRect suggestRow = suggestView->visualRect(suggestIndex);
        const QImage suggestImage = renderWidgetImage(suggestView->viewport());
        const QRect suggestIndicator(suggestRow.left() + 4, suggestRow.center().y() - 8, 4, 16);
        QVERIFY2(nearColorPixelCount(suggestImage, lightTokens.accent.base, suggestIndicator, 64) > 4,
                 "AutoSuggest selected row should render a 3px accent token indicator");

        syncTheme(true, QColor(QStringLiteral("#0066B4")));
        const ThemeColors darkColors = ThemeManager::instance().colors();
        const FluentThemeTokens darkTokens = ThemeManager::instance().tokens();

        QWidget host;
        host.resize(150, 52);
        host.setAttribute(Qt::WA_StyledBackground, true);
        host.setStyleSheet(QStringLiteral("background: %1;").arg(darkColors.background.name(QColor::HexArgb)));

        auto *disabledCombo = new FluentComboBox(&host);
        disabledCombo->addItem(QStringLiteral("Disabled"));
        disabledCombo->setEnabled(false);
        disabledCombo->move(8, 8);
        disabledCombo->resize(132, 36);
        disabledCombo->show();

        host.show();
        QCoreApplication::processEvents();
        QImage hostImage(host.size(), QImage::Format_ARGB32);
        hostImage.fill(darkColors.background.rgba());
        {
            QPainter painter(&hostImage);
            host.render(&painter);
        }

        const QColor disabledFill = dominantColor(hostImage, QRect(18, 20, 20, 12));
        const QColor expectedDisabled = Style::mix(darkTokens.neutral.card, darkTokens.neutral.background, 0.48);
        const QColor legacyDisabled = Style::mix(darkColors.surface, darkColors.hover, 0.35);
        QVERIFY2(colorDelta(disabledFill, expectedDisabled) < 48,
                 qPrintable(QStringLiteral("Disabled ComboBox should use shared neutral surface tokens, got %1 expected near %2")
                                .arg(disabledFill.name(), expectedDisabled.name())));
        QVERIFY2(colorDelta(disabledFill, legacyDisabled) > 16,
                 qPrintable(QStringLiteral("Disabled ComboBox should not fall back to legacy surface/hover mix, got %1")
                                .arg(disabledFill.name())));
    }

    void comboMultiSelectionKeepsPopupOpenAndUsesAccentCheckboxTokens()
    {
        struct AnimationGuard {
            bool enabled = ThemeManager::instance().animationsEnabled();
            FluentMotionTokens tokens = ThemeManager::instance().motionTokens();
            ~AnimationGuard()
            {
                ThemeManager::instance().setMotionTokens(tokens);
                ThemeManager::instance().setAnimationsEnabled(enabled);
                QCoreApplication::processEvents();
            }
        } guard;

        ThemeManager::instance().setAnimationsEnabled(false);
        syncTheme(false, QColor(QStringLiteral("#43FF43")));
        const FluentThemeTokens tokens = ThemeManager::instance().tokens();

        QWidget host;
        auto *layout = new QVBoxLayout(&host);
        auto *combo = new FluentComboBox(&host);
        combo->addItems({QStringLiteral("Alpha"), QStringLiteral("Beta"), QStringLiteral("Gamma")});
        combo->setSelectionMode(FluentComboBox::MultiSelection);
        combo->setMultiSelectionPlaceholder(QStringLiteral("Choose controls"));
        combo->resize(240, 36);
        layout->addWidget(combo);
        host.resize(280, 72);
        host.show();
        QTRY_VERIFY(host.isVisible());

        QCOMPARE(combo->selectionMode(), FluentComboBox::MultiSelection);
        QCOMPARE(combo->multiSelectionPlaceholder(), QStringLiteral("Choose controls"));
        QCOMPARE(combo->checkedIndexes(), QList<int>{});
        QCOMPARE(combo->checkedTexts(), QStringList{});
        const QImage placeholderImage = renderWidgetImage(combo);
        QVERIFY2(!placeholderImage.isNull(),
                 "Multi-selection ComboBox should render its empty placeholder through QWidget::render");

        QSignalSpy checkedSpy(combo, &FluentComboBox::checkedIndexesChanged);
        combo->setCheckedIndexes({2, 1, 99, -1, 2});
        QCOMPARE(combo->checkedIndexes(), (QList<int>{1, 2}));
        QCOMPARE(combo->checkedTexts(), (QStringList{QStringLiteral("Beta"), QStringLiteral("Gamma")}));
        QTRY_COMPARE(checkedSpy.count(), 1);
        QCOMPARE(checkedSpy.takeFirst().at(0).value<QList<int>>(), (QList<int>{1, 2}));
        const QImage helperCheckedImage = renderWidgetImage(combo);
        QVERIFY2(changedPixelCount(placeholderImage, helperCheckedImage, 12) > 24,
                 "setCheckedIndexes should update the closed multi-selection ComboBox text");
        combo->setCheckedIndexes({1, 2});
        QCOMPARE(checkedSpy.count(), 0);
        combo->clearChecked();
        QCOMPARE(combo->checkedIndexes(), QList<int>{});
        QCOMPARE(combo->checkedTexts(), QStringList{});
        QTRY_COMPARE(checkedSpy.count(), 1);
        QCOMPARE(checkedSpy.takeFirst().at(0).value<QList<int>>(), QList<int>{});

        combo->showPopup();
        QTRY_VERIFY2(findComboPopupView(), "Multi-selection ComboBox should open the Fluent popup view");
        QListView *popupView = findComboPopupView();
        QVERIFY(popupView);
        QWidget *popupHost = findVisibleTopLevelByObjectName(QStringLiteral("FluentComboPopup"));
        QVERIFY2(popupHost, "Multi-selection ComboBox should use the Fluent popup host");

        const QModelIndex betaIndex = popupView->model()->index(1, 0);
        QVERIFY(betaIndex.isValid());
        QTRY_VERIFY(popupView->visualRect(betaIndex).isValid());
        const QRect betaRow = popupView->visualRect(betaIndex);
        QTest::mouseClick(popupView->viewport(), Qt::LeftButton, Qt::NoModifier, betaRow.center());
        QCoreApplication::processEvents();

        QVERIFY2(popupHost->isVisible(),
                 "Clicking a multi-selection row should toggle it without closing the popup");
        QCOMPARE(combo->checkedIndexes(), QList<int>{1});
        QCOMPARE(combo->checkedTexts(), QStringList{QStringLiteral("Beta")});
        QTRY_COMPARE(checkedSpy.count(), 1);
        QCOMPARE(checkedSpy.takeFirst().at(0).value<QList<int>>(), QList<int>{1});

        const QImage checkedClosedImage = renderWidgetImage(combo);
        QVERIFY2(changedPixelCount(placeholderImage, checkedClosedImage, 12) > 24,
                 "Multi-selection ComboBox closed text should change from placeholder to checked item text");

        const QImage popupImage = renderWidgetImage(popupView->viewport());
        QVERIFY2(!popupImage.isNull(),
                 "Multi-selection ComboBox popup should render through QWidget::render");
        const QRect itemRect = betaRow.adjusted(4, 2, -4, -2);
        const QRect checkboxRect(itemRect.left() + 10,
                                 itemRect.center().y() - 8,
                                 16,
                                 16);
        QVERIFY2(nearColorPixelCount(popupImage, tokens.accent.base, checkboxRect.adjusted(1, 1, -1, -1), 72) > 24,
                 "Checked multi-selection ComboBox checkbox should use accent.base fill pixels");
        QVERIFY2(nearColorPixelCount(popupImage, tokens.onAccent, checkboxRect, 72) > 4,
                 "Checked multi-selection ComboBox checkbox mark should use onAccent pixels");

        combo->clearChecked();
        QCOMPARE(combo->checkedIndexes(), QList<int>{});
        QCOMPARE(combo->checkedTexts(), QStringList{});
        QTRY_COMPARE(checkedSpy.count(), 1);
        QCOMPARE(checkedSpy.takeFirst().at(0).value<QList<int>>(), QList<int>{});
        QVERIFY2(popupHost->isVisible(),
                 "Clearing checked items while the popup is open should not dismiss the multi-selection popup");

        combo->hidePopup();
        QTRY_VERIFY2(!popupHost->isVisible(), "Multi-selection ComboBox popup should close when explicitly hidden");
    }

